INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_erste-schritte', 'de', 'Erste Schritte', 'erste-schritte', 'Aera kennenlernen, ein Konto erstellen und eine Community finden.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_community-starten', 'de', 'Deine Community starten', 'community-starten', 'In wenigen Minuten deine eigene Community unter deiner Marke aufbauen.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_mitgliedschaften-preise', 'de', 'Mitgliedschaften & Preise', 'mitgliedschaften-preise', 'Kostenlose und bezahlte Mitgliedschaften einrichten und verstehen.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_bezahlen-auszahlungen', 'de', 'Bezahlen & Auszahlungen', 'bezahlen-auszahlungen', 'Sichere Zahlung, Auszahlungen an Creator, Belege und Erstattungen.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_inhalte-erstellen', 'de', 'Inhalte: Beiträge, Kurse, Events & Newsletter', 'inhalte-erstellen', 'Veröffentlichen, unterrichten, Events halten und Mitglieder direkt erreichen.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_teilnehmen', 'de', 'Für Mitglieder: Teilnehmen', 'teilnehmen', 'Beitreten, mitmachen, lernen und in Kontakt bleiben.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_ki-funktionen', 'de', 'KI-Funktionen', 'ki-funktionen', 'Der KI-Assistent, Empfehlungen und das KI-Guthaben.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_de_konto-marke-daten', 'de', 'Konto, Marke & Daten', 'konto-marke-daten', 'Profil und Sicherheit, Marke anpassen, Mitglieder verwalten und Daten herunterladen.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_erste-schritte_0', c."id", 'Was ist Aera?', 'Aera ist eine Plattform, auf der Creator ihre eigene Community unter ihrer eigenen Marke betreiben — mit Mitgliedschaften, Kursen, Events, Newsletter und mehr an einem Ort.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_erste-schritte_1', c."id", 'Wie erstelle ich ein Konto?', 'Klicke auf „Registrieren" und melde dich mit deiner E-Mail-Adresse und einem Passwort an.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_erste-schritte_2', c."id", 'Brauche ich ein Konto, um mich umzusehen?', 'Viele Community-Seiten kannst du auch ohne Konto ansehen. Sobald du beitreten, mitschreiben oder etwas kaufen möchtest, brauchst du ein kostenloses Konto.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_erste-schritte_3', c."id", 'Wie finde ich eine Community?', 'Über „Entdecken" auf der Startseite findest du öffentliche Communities. Oder du öffnest direkt die Adresse bzw. den Link, den dir ein Creator gegeben hat (zum Beispiel name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_erste-schritte_4', c."id", 'Was kostet Aera?', 'Ein Konto anlegen und einer Community beitreten ist kostenlos.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_0', c."id", 'Wie starte ich meine eigene Community?', 'Wähle „Community starten". Du legst Namen und Adresse fest und triffst ein paar Grundeinstellungen. Danach landest du direkt in deinem Dashboard und kannst loslegen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_1', c."id", 'Was ist das Dashboard?', 'Das Dashboard ist deine Schaltzentrale. Von hier aus richtest du Bereiche ein, veröffentlichst Inhalte, verwaltest Mitglieder, legst Mitgliedschaften und Preise fest, versendest Newsletter und siehst deine wichtigsten Zahlen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_2', c."id", 'Was sind Bereiche?', 'Bereiche sind die Räume deiner Community — zum Beispiel ein Feed für Beiträge, Kurse, Events, ein Chat oder eine Mediathek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_3', c."id", 'Kann ich das Aussehen an meine Marke anpassen?', 'Ja. Du kannst Logo, Farben und Layout so einstellen, dass deine Community wie deine eigene Marke wirkt. Aera tritt bewusst in den Hintergrund — im Vordergrund stehst du.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_4', c."id", 'Bekomme ich eine eigene Adresse?', 'Ja. Deine Community erhält eine eigene Internetadresse (zum Beispiel deinname.aera.so). Eine eigene Wunsch-Domain lässt sich ebenfalls anbinden.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_community-starten_5', c."id", 'Wie lade ich die ersten Mitglieder ein?', 'Teile einfach den Link zu deiner Community — über Social Media, Messenger oder E-Mail. Später erreichst du deine Mitglieder jederzeit direkt über den Newsletter, ganz ohne Algorithmus dazwischen.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_mitgliedschaften-preise_0', c."id", 'Was ist eine Mitgliedschaft?', 'Eine Mitgliedschaft legt fest, was ein Mitglied in deiner Community sehen und tun darf. Es kann kostenlose und bezahlte Stufen geben — zum Beispiel „Frei", „Plus" und „Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_mitgliedschaften-preise_1', c."id", 'Wie erstelle ich eine bezahlte Mitgliedschaft?', 'Im Dashboard legst du unter Mitgliedschaften eine neue Stufe an. Du wählst den Preis und die Abrechnung (monatlich oder jährlich) und bestimmst, welche Bereiche und Inhalte die Stufe freischaltet.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_mitgliedschaften-preise_2', c."id", 'Wie werde ich zahlendes Mitglied?', 'Wähle in der Community die gewünschte Mitgliedschaft und schließe die Zahlung über den sicheren Checkout ab. Dein Zugang schaltet sich sofort frei.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_mitgliedschaften-preise_3', c."id", 'Kann ich meine Mitgliedschaft ändern oder kündigen?', 'Ja. In deinen Mitgliedschafts-Einstellungen kannst du jederzeit wechseln oder kündigen.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_mitgliedschaften-preise_4', c."id", 'Was passiert nach dem Kauf mit meinem Zugang?', 'Bezahlte Bereiche und Inhalte schalten sich automatisch frei. Läuft eine Mitgliedschaft aus, werden sie wieder gesperrt — deine eigenen Beiträge und Daten bleiben dabei erhalten.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_0', c."id", 'Wie bezahle ich sicher?', 'Zahlungen laufen über unseren Zahlungsdienstleister Stripe. Deine Zahlungsdaten werden dort verschlüsselt verarbeitet — Aera speichert selbst keine Kartendaten.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_1', c."id", 'Welche Zahlungsmittel kann ich nutzen?', 'Je nach Land und Gerät stehen dir zum Beispiel Kredit- und Debitkarten sowie gängige digitale Zahlungsmittel zur Verfügung. Welche Optionen möglich sind, siehst du direkt an der Kasse.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_2', c."id", 'Bekomme ich einen Beleg oder eine Rechnung?', 'Ja. Nach jedem Kauf erhältst du eine Bestätigung per E-Mail. Deine Käufe findest du außerdem jederzeit in deinen Kontoeinstellungen.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_3', c."id", 'Wie bekomme ich als Creator meine Einnahmen?', 'Deine Auszahlungen laufen sicher über Stripe. Du hinterlegst einmalig deine Auszahlungsdaten, danach werden deine Einnahmen automatisch an dich überwiesen.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_4', c."id", 'Welche Gebühren fallen für Creator an?', 'Aera behält beim Verkauf eine kleine Plattformgebühr. Zusätzlich können bei der Zahlungsabwicklung Gebühren des Zahlungsdienstleisters anfallen. Der Rest deiner Einnahmen gehört dir.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_bezahlen-auszahlungen_5', c."id", 'Wie funktionieren Erstattungen?', 'Eine Erstattung stößt der jeweilige Creator an. Bei Fragen zu einem Kauf wende dich zuerst an den Creator der Community — oder an unseren Support, wenn du nicht weiterkommst.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_0', c."id", 'Wie veröffentliche ich einen Beitrag?', 'Öffne den passenden Bereich, wähle „Neuer Beitrag", füge Text und Medien hinzu und veröffentliche. Du legst dabei fest, welche Mitglieder den Beitrag sehen dürfen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_1', c."id", 'Wie erstelle ich einen Kurs?', 'Lege einen Kurs-Bereich an und füge Lektionen oder Module hinzu. Du entscheidest, ob der Kurs frei zugänglich oder Teil einer bezahlten Mitgliedschaft ist.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_2', c."id", 'Wie plane ich ein Event?', 'Im Events-Bereich legst du Titel, Zeitpunkt und Details fest. Mitglieder können zusagen. Events kannst du kostenlos oder kostenpflichtig anbieten.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_3', c."id", 'Wie versende ich einen Newsletter?', 'Verfasse im Dashboard einen Newsletter und sende ihn an alle oder an ausgewählte Mitglieder. So erreichst du deine Community direkt in ihrem Postfach — ohne fremden Algorithmus dazwischen.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_4', c."id", 'Was ist die Mediathek?', 'Die Mediathek ist der zentrale Ort für deine Videos, Audios und Dateien. Von dort aus bindest du sie in Beiträge, Kurse oder Events ein.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_inhalte-erstellen_5', c."id", 'Kann ich Beiträge im Voraus planen?', 'Ja. Du kannst Inhalte für einen späteren Zeitpunkt planen, sodass sie automatisch erscheinen — praktisch, um regelmäßig aktiv zu bleiben.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_0', c."id", 'Wie trete ich einer Community bei?', 'Öffne die Community und wähle „Beitreten". Bei kostenlosen Communities bist du sofort dabei. Bei bezahlten wählst du zuerst eine Mitgliedschaft aus.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_1', c."id", 'Wie schreibe ich Beiträge und Kommentare?', 'In allen Bereichen, für die du Zugang hast, kannst du Beiträge schreiben, kommentieren und reagieren — ähnlich wie in einem sozialen Netzwerk, nur ohne fremden Algorithmus.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_2', c."id", 'Wo finde ich Kurse und Events?', 'Freigeschaltete Kurse findest du im Bereich „Kurse", anstehende Termine unter „Events". Was du sehen kannst, hängt von deiner Mitgliedschaft ab.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_3', c."id", 'Was sind Punkte, Level und Abzeichen?', 'Für deine Aktivität sammelst du Punkte, steigst im Level auf und verdienst Abzeichen. Eine Bestenliste zeigt besonders aktive Mitglieder — das macht das Mitmachen lebendiger.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_4', c."id", 'Kann ich anderen Mitgliedern schreiben?', 'Ja, sofern der Creator den Chat und Direktnachrichten aktiviert hat, kannst du dich mit anderen Mitgliedern austauschen.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_teilnehmen_5', c."id", 'Wie stelle ich meine Benachrichtigungen ein?', 'In deinen Kontoeinstellungen legst du fest, worüber du per E-Mail und in der App informiert werden möchtest.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_ki-funktionen_0', c."id", 'Was kann der KI-Assistent?', 'Der KI-Assistent hilft dir beim Schreiben von Beiträgen, Newslettern und beim Sammeln von Ideen. Er liefert einen Startpunkt, den du anpasst — die Kontrolle behältst immer du.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_ki-funktionen_1', c."id", 'Was sind KI-Empfehlungen?', 'Aera schlägt Mitgliedern passende Inhalte vor, damit sie schneller finden, was sie interessiert. Ist keine KI aktiv, funktioniert das über eine einfache, transparente Suche nach Stichworten.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_ki-funktionen_2', c."id", 'Was ist das KI-Guthaben?', 'KI-Funktionen verbrauchen Guthaben. Jede Community hat ein Guthaben, und bei Bedarf kannst du zusätzliche Pakete nachkaufen.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_ki-funktionen_3', c."id", 'Was passiert, wenn das KI-Guthaben aufgebraucht ist?', 'Dann pausieren die KI-Funktionen, bis du neues Guthaben nachlädst. Alle übrigen Funktionen deiner Community laufen ganz normal weiter.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_ki-funktionen_4', c."id", 'Werden meine Inhalte für KI-Training verwendet?', 'Nein. Deine Inhalte gehören dir. Sie werden nur genutzt, um dir die Funktionen bereitzustellen, die du selbst verwendest.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_0', c."id", 'Wie ändere ich mein Profil oder Passwort?', 'In deinen Kontoeinstellungen kannst du Name, Profilbild, E-Mail-Adresse und Passwort jederzeit anpassen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_1', c."id", 'Wie verwalte ich meine Mitglieder?', 'Im Dashboard siehst du alle Mitglieder deiner Community. Du kannst Rollen wie Moderator vergeben, neue Mitglieder einladen oder Mitglieder entfernen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_2', c."id", 'Gehören mir meine Daten?', 'Ja. Deine Community, deine Mitgliederliste und deine Inhalte gehören dir. Du kannst deine Daten jederzeit herunterladen — du bist an nichts gebunden.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_3', c."id", 'Wie lade ich meine Daten herunter?', 'In den Einstellungen findest du den Datenexport. Damit erhältst du deine Inhalte in einem gängigen Format zum Herunterladen.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_4', c."id", 'Wie sicher sind meine Daten?', 'Jede Community ist sauber von allen anderen getrennt und geschützt, sodass niemand sonst Zugriff hat. Deine Zahlungsdaten liegen ausschließlich beim Zahlungsdienstleister, nicht bei Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_5', c."id", 'Wie lösche ich meine Community oder mein Konto?', 'Das geht in den Einstellungen. Beim Löschen werden die zugehörigen Inhalte entfernt — lade dir vorher bei Bedarf deine Daten herunter.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_de_konto-marke-daten_6', c."id", 'Wie erreiche ich den Support?', 'Nutze den Kontakt-Button am Ende des Hilfe-Centers. Beschreibe dein Anliegen möglichst genau, dann können wir dir schnell weiterhelfen.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_erste-schritte', 'en', 'Getting Started', 'erste-schritte', 'Get to know Aera, create an account, and find a community.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_community-starten', 'en', 'Starting Your Community', 'community-starten', 'Build your own community under your brand in just a few minutes.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_mitgliedschaften-preise', 'en', 'Memberships & Pricing', 'mitgliedschaften-preise', 'Set up and understand free and paid memberships.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_bezahlen-auszahlungen', 'en', 'Payments & Payouts', 'bezahlen-auszahlungen', 'Secure payment, payouts to creators, receipts, and refunds.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_inhalte-erstellen', 'en', 'Content: Posts, Courses, Events & Newsletter', 'inhalte-erstellen', 'Publish, teach, host events, and reach members directly.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_teilnehmen', 'en', 'For Members: Taking Part', 'teilnehmen', 'Join, get involved, learn, and stay in touch.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_ki-funktionen', 'en', 'AI Features', 'ki-funktionen', 'The AI assistant, recommendations, and AI credit.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en_konto-marke-daten', 'en', 'Account, Brand & Data', 'konto-marke-daten', 'Profile and security, customizing your brand, managing members, and downloading your data.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_erste-schritte_0', c."id", 'What is Aera?', 'Aera is a platform where creators run their own community under their own brand — with memberships, courses, events, a newsletter, and more, all in one place.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_erste-schritte_1', c."id", 'How do I create an account?', 'Click “Sign up” and register with your email address and a password.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_erste-schritte_2', c."id", 'Do I need an account just to look around?', 'You can view many community pages without an account. As soon as you want to join, post, or buy something, you''ll need a free account.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_erste-schritte_3', c."id", 'How do I find a community?', 'You''ll find public communities through “Explore” on the home page. Or you can go straight to the address or link a creator gave you (for example, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_erste-schritte_4', c."id", 'How much does Aera cost?', 'Creating an account and joining a community is free.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_0', c."id", 'How do I start my own community?', 'Choose “Start a community.” You set your name and address and make a few basic settings. After that, you land right in your dashboard and can get going.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_1', c."id", 'What is the dashboard?', 'The dashboard is your control center. From here you set up spaces, publish content, manage members, set memberships and pricing, send newsletters, and see your most important numbers.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_2', c."id", 'What are spaces?', 'Spaces are the rooms of your community — for example, a feed for posts, courses, events, a chat, or a media library.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_3', c."id", 'Can I customize the look to match my brand?', 'Yes. You can set your logo, colors, and layout so your community feels like your own brand. Aera intentionally stays in the background — you''re the one front and center.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_4', c."id", 'Do I get my own address?', 'Yes. Your community gets its own web address (for example, yourname.aera.so). You can also connect your own custom domain.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_community-starten_5', c."id", 'How do I invite my first members?', 'Just share the link to your community — through social media, messaging, or email. Later, you can reach your members directly anytime through the newsletter, with no algorithm getting in the way.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_mitgliedschaften-preise_0', c."id", 'What is a membership?', 'A membership determines what a member can see and do in your community. There can be free and paid tiers — for example, “Free,” “Plus,” and “Premium.”', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_mitgliedschaften-preise_1', c."id", 'How do I create a paid membership?', 'In the dashboard, you create a new tier under Memberships. You choose the price and the billing (monthly or yearly) and decide which spaces and content the tier unlocks.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_mitgliedschaften-preise_2', c."id", 'How do I become a paying member?', 'Choose the membership you want in the community and complete your payment through the secure checkout. Your access unlocks right away.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_mitgliedschaften-preise_3', c."id", 'Can I change or cancel my membership?', 'Yes. In your membership settings, you can switch or cancel anytime.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_mitgliedschaften-preise_4', c."id", 'What happens to my access after I buy?', 'Paid spaces and content unlock automatically. When a membership runs out, they lock again — but your own posts and data stay safe.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_0', c."id", 'How do I pay securely?', 'Payments run through our payment provider, Stripe. Your payment details are processed there with encryption — Aera itself doesn''t store any card details.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_1', c."id", 'Which payment methods can I use?', 'Depending on your country and device, you''ll have options like credit and debit cards as well as common digital payment methods. You''ll see which options are available right at checkout.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_2', c."id", 'Do I get a receipt or an invoice?', 'Yes. After every purchase, you''ll receive a confirmation by email. You can also find your purchases anytime in your account settings.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_3', c."id", 'As a creator, how do I get my earnings?', 'Your payouts run securely through Stripe. You set up your payout details once, and after that your earnings are automatically transferred to you.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_4', c."id", 'What fees do creators pay?', 'Aera keeps a small platform fee on each sale. In addition, the payment provider may charge fees for processing the payment. The rest of your earnings is yours.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_bezahlen-auszahlungen_5', c."id", 'How do refunds work?', 'A refund is started by the creator involved. If you have questions about a purchase, reach out first to the creator of the community — or to our support team if you get stuck.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_0', c."id", 'How do I publish a post?', 'Open the right space, choose “New post,” add text and media, and publish. As you do, you decide which members are allowed to see the post.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_1', c."id", 'How do I create a course?', 'Set up a course space and add lessons or modules. You decide whether the course is freely available or part of a paid membership.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_2', c."id", 'How do I plan an event?', 'In the events space, you set the title, time, and details. Members can RSVP. You can offer events for free or for a fee.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_3', c."id", 'How do I send a newsletter?', 'Write a newsletter in the dashboard and send it to everyone or to select members. That way you reach your community right in their inbox — with no outside algorithm in between.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_4', c."id", 'What is the media library?', 'The media library is the central place for your videos, audio, and files. From there, you add them to posts, courses, or events.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_inhalte-erstellen_5', c."id", 'Can I schedule posts in advance?', 'Yes. You can schedule content for a later time so it appears automatically — handy for staying active on a regular basis.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_0', c."id", 'How do I join a community?', 'Open the community and choose “Join.” For free communities, you''re in right away. For paid ones, you first choose a membership.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_1', c."id", 'How do I write posts and comments?', 'In all the spaces you have access to, you can write posts, comment, and react — much like a social network, just without an outside algorithm.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_2', c."id", 'Where do I find courses and events?', 'You''ll find your unlocked courses in the “Courses” space and upcoming dates under “Events.” What you can see depends on your membership.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_3', c."id", 'What are points, levels, and badges?', 'You collect points for your activity, level up, and earn badges. A leaderboard highlights especially active members — it makes taking part more lively.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_4', c."id", 'Can I message other members?', 'Yes, as long as the creator has turned on chat and direct messages, you can connect with other members.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_teilnehmen_5', c."id", 'How do I set up my notifications?', 'In your account settings, you decide what you''d like to be notified about by email and in the app.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_ki-funktionen_0', c."id", 'What can the AI assistant do?', 'The AI assistant helps you write posts and newsletters and brainstorm ideas. It gives you a starting point that you refine — you''re always the one in control.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_ki-funktionen_1', c."id", 'What are AI recommendations?', 'Aera suggests content that fits each member, so they can find what interests them faster. If no AI is active, this works through a simple, transparent search by keyword.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_ki-funktionen_2', c."id", 'What is AI credit?', 'AI features use up credit. Every community has a credit balance, and if you need more, you can buy additional packages.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_ki-funktionen_3', c."id", 'What happens when the AI credit runs out?', 'The AI features pause until you top up with new credit. All the other features of your community keep running as normal.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_ki-funktionen_4', c."id", 'Is my content used to train AI?', 'No. Your content belongs to you. It''s only used to provide the features you use yourself.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_0', c."id", 'How do I change my profile or password?', 'In your account settings, you can update your name, profile picture, email address, and password anytime.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_1', c."id", 'How do I manage my members?', 'In the dashboard, you can see all the members of your community. You can assign roles like moderator, invite new members, or remove members.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_2', c."id", 'Do I own my data?', 'Yes. Your community, your member list, and your content belong to you. You can download your data anytime — you''re not locked in to anything.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_3', c."id", 'How do I download my data?', 'In the settings, you''ll find the data export. It gives you your content in a common format ready to download.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_4', c."id", 'How safe is my data?', 'Every community is cleanly separated from all the others and protected, so no one else has access. Your payment details are held solely by the payment provider, not by Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_5', c."id", 'How do I delete my community or my account?', 'You can do this in the settings. When you delete, the related content is removed — so download your data beforehand if you''d like to keep it.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en_konto-marke-daten_6', c."id", 'How do I reach support?', 'Use the contact button at the bottom of the Help Center. Describe your question as clearly as you can, and we''ll be able to help you quickly.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en-GB_erste-schritte', 'en-GB', 'Getting started', 'erste-schritte', 'Get to know Aera, create an account and find a community.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_en-GB_community-starten', 'en-GB', 'Starting your community', 'community-starten', 'Build your own community under your own brand in just a few minutes.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
