INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_community-starten_3', c."id", 'Can I match the look to my brand?', 'Yes. You can set your logo, colours and layout so that your community feels like your very own brand. Aera deliberately stays in the background — you''re the one in the spotlight.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_community-starten_4', c."id", 'Do I get my own address?', 'Yes. Your community gets its own web address (for example deinname.aera.so). You can also connect your own preferred domain.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_community-starten_5', c."id", 'How do I invite my first members?', 'Simply share the link to your community — via social media, messaging apps or email. Later on you can reach your members directly at any time through the newsletter, with no algorithm getting in the way.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_mitgliedschaften-preise_0', c."id", 'What is a membership?', 'A membership sets out what a member is allowed to see and do in your community. There can be free and paid tiers — for example ‘Free’, ‘Plus’ and ‘Premium’.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_mitgliedschaften-preise_1', c."id", 'How do I create a paid membership?', 'In the dashboard, you add a new tier under Memberships. You choose the price and the billing (monthly or yearly) and decide which spaces and content the tier unlocks.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_mitgliedschaften-preise_2', c."id", 'How do I become a paying member?', 'In the community, choose the membership you''d like and complete the payment through the secure checkout. Your access is unlocked straight away.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_mitgliedschaften-preise_3', c."id", 'Can I change or cancel my membership?', 'Yes. In your membership settings you can switch or cancel at any time.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_mitgliedschaften-preise_4', c."id", 'What happens to my access after I buy?', 'Paid spaces and content are unlocked automatically. If a membership runs out, they''re locked again — but your own posts and data are kept.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_0', c."id", 'How do I pay securely?', 'Payments are handled by our payment provider, Stripe. Your payment details are processed there with encryption — Aera itself doesn''t store any card details.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_1', c."id", 'Which payment methods can I use?', 'Depending on your country and device, you''ll have options such as credit and debit cards as well as popular digital payment methods. You''ll see which options are available right at the checkout.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_2', c."id", 'Do I get a receipt or an invoice?', 'Yes. After every purchase you''ll receive a confirmation by email. You can also find your purchases at any time in your account settings.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_3', c."id", 'As a creator, how do I get my earnings?', 'Your payouts are handled securely through Stripe. You provide your payout details once, and after that your earnings are transferred to you automatically.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_4', c."id", 'What fees do creators pay?', 'Aera keeps a small platform fee on each sale. On top of that, the payment provider may charge fees for handling the payment. The rest of your earnings is yours.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_bezahlen-auszahlungen_5', c."id", 'How do refunds work?', 'A refund is started by the creator in question. If you have a question about a purchase, please contact the creator of the community first — or our support team if you''re still stuck.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_0', c."id", 'How do I publish a post?', 'Open the relevant space, choose ‘New post’, add text and media, and publish. As you do, you decide which members are allowed to see the post.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_1', c."id", 'How do I create a course?', 'Set up a course space and add lessons or modules. You decide whether the course is freely available or part of a paid membership.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_2', c."id", 'How do I plan an event?', 'In the events space you set the title, time and details. Members can let you know they''re coming. You can offer events free of charge or for a fee.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_3', c."id", 'How do I send a newsletter?', 'Write a newsletter in the dashboard and send it to everyone or to selected members. That way you reach your community directly in their inbox — with no outside algorithm getting in the way.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_4', c."id", 'What is the media library?', 'The media library is the central place for your videos, audio and files. From there you can add them to posts, courses or events.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_inhalte-erstellen_5', c."id", 'Can I schedule posts in advance?', 'Yes. You can schedule content for a later time so that it appears automatically — handy for staying active on a regular basis.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_0', c."id", 'How do I join a community?', 'Open the community and choose ‘Join’. With free communities you''re in straight away. With paid ones, you first choose a membership.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_1', c."id", 'How do I write posts and comments?', 'In every space you have access to, you can write posts, leave comments and react — much like on a social network, just without an outside algorithm.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_2', c."id", 'Where do I find courses and events?', 'You''ll find the courses you''ve unlocked in the ‘Courses’ space, and upcoming dates under ‘Events’. What you can see depends on your membership.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_3', c."id", 'What are points, levels and badges?', 'You collect points for your activity, move up through the levels and earn badges. A leaderboard highlights the most active members — it makes joining in more lively.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_4', c."id", 'Can I message other members?', 'Yes — as long as the creator has turned on chat and direct messages, you can get chatting with other members.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_teilnehmen_5', c."id", 'How do I set up my notifications?', 'In your account settings you decide what you''d like to be kept informed about by email and in the app.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_ki-funktionen_0', c."id", 'What can the AI assistant do?', 'The AI assistant helps you write posts and newsletters and gather ideas. It gives you a starting point that you then shape — you always stay in control.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_ki-funktionen_1', c."id", 'What are AI recommendations?', 'Aera suggests relevant content to members so they can find what interests them more quickly. If no AI is switched on, this works through a simple, transparent search by keyword.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_ki-funktionen_2', c."id", 'What is AI credit?', 'AI features use up credit. Every community has its own credit, and if you need more you can top up with extra bundles.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_ki-funktionen_3', c."id", 'What happens when the AI credit runs out?', 'The AI features then pause until you top up with new credit. All the other features of your community carry on as normal.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_ki-funktionen_4', c."id", 'Is my content used to train AI?', 'No. Your content belongs to you. It''s only used to provide the features that you choose to use yourself.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_0', c."id", 'How do I change my profile or password?', 'In your account settings you can update your name, profile picture, email address and password at any time.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_1', c."id", 'How do I manage my members?', 'In the dashboard you can see all the members of your community. You can assign roles such as moderator, invite new members or remove members.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_2', c."id", 'Is my data my own?', 'Yes. Your community, your member list and your content belong to you. You can download your data at any time — you''re not tied to anything.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_3', c."id", 'How do I download my data?', 'You''ll find the data export in the settings. It gives you your content to download in a common format.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_4', c."id", 'How safe is my data?', 'Every community is cleanly separated from all the others and kept protected, so that no one else has access. Your payment details are held solely by the payment provider, not by Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_5', c."id", 'How do I delete my community or my account?', 'You can do this in the settings. When you delete, the related content is removed — so do download your data first if you''d like to keep it.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_en-GB_konto-marke-daten_6', c."id", 'How do I get in touch with support?', 'Use the contact button at the bottom of the help centre. Describe what you need as precisely as you can, and then we can help you quickly.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_en-GB_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_erste-schritte', 'da', 'Kom godt i gang', 'erste-schritte', 'Lær Aera at kende, opret en konto og find et fællesskab.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_community-starten', 'da', 'Start dit fællesskab', 'community-starten', 'Opbyg dit eget fællesskab under dit brand på få minutter.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_mitgliedschaften-preise', 'da', 'Medlemskaber & priser', 'mitgliedschaften-preise', 'Opret og forstå gratis og betalte medlemskaber.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_bezahlen-auszahlungen', 'da', 'Betaling & udbetalinger', 'bezahlen-auszahlungen', 'Sikker betaling, udbetalinger til kreatorer, kvitteringer og refunderinger.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_inhalte-erstellen', 'da', 'Indhold: opslag, kurser, events & nyhedsbrev', 'inhalte-erstellen', 'Udgiv, undervis, hold events og nå dine medlemmer direkte.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_teilnehmen', 'da', 'For medlemmer: deltag', 'teilnehmen', 'Bliv en del af fællesskabet, deltag, lær og hold kontakten.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_ki-funktionen', 'da', 'AI-funktioner', 'ki-funktionen', 'AI-assistenten, anbefalinger og AI-saldoen.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_da_konto-marke-daten', 'da', 'Konto, brand & data', 'konto-marke-daten', 'Profil og sikkerhed, tilpas dit brand, administrer medlemmer og download data.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_erste-schritte_0', c."id", 'Hvad er Aera?', 'Aera er en platform, hvor kreatorer driver deres eget fællesskab under deres eget brand — med medlemskaber, kurser, events, nyhedsbrev og meget mere samlet ét sted.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_erste-schritte_1', c."id", 'Hvordan opretter jeg en konto?', 'Klik på „Tilmeld dig" og log ind med din e-mailadresse og en adgangskode.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_erste-schritte_2', c."id", 'Har jeg brug for en konto for at kigge mig omkring?', 'Mange fællesskabssider kan du også se uden en konto. Så snart du vil deltage, skrive med eller købe noget, har du brug for en gratis konto.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_erste-schritte_3', c."id", 'Hvordan finder jeg et fællesskab?', 'Via „Opdag" på forsiden finder du offentlige fællesskaber. Eller du åbner direkte den adresse eller det link, som en kreator har givet dig (for eksempel name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_erste-schritte_4', c."id", 'Hvad koster Aera?', 'Det er gratis at oprette en konto og blive en del af et fællesskab.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_0', c."id", 'Hvordan starter jeg mit eget fællesskab?', 'Vælg „Start et fællesskab". Du fastlægger navn og adresse og laver et par grundlæggende indstillinger. Derefter lander du direkte i dit dashboard og kan komme i gang.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_1', c."id", 'Hvad er dashboardet?', 'Dashboardet er dit kontrolcenter. Herfra opretter du områder, udgiver indhold, administrerer medlemmer, fastlægger medlemskaber og priser, sender nyhedsbreve og ser dine vigtigste tal.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_2', c."id", 'Hvad er områder?', 'Områder er rummene i dit fællesskab — for eksempel et feed til opslag, kurser, events, en chat eller et mediebibliotek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_3', c."id", 'Kan jeg tilpasse udseendet til mit brand?', 'Ja. Du kan indstille logo, farver og layout, så dit fællesskab fremstår som dit eget brand. Aera træder bevidst i baggrunden — det er dig, der er i forgrunden.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_4', c."id", 'Får jeg min egen adresse?', 'Ja. Dit fællesskab får sin egen internetadresse (for eksempel dinnavn.aera.so). Du kan også tilknytte dit eget ønskede domæne.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_community-starten_5', c."id", 'Hvordan inviterer jeg de første medlemmer?', 'Del blot linket til dit fællesskab — via sociale medier, beskedtjenester eller e-mail. Senere kan du altid nå dine medlemmer direkte via nyhedsbrevet, helt uden en algoritme imellem.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_mitgliedschaften-preise_0', c."id", 'Hvad er et medlemskab?', 'Et medlemskab fastlægger, hvad et medlem må se og gøre i dit fællesskab. Der kan være gratis og betalte niveauer — for eksempel „Gratis", „Plus" og „Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_mitgliedschaften-preise_1', c."id", 'Hvordan opretter jeg et betalt medlemskab?', 'I dashboardet opretter du et nyt niveau under Medlemskaber. Du vælger prisen og betalingen (månedligt eller årligt) og bestemmer, hvilke områder og hvilket indhold niveauet giver adgang til.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_mitgliedschaften-preise_2', c."id", 'Hvordan bliver jeg betalende medlem?', 'Vælg det ønskede medlemskab i fællesskabet og gennemfør betalingen via den sikre kasse. Din adgang åbnes med det samme.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_mitgliedschaften-preise_3', c."id", 'Kan jeg ændre eller opsige mit medlemskab?', 'Ja. I dine medlemskabsindstillinger kan du til enhver tid skifte eller opsige.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_mitgliedschaften-preise_4', c."id", 'Hvad sker der med min adgang efter købet?', 'Betalte områder og indhold åbnes automatisk. Udløber et medlemskab, spærres de igen — men dine egne opslag og data bevares.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_0', c."id", 'Hvordan betaler jeg sikkert?', 'Betalinger håndteres via vores betalingsudbyder Stripe. Dine betalingsoplysninger behandles krypteret der — Aera gemmer ikke selv kortoplysninger.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_1', c."id", 'Hvilke betalingsmidler kan jeg bruge?', 'Afhængigt af land og enhed har du for eksempel adgang til kredit- og debitkort samt gængse digitale betalingsmidler. Hvilke muligheder der er, ser du direkte i kassen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_2', c."id", 'Får jeg en kvittering eller en faktura?', 'Ja. Efter hvert køb får du en bekræftelse på e-mail. Dine køb finder du desuden altid i dine kontoindstillinger.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_3', c."id", 'Hvordan får jeg som kreator mine indtægter?', 'Dine udbetalinger håndteres sikkert via Stripe. Du angiver dine udbetalingsoplysninger én gang, og derefter overføres dine indtægter automatisk til dig.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_4', c."id", 'Hvilke gebyrer betaler kreatorer?', 'Aera beholder et lille platformgebyr ved salg. Derudover kan der påløbe gebyrer fra betalingsudbyderen ved betalingsafviklingen. Resten af dine indtægter tilhører dig.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_bezahlen-auszahlungen_5', c."id", 'Hvordan fungerer refunderinger?', 'En refundering igangsættes af den pågældende kreator. Har du spørgsmål til et køb, så henvend dig først til fællesskabets kreator — eller til vores support, hvis du ikke kommer videre.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_0', c."id", 'Hvordan udgiver jeg et opslag?', 'Åbn det rette område, vælg „Nyt opslag", tilføj tekst og medier, og udgiv. Du fastlægger samtidig, hvilke medlemmer der må se opslaget.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_1', c."id", 'Hvordan opretter jeg et kursus?', 'Opret et kursusområde og tilføj lektioner eller moduler. Du bestemmer, om kurset er frit tilgængeligt eller en del af et betalt medlemskab.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_2', c."id", 'Hvordan planlægger jeg et event?', 'I events-området fastlægger du titel, tidspunkt og detaljer. Medlemmer kan tilmelde sig. Events kan du tilbyde gratis eller mod betaling.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_3', c."id", 'Hvordan sender jeg et nyhedsbrev?', 'Skriv et nyhedsbrev i dashboardet og send det til alle eller til udvalgte medlemmer. Sådan når du dit fællesskab direkte i deres indbakke — uden en fremmed algoritme imellem.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_4', c."id", 'Hvad er mediebiblioteket?', 'Mediebiblioteket er det centrale sted for dine videoer, lydfiler og filer. Herfra indsætter du dem i opslag, kurser eller events.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_inhalte-erstellen_5', c."id", 'Kan jeg planlægge opslag i forvejen?', 'Ja. Du kan planlægge indhold til et senere tidspunkt, så det udkommer automatisk — praktisk for at forblive aktiv regelmæssigt.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_0', c."id", 'Hvordan bliver jeg en del af et fællesskab?', 'Åbn fællesskabet og vælg „Deltag". Ved gratis fællesskaber er du med med det samme. Ved betalte vælger du først et medlemskab.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_1', c."id", 'Hvordan skriver jeg opslag og kommentarer?', 'I alle de områder, du har adgang til, kan du skrive opslag, kommentere og reagere — ligesom på et socialt netværk, bare uden en fremmed algoritme.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_2', c."id", 'Hvor finder jeg kurser og events?', 'Kurser, du har adgang til, finder du i området „Kurser", og kommende datoer under „Events". Hvad du kan se, afhænger af dit medlemskab.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_3', c."id", 'Hvad er point, niveauer og badges?', 'For din aktivitet samler du point, stiger i niveau og optjener badges. En rangliste viser særligt aktive medlemmer — det gør det mere levende at være med.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_4', c."id", 'Kan jeg skrive til andre medlemmer?', 'Ja, så længe kreatoren har aktiveret chat og direkte beskeder, kan du udveksle med andre medlemmer.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_teilnehmen_5', c."id", 'Hvordan indstiller jeg mine notifikationer?', 'I dine kontoindstillinger fastlægger du, hvad du vil have besked om via e-mail og i appen.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_ki-funktionen_0', c."id", 'Hvad kan AI-assistenten?', 'AI-assistenten hjælper dig med at skrive opslag, nyhedsbreve og med at samle idéer. Den giver dig et udgangspunkt, som du tilpasser — kontrollen beholder du altid selv.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_ki-funktionen_1', c."id", 'Hvad er AI-anbefalinger?', 'Aera foreslår medlemmerne relevant indhold, så de hurtigere finder det, der interesserer dem. Er der ingen AI aktiv, fungerer det via en enkel, gennemsigtig søgning på nøgleord.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_ki-funktionen_2', c."id", 'Hvad er AI-saldoen?', 'AI-funktioner bruger saldo. Hvert fællesskab har en saldo, og efter behov kan du købe ekstra pakker til.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_ki-funktionen_3', c."id", 'Hvad sker der, når AI-saldoen er brugt op?', 'Så sættes AI-funktionerne på pause, indtil du fylder ny saldo på. Alle øvrige funktioner i dit fællesskab kører helt normalt videre.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_ki-funktionen_4', c."id", 'Bliver mit indhold brugt til AI-træning?', 'Nej. Dit indhold tilhører dig. Det bruges kun til at levere de funktioner til dig, som du selv anvender.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_0', c."id", 'Hvordan ændrer jeg min profil eller adgangskode?', 'I dine kontoindstillinger kan du til enhver tid tilpasse navn, profilbillede, e-mailadresse og adgangskode.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_1', c."id", 'Hvordan administrerer jeg mine medlemmer?', 'I dashboardet ser du alle medlemmer af dit fællesskab. Du kan tildele roller som moderator, invitere nye medlemmer eller fjerne medlemmer.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_2', c."id", 'Tilhører mine data mig?', 'Ja. Dit fællesskab, din medlemsliste og dit indhold tilhører dig. Du kan til enhver tid downloade dine data — du er ikke bundet til noget.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_3', c."id", 'Hvordan downloader jeg mine data?', 'I indstillingerne finder du dataeksporten. Med den får du dit indhold i et gængs format klar til download.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_4', c."id", 'Hvor sikre er mine data?', 'Hvert fællesskab er holdt pænt adskilt fra alle andre og beskyttet, så ingen andre har adgang. Dine betalingsoplysninger ligger udelukkende hos betalingsudbyderen, ikke hos Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_5', c."id", 'Hvordan sletter jeg mit fællesskab eller min konto?', 'Det gør du i indstillingerne. Ved sletning fjernes det tilhørende indhold — download dine data på forhånd, hvis du har brug for dem.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_da_konto-marke-daten_6', c."id", 'Hvordan kontakter jeg supporten?', 'Brug kontaktknappen nederst i hjælpecenteret. Beskriv dit spørgsmål så præcist som muligt, så kan vi hurtigt hjælpe dig videre.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_da_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_erste-schritte', 'es', 'Primeros pasos', 'erste-schritte', 'Conoce Aera, crea una cuenta y encuentra una comunidad.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_community-starten', 'es', 'Crea tu comunidad', 'community-starten', 'Construye tu propia comunidad bajo tu marca en pocos minutos.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_mitgliedschaften-preise', 'es', 'Membresías y precios', 'mitgliedschaften-preise', 'Configura y entiende las membresías gratuitas y de pago.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_bezahlen-auszahlungen', 'es', 'Pagos y cobros', 'bezahlen-auszahlungen', 'Pago seguro, cobros para creadores, recibos y reembolsos.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_inhalte-erstellen', 'es', 'Contenidos: publicaciones, cursos, eventos y newsletter', 'inhalte-erstellen', 'Publica, enseña, organiza eventos y llega directamente a tus miembros.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_teilnehmen', 'es', 'Para miembros: participar', 'teilnehmen', 'Únete, participa, aprende y mantén el contacto.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_ki-funktionen', 'es', 'Funciones de IA', 'ki-funktionen', 'El asistente de IA, las recomendaciones y el saldo de IA.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es_konto-marke-daten', 'es', 'Cuenta, marca y datos', 'konto-marke-daten', 'Perfil y seguridad, personalización de la marca, gestión de miembros y descarga de datos.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_erste-schritte_0', c."id", '¿Qué es Aera?', 'Aera es una plataforma en la que los creadores gestionan su propia comunidad bajo su propia marca, con membresías, cursos, eventos, newsletter y mucho más, todo en un mismo lugar.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_erste-schritte_1', c."id", '¿Cómo creo una cuenta?', 'Haz clic en «Registrarse» y date de alta con tu dirección de correo electrónico y una contraseña.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_erste-schritte_2', c."id", '¿Necesito una cuenta para echar un vistazo?', 'Muchas páginas de comunidades puedes verlas también sin cuenta. En cuanto quieras unirte, participar o comprar algo, necesitarás una cuenta gratuita.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_erste-schritte_3', c."id", '¿Cómo encuentro una comunidad?', 'En «Descubrir», dentro de la página de inicio, encontrarás comunidades públicas. O bien puedes abrir directamente la dirección o el enlace que te haya dado un creador (por ejemplo, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_erste-schritte_4', c."id", '¿Cuánto cuesta Aera?', 'Crear una cuenta y unirse a una comunidad es gratis.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_0', c."id", '¿Cómo creo mi propia comunidad?', 'Elige «Crear comunidad». Defines el nombre y la dirección y ajustas unas cuantas opciones básicas. Después llegas directamente a tu panel de control y puedes empezar.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_1', c."id", '¿Qué es el panel de control?', 'El panel de control es tu centro de mando. Desde aquí configuras espacios, publicas contenidos, gestionas miembros, defines membresías y precios, envías newsletters y ves tus cifras más importantes.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_2', c."id", '¿Qué son los espacios?', 'Los espacios son las salas de tu comunidad, por ejemplo un feed para publicaciones, cursos, eventos, un chat o una mediateca.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_3', c."id", '¿Puedo adaptar el aspecto a mi marca?', 'Sí. Puedes ajustar el logotipo, los colores y el diseño para que tu comunidad tenga el aspecto de tu propia marca. Aera pasa a un segundo plano de forma intencionada: quien está en primer plano eres tú.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_4', c."id", '¿Tengo una dirección propia?', 'Sí. Tu comunidad recibe su propia dirección de internet (por ejemplo, deinname.aera.so). También puedes conectar tu propio dominio personalizado.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_community-starten_5', c."id", '¿Cómo invito a los primeros miembros?', 'Simplemente comparte el enlace a tu comunidad, a través de redes sociales, mensajería o correo electrónico. Más adelante podrás llegar a tus miembros en cualquier momento directamente con la newsletter, sin ningún algoritmo de por medio.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_mitgliedschaften-preise_0', c."id", '¿Qué es una membresía?', 'Una membresía define qué puede ver y hacer un miembro en tu comunidad. Puede haber niveles gratuitos y de pago, por ejemplo «Gratis», «Plus» y «Premium».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_mitgliedschaften-preise_1', c."id", '¿Cómo creo una membresía de pago?', 'En el panel de control creas un nuevo nivel dentro de Membresías. Eliges el precio y la forma de cobro (mensual o anual) y decides qué espacios y contenidos desbloquea ese nivel.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_mitgliedschaften-preise_2', c."id", '¿Cómo me hago miembro de pago?', 'Elige en la comunidad la membresía que quieras y completa el pago a través del proceso de compra seguro. Tu acceso se activa de inmediato.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_mitgliedschaften-preise_3', c."id", '¿Puedo cambiar o cancelar mi membresía?', 'Sí. En los ajustes de tu membresía puedes cambiar o cancelar en cualquier momento.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_mitgliedschaften-preise_4', c."id", '¿Qué pasa con mi acceso después de la compra?', 'Los espacios y contenidos de pago se desbloquean automáticamente. Si una membresía caduca, se vuelven a bloquear, pero tus propias publicaciones y datos se conservan.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_0', c."id", '¿Cómo pago de forma segura?', 'Los pagos se procesan a través de nuestro proveedor de pagos, Stripe. Tus datos de pago se procesan allí de forma cifrada; Aera no guarda ningún dato de tarjeta.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_1', c."id", '¿Qué medios de pago puedo usar?', 'Según el país y el dispositivo, tienes a tu disposición, por ejemplo, tarjetas de crédito y débito, así como los medios de pago digitales más habituales. Verás qué opciones están disponibles directamente en el momento de pagar.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_2', c."id", '¿Recibo un recibo o una factura?', 'Sí. Después de cada compra recibes una confirmación por correo electrónico. Además, siempre puedes consultar tus compras en los ajustes de tu cuenta.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_3', c."id", 'Como creador, ¿cómo recibo mis ingresos?', 'Tus cobros se gestionan de forma segura a través de Stripe. Introduces una sola vez tus datos de cobro y, a partir de ahí, tus ingresos se transfieren a ti automáticamente.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_4', c."id", '¿Qué comisiones se aplican a los creadores?', 'Aera se queda con una pequeña comisión de plataforma en cada venta. Además, al procesar el pago pueden aplicarse comisiones del proveedor de pagos. El resto de tus ingresos es tuyo.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_bezahlen-auszahlungen_5', c."id", '¿Cómo funcionan los reembolsos?', 'El reembolso lo inicia el creador correspondiente. Si tienes dudas sobre una compra, dirígete primero al creador de la comunidad, o a nuestro equipo de soporte si no consigues resolverlo.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_0', c."id", '¿Cómo publico una publicación?', 'Abre el espacio adecuado, elige «Nueva publicación», añade texto y contenido multimedia y publícala. Al hacerlo, decides qué miembros pueden ver la publicación.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_1', c."id", '¿Cómo creo un curso?', 'Crea un espacio de curso y añade lecciones o módulos. Tú decides si el curso es de acceso libre o forma parte de una membresía de pago.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_2', c."id", '¿Cómo planifico un evento?', 'En el espacio de eventos defines el título, la fecha y los detalles. Los miembros pueden confirmar su asistencia. Puedes ofrecer eventos gratuitos o de pago.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_3', c."id", '¿Cómo envío una newsletter?', 'Redacta una newsletter en el panel de control y envíala a todos o a miembros seleccionados. Así llegas a tu comunidad directamente en su bandeja de entrada, sin ningún algoritmo ajeno de por medio.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_4', c."id", '¿Qué es la mediateca?', 'La mediateca es el lugar central para tus vídeos, audios y archivos. Desde ahí los integras en publicaciones, cursos o eventos.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_inhalte-erstellen_5', c."id", '¿Puedo programar publicaciones con antelación?', 'Sí. Puedes programar contenidos para un momento posterior, de modo que aparezcan automáticamente; muy práctico para mantenerte activo con regularidad.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_0', c."id", '¿Cómo me uno a una comunidad?', 'Abre la comunidad y elige «Unirse». En las comunidades gratuitas entras al momento. En las de pago, primero eliges una membresía.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_1', c."id", '¿Cómo escribo publicaciones y comentarios?', 'En todos los espacios a los que tienes acceso puedes escribir publicaciones, comentar y reaccionar, de forma parecida a una red social, pero sin ningún algoritmo ajeno.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_2', c."id", '¿Dónde encuentro cursos y eventos?', 'Los cursos desbloqueados los encuentras en el espacio «Cursos», y las próximas citas en «Eventos». Lo que puedes ver depende de tu membresía.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_3', c."id", '¿Qué son los puntos, los niveles y las insignias?', 'Por tu actividad acumulas puntos, subes de nivel y consigues insignias. Una tabla de clasificación muestra a los miembros más activos, lo que hace que participar sea más ameno.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_4', c."id", '¿Puedo escribir a otros miembros?', 'Sí, siempre que el creador haya activado el chat y los mensajes directos, puedes comunicarte con otros miembros.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_teilnehmen_5', c."id", '¿Cómo configuro mis notificaciones?', 'En los ajustes de tu cuenta decides sobre qué quieres que te informemos por correo electrónico y dentro de la aplicación.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_ki-funktionen_0', c."id", '¿Qué puede hacer el asistente de IA?', 'El asistente de IA te ayuda a escribir publicaciones y newsletters y a reunir ideas. Te ofrece un punto de partida que tú adaptas: el control siempre lo tienes tú.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_ki-funktionen_1', c."id", '¿Qué son las recomendaciones de IA?', 'Aera sugiere a los miembros contenidos que encajan con ellos, para que encuentren antes lo que les interesa. Si no hay ninguna IA activa, esto funciona mediante una búsqueda sencilla y transparente por palabras clave.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_ki-funktionen_2', c."id", '¿Qué es el saldo de IA?', 'Las funciones de IA consumen saldo. Cada comunidad tiene un saldo y, si lo necesitas, puedes comprar paquetes adicionales.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_ki-funktionen_3', c."id", '¿Qué pasa cuando se agota el saldo de IA?', 'Entonces las funciones de IA se pausan hasta que recargas saldo. Todas las demás funciones de tu comunidad siguen funcionando con total normalidad.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_ki-funktionen_4', c."id", '¿Se usan mis contenidos para entrenar la IA?', 'No. Tus contenidos son tuyos. Solo se utilizan para ofrecerte las funciones que tú mismo usas.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_0', c."id", '¿Cómo cambio mi perfil o mi contraseña?', 'En los ajustes de tu cuenta puedes cambiar en cualquier momento el nombre, la foto de perfil, la dirección de correo electrónico y la contraseña.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_1', c."id", '¿Cómo gestiono a mis miembros?', 'En el panel de control ves a todos los miembros de tu comunidad. Puedes asignar roles como el de moderador, invitar a nuevos miembros o eliminar a miembros.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_2', c."id", '¿Mis datos son míos?', 'Sí. Tu comunidad, tu lista de miembros y tus contenidos son tuyos. Puedes descargar tus datos en cualquier momento: no estás atado a nada.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_3', c."id", '¿Cómo descargo mis datos?', 'En los ajustes encontrarás la exportación de datos. Con ella obtienes tus contenidos en un formato habitual listo para descargar.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_4', c."id", '¿Qué seguridad tienen mis datos?', 'Cada comunidad está claramente separada de todas las demás y protegida, de modo que nadie más tiene acceso. Tus datos de pago están únicamente en el proveedor de pagos, no en Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_5', c."id", '¿Cómo elimino mi comunidad o mi cuenta?', 'Puedes hacerlo en los ajustes. Al eliminarla, se borran los contenidos asociados; si lo necesitas, descarga antes tus datos.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es_konto-marke-daten_6', c."id", '¿Cómo contacto con el soporte?', 'Usa el botón de contacto al final del centro de ayuda. Describe tu consulta con el mayor detalle posible para que podamos ayudarte rápidamente.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_erste-schritte', 'es-419', 'Primeros pasos', 'erste-schritte', 'Conoce Aera, crea una cuenta y encuentra una comunidad.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_community-starten', 'es-419', 'Crear tu comunidad', 'community-starten', 'Construye tu propia comunidad bajo tu marca en pocos minutos.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_mitgliedschaften-preise', 'es-419', 'Membresías y precios', 'mitgliedschaften-preise', 'Configura y comprende las membresías gratuitas y de pago.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_bezahlen-auszahlungen', 'es-419', 'Pagos y cobros', 'bezahlen-auszahlungen', 'Pago seguro, cobros para creadores, comprobantes y reembolsos.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_inhalte-erstellen', 'es-419', 'Contenido: publicaciones, cursos, eventos y newsletter', 'inhalte-erstellen', 'Publica, enseña, organiza eventos y llega directamente a tus miembros.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_teilnehmen', 'es-419', 'Para miembros: participar', 'teilnehmen', 'Únete, participa, aprende y mantente en contacto.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_ki-funktionen', 'es-419', 'Funciones de IA', 'ki-funktionen', 'El asistente de IA, las recomendaciones y el saldo de IA.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_es-419_konto-marke-daten', 'es-419', 'Cuenta, marca y datos', 'konto-marke-daten', 'Perfil y seguridad, personalizar tu marca, gestionar miembros y descargar tus datos.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_erste-schritte_0', c."id", '¿Qué es Aera?', 'Aera es una plataforma donde los creadores gestionan su propia comunidad bajo su propia marca, con membresías, cursos, eventos, newsletter y mucho más en un solo lugar.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_erste-schritte_1', c."id", '¿Cómo creo una cuenta?', 'Haz clic en «Registrarte» e ingresa con tu correo electrónico y una contraseña.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_erste-schritte_2', c."id", '¿Necesito una cuenta para explorar?', 'Muchas páginas de comunidades puedes verlas sin necesidad de una cuenta. En cuanto quieras unirte, participar o comprar algo, necesitarás una cuenta gratuita.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_erste-schritte_3', c."id", '¿Cómo encuentro una comunidad?', 'En «Descubrir», dentro de la página de inicio, encuentras comunidades públicas. O también puedes abrir directamente la dirección o el enlace que te haya compartido un creador (por ejemplo, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_erste-schritte_4', c."id", '¿Cuánto cuesta Aera?', 'Crear una cuenta y unirte a una comunidad es gratis.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_0', c."id", '¿Cómo creo mi propia comunidad?', 'Elige «Crear comunidad». Defines el nombre y la dirección, y ajustas algunas configuraciones básicas. Después llegas directo a tu panel de control y puedes empezar.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_1', c."id", '¿Qué es el panel de control?', 'El panel de control es tu centro de mando. Desde aquí configuras espacios, publicas contenido, gestionas a tus miembros, defines membresías y precios, envías newsletters y ves tus cifras más importantes.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_2', c."id", '¿Qué son los espacios?', 'Los espacios son las salas de tu comunidad, por ejemplo un feed para publicaciones, cursos, eventos, un chat o una biblioteca de medios.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_3', c."id", '¿Puedo adaptar la apariencia a mi marca?', 'Sí. Puedes ajustar el logo, los colores y el diseño para que tu comunidad se vea como tu propia marca. Aera pasa a un segundo plano a propósito: el protagonista eres tú.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_4', c."id", '¿Obtengo mi propia dirección?', 'Sí. Tu comunidad recibe su propia dirección de internet (por ejemplo, deinname.aera.so). También puedes conectar tu propio dominio personalizado.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_community-starten_5', c."id", '¿Cómo invito a mis primeros miembros?', 'Solo comparte el enlace de tu comunidad, ya sea por redes sociales, mensajería o correo electrónico. Más adelante podrás llegar a tus miembros en cualquier momento directamente a través del newsletter, sin ningún algoritmo de por medio.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_mitgliedschaften-preise_0', c."id", '¿Qué es una membresía?', 'Una membresía define lo que un miembro puede ver y hacer en tu comunidad. Puede haber niveles gratuitos y de pago, por ejemplo «Gratis», «Plus» y «Premium».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_mitgliedschaften-preise_1', c."id", '¿Cómo creo una membresía de pago?', 'En el panel de control creas un nuevo nivel dentro de Membresías. Eliges el precio y el tipo de cobro (mensual o anual) y defines qué espacios y contenidos desbloquea ese nivel.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_mitgliedschaften-preise_2', c."id", '¿Cómo me convierto en miembro de pago?', 'Elige en la comunidad la membresía que quieras y completa el pago a través del proceso de compra seguro. Tu acceso se activa de inmediato.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_mitgliedschaften-preise_3', c."id", '¿Puedo cambiar o cancelar mi membresía?', 'Sí. En la configuración de tu membresía puedes cambiar o cancelar en cualquier momento.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_mitgliedschaften-preise_4', c."id", '¿Qué pasa con mi acceso después de la compra?', 'Los espacios y contenidos de pago se desbloquean automáticamente. Si una membresía vence, vuelven a bloquearse, pero tus propias publicaciones y datos se conservan.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_0', c."id", '¿Cómo pago de forma segura?', 'Los pagos se procesan a través de nuestro proveedor de pagos Stripe. Ahí tus datos de pago se procesan de forma cifrada; Aera no guarda ningún dato de tu tarjeta.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_1', c."id", '¿Qué medios de pago puedo usar?', 'Según tu país y dispositivo, tienes disponibles, por ejemplo, tarjetas de crédito y débito, además de los medios de pago digitales más comunes. Puedes ver qué opciones están disponibles directamente al momento de pagar.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_2', c."id", '¿Recibo un comprobante o una factura?', 'Sí. Después de cada compra recibes una confirmación por correo electrónico. Además, puedes encontrar tus compras en cualquier momento en la configuración de tu cuenta.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_3', c."id", '¿Cómo recibo mis ingresos como creador?', 'Tus cobros se realizan de forma segura a través de Stripe. Registras una sola vez tus datos de cobro y, a partir de ahí, tus ingresos se transfieren automáticamente.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_4', c."id", '¿Qué comisiones se aplican a los creadores?', 'Aera retiene una pequeña comisión de la plataforma en cada venta. Además, al procesar el pago pueden aplicarse comisiones del proveedor de pagos. El resto de tus ingresos es tuyo.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_bezahlen-auszahlungen_5', c."id", '¿Cómo funcionan los reembolsos?', 'El reembolso lo inicia el creador correspondiente. Si tienes preguntas sobre una compra, contacta primero al creador de la comunidad o a nuestro equipo de soporte si no encuentras una solución.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_0', c."id", '¿Cómo creo una publicación?', 'Abre el espacio correspondiente, elige «Nueva publicación», agrega texto y archivos multimedia, y publícala. Ahí defines qué miembros pueden ver la publicación.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_1', c."id", '¿Cómo creo un curso?', 'Crea un espacio de curso y agrega lecciones o módulos. Tú decides si el curso es de acceso libre o parte de una membresía de pago.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_2', c."id", '¿Cómo organizo un evento?', 'En el espacio de eventos defines el título, la fecha y los detalles. Los miembros pueden confirmar su asistencia. Puedes ofrecer eventos gratuitos o de pago.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_3', c."id", '¿Cómo envío un newsletter?', 'Redacta un newsletter en el panel de control y envíalo a todos tus miembros o a algunos en particular. Así llegas a tu comunidad directamente en su bandeja de entrada, sin ningún algoritmo ajeno de por medio.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_4', c."id", '¿Qué es la biblioteca de medios?', 'La biblioteca de medios es el lugar central para tus videos, audios y archivos. Desde ahí los agregas a publicaciones, cursos o eventos.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_inhalte-erstellen_5', c."id", '¿Puedo programar publicaciones con anticipación?', 'Sí. Puedes programar contenido para un momento posterior, de modo que aparezca automáticamente; muy práctico para mantenerte activo con regularidad.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_0', c."id", '¿Cómo me uno a una comunidad?', 'Abre la comunidad y elige «Unirte». En las comunidades gratuitas quedas dentro de inmediato. En las de pago, primero eliges una membresía.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_1', c."id", '¿Cómo escribo publicaciones y comentarios?', 'En todos los espacios a los que tienes acceso, puedes escribir publicaciones, comentar y reaccionar, muy parecido a una red social, pero sin algoritmos ajenos.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_2', c."id", '¿Dónde encuentro los cursos y eventos?', 'Los cursos desbloqueados los encuentras en el espacio «Cursos», y las próximas fechas en «Eventos». Lo que puedes ver depende de tu membresía.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_3', c."id", '¿Qué son los puntos, niveles e insignias?', 'Por tu actividad acumulas puntos, subes de nivel y ganas insignias. Una tabla de clasificación muestra a los miembros más activos; así participar se vuelve más divertido.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_4', c."id", '¿Puedo escribirles a otros miembros?', 'Sí, siempre que el creador haya activado el chat y los mensajes directos, puedes conversar con otros miembros.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_teilnehmen_5', c."id", '¿Cómo configuro mis notificaciones?', 'En la configuración de tu cuenta defines sobre qué quieres recibir información por correo electrónico y en la aplicación.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_ki-funktionen_0', c."id", '¿Qué puede hacer el asistente de IA?', 'El asistente de IA te ayuda a escribir publicaciones, newsletters y a reunir ideas. Te da un punto de partida que luego ajustas; el control siempre lo tienes tú.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_ki-funktionen_1', c."id", '¿Qué son las recomendaciones de IA?', 'Aera sugiere a los miembros contenido relevante para que encuentren más rápido lo que les interesa. Si no hay IA activa, esto funciona mediante una búsqueda sencilla y transparente por palabras clave.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_ki-funktionen_2', c."id", '¿Qué es el saldo de IA?', 'Las funciones de IA consumen saldo. Cada comunidad tiene un saldo y, si lo necesitas, puedes comprar paquetes adicionales.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_ki-funktionen_3', c."id", '¿Qué pasa cuando se agota el saldo de IA?', 'Entonces las funciones de IA se pausan hasta que recargues saldo. Todas las demás funciones de tu comunidad siguen funcionando con normalidad.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_ki-funktionen_4', c."id", '¿Se usan mis contenidos para entrenar la IA?', 'No. Tus contenidos son tuyos. Solo se usan para ofrecerte las funciones que tú mismo utilizas.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_0', c."id", '¿Cómo cambio mi perfil o contraseña?', 'En la configuración de tu cuenta puedes cambiar tu nombre, foto de perfil, correo electrónico y contraseña en cualquier momento.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_1', c."id", '¿Cómo gestiono a mis miembros?', 'En el panel de control ves a todos los miembros de tu comunidad. Puedes asignar roles como el de moderador, invitar a nuevos miembros o quitar a miembros.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_2', c."id", '¿Mis datos me pertenecen?', 'Sí. Tu comunidad, tu lista de miembros y tus contenidos son tuyos. Puedes descargar tus datos en cualquier momento; no estás atado a nada.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_3', c."id", '¿Cómo descargo mis datos?', 'En la configuración encuentras la exportación de datos. Con ella obtienes tus contenidos en un formato común, listos para descargar.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_4', c."id", '¿Qué tan seguros están mis datos?', 'Cada comunidad está claramente separada y protegida de todas las demás, de modo que nadie más tiene acceso. Tus datos de pago están únicamente en el proveedor de pagos, no en Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_5', c."id", '¿Cómo elimino mi comunidad o mi cuenta?', 'Puedes hacerlo en la configuración. Al eliminar, se borran los contenidos asociados; si lo necesitas, descarga antes tus datos.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_es-419_konto-marke-daten_6', c."id", '¿Cómo contacto al soporte?', 'Usa el botón de contacto al final del centro de ayuda. Describe tu solicitud con el mayor detalle posible para que podamos ayudarte rápidamente.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_es-419_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_erste-schritte', 'fr', 'Premiers pas', 'erste-schritte', 'Découvrez Aera, créez un compte et trouvez une communauté.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_community-starten', 'fr', 'Lancer votre communauté', 'community-starten', 'Créez votre propre communauté sous votre marque en quelques minutes.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_mitgliedschaften-preise', 'fr', 'Abonnements et tarifs', 'mitgliedschaften-preise', 'Configurez et comprenez les abonnements gratuits et payants.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_bezahlen-auszahlungen', 'fr', 'Paiements et versements', 'bezahlen-auszahlungen', 'Paiement sécurisé, versements aux créateurs, reçus et remboursements.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_inhalte-erstellen', 'fr', 'Contenus : publications, cours, événements et newsletter', 'inhalte-erstellen', 'Publiez, enseignez, organisez des événements et joignez vos membres directement.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_teilnehmen', 'fr', 'Pour les membres : participer', 'teilnehmen', 'Rejoignez, participez, apprenez et restez en contact.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_ki-funktionen', 'fr', 'Fonctions d''IA', 'ki-funktionen', 'L''assistant IA, les recommandations et le crédit IA.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_fr_konto-marke-daten', 'fr', 'Compte, marque et données', 'konto-marke-daten', 'Profil et sécurité, personnalisation de la marque, gestion des membres et téléchargement des données.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_erste-schritte_0', c."id", 'Qu''est-ce qu''Aera ?', 'Aera est une plateforme sur laquelle les créateurs animent leur propre communauté sous leur propre marque — avec des abonnements, des cours, des événements, une newsletter et bien plus, le tout au même endroit.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_erste-schritte_1', c."id", 'Comment créer un compte ?', 'Cliquez sur « S''inscrire » et connectez-vous avec votre adresse e-mail et un mot de passe.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_erste-schritte_2', c."id", 'Ai-je besoin d''un compte pour explorer ?', 'Vous pouvez consulter de nombreuses pages de communauté sans compte. Dès que vous souhaitez rejoindre une communauté, participer ou acheter quelque chose, il vous faut un compte gratuit.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_erste-schritte_3', c."id", 'Comment trouver une communauté ?', 'Via « Découvrir » sur la page d''accueil, vous trouvez les communautés publiques. Vous pouvez aussi ouvrir directement l''adresse ou le lien qu''un créateur vous a communiqué (par exemple name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_erste-schritte_4', c."id", 'Combien coûte Aera ?', 'Créer un compte et rejoindre une communauté est gratuit.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_0', c."id", 'Comment lancer ma propre communauté ?', 'Choisissez « Lancer une communauté ». Vous définissez le nom et l''adresse, puis réglez quelques paramètres de base. Vous arrivez ensuite directement dans votre tableau de bord et pouvez vous lancer.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_1', c."id", 'Qu''est-ce que le tableau de bord ?', 'Le tableau de bord est votre centre de commande. Depuis cet espace, vous configurez des espaces, publiez du contenu, gérez vos membres, définissez les abonnements et les tarifs, envoyez des newsletters et consultez vos chiffres les plus importants.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_2', c."id", 'Que sont les espaces ?', 'Les espaces sont les lieux de votre communauté — par exemple un fil d''actualité pour les publications, des cours, des événements, un chat ou une médiathèque.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_3', c."id", 'Puis-je adapter l''apparence à ma marque ?', 'Oui. Vous pouvez régler le logo, les couleurs et la mise en page pour que votre communauté reflète pleinement votre propre marque. Aera s''efface volontairement — c''est vous qui êtes mis en avant.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_4', c."id", 'Est-ce que j''obtiens ma propre adresse ?', 'Oui. Votre communauté reçoit sa propre adresse Internet (par exemple deinname.aera.so). Vous pouvez également relier votre propre nom de domaine personnalisé.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_community-starten_5', c."id", 'Comment inviter les premiers membres ?', 'Partagez simplement le lien vers votre communauté — sur les réseaux sociaux, par messagerie ou par e-mail. Par la suite, vous pouvez joindre vos membres à tout moment directement via la newsletter, sans aucun algorithme entre vous.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_mitgliedschaften-preise_0', c."id", 'Qu''est-ce qu''un abonnement ?', 'Un abonnement définit ce qu''un membre peut voir et faire dans votre communauté. Il peut exister des niveaux gratuits et payants — par exemple « Gratuit », « Plus » et « Premium ».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_mitgliedschaften-preise_1', c."id", 'Comment créer un abonnement payant ?', 'Dans le tableau de bord, sous Abonnements, vous créez un nouveau niveau. Vous choisissez le prix et la facturation (mensuelle ou annuelle) et déterminez quels espaces et contenus ce niveau débloque.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_mitgliedschaften-preise_2', c."id", 'Comment devenir membre payant ?', 'Dans la communauté, choisissez l''abonnement souhaité et finalisez le paiement via le paiement sécurisé. Votre accès s''active immédiatement.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_mitgliedschaften-preise_3', c."id", 'Puis-je modifier ou résilier mon abonnement ?', 'Oui. Dans les paramètres de votre abonnement, vous pouvez changer de formule ou résilier à tout moment.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_mitgliedschaften-preise_4', c."id", 'Qu''advient-il de mon accès après l''achat ?', 'Les espaces et contenus payants se débloquent automatiquement. Lorsqu''un abonnement prend fin, ils sont de nouveau verrouillés — vos propres publications et données, elles, sont conservées.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_0', c."id", 'Comment payer en toute sécurité ?', 'Les paiements passent par notre prestataire de paiement Stripe. Vos données de paiement y sont traitées de manière chiffrée — Aera n''enregistre elle-même aucune donnée de carte.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_1', c."id", 'Quels moyens de paiement puis-je utiliser ?', 'Selon votre pays et votre appareil, vous disposez par exemple des cartes de crédit et de débit ainsi que des moyens de paiement numériques courants. Les options disponibles s''affichent directement au moment du paiement.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_2', c."id", 'Est-ce que je reçois un reçu ou une facture ?', 'Oui. Après chaque achat, vous recevez une confirmation par e-mail. Vous retrouvez également vos achats à tout moment dans les paramètres de votre compte.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_3', c."id", 'Comment reçois-je mes revenus en tant que créateur ?', 'Vos versements passent en toute sécurité par Stripe. Vous renseignez une seule fois vos coordonnées de versement, puis vos revenus vous sont automatiquement transférés.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_4', c."id", 'Quels frais s''appliquent aux créateurs ?', 'Lors d''une vente, Aera retient une petite commission de plateforme. Des frais du prestataire de paiement peuvent en outre s''appliquer au traitement du paiement. Le reste de vos revenus vous revient.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_bezahlen-auszahlungen_5', c."id", 'Comment fonctionnent les remboursements ?', 'Un remboursement est déclenché par le créateur concerné. Pour toute question sur un achat, adressez-vous d''abord au créateur de la communauté — ou à notre support si vous ne trouvez pas de solution.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_0', c."id", 'Comment publier une publication ?', 'Ouvrez l''espace approprié, choisissez « Nouvelle publication », ajoutez du texte et des médias, puis publiez. Vous définissez à cette occasion quels membres peuvent voir la publication.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_1', c."id", 'Comment créer un cours ?', 'Créez un espace de cours et ajoutez des leçons ou des modules. Vous décidez si le cours est en accès libre ou fait partie d''un abonnement payant.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_2', c."id", 'Comment planifier un événement ?', 'Dans l''espace Événements, vous définissez le titre, la date et les détails. Les membres peuvent confirmer leur participation. Vous pouvez proposer des événements gratuits ou payants.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_3', c."id", 'Comment envoyer une newsletter ?', 'Rédigez une newsletter dans le tableau de bord et envoyez-la à tous vos membres ou à une sélection d''entre eux. Vous joignez ainsi votre communauté directement dans sa boîte de réception — sans algorithme étranger entre vous.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_4', c."id", 'Qu''est-ce que la médiathèque ?', 'La médiathèque est l''endroit central pour vos vidéos, vos fichiers audio et vos fichiers. Depuis cet espace, vous les intégrez à vos publications, cours ou événements.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_inhalte-erstellen_5', c."id", 'Puis-je programmer des publications à l''avance ?', 'Oui. Vous pouvez programmer des contenus pour une date ultérieure afin qu''ils paraissent automatiquement — pratique pour rester actif régulièrement.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_0', c."id", 'Comment rejoindre une communauté ?', 'Ouvrez la communauté et choisissez « Rejoindre ». Pour les communautés gratuites, vous êtes membre immédiatement. Pour les communautés payantes, vous choisissez d''abord un abonnement.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_1', c."id", 'Comment rédiger des publications et des commentaires ?', 'Dans tous les espaces auxquels vous avez accès, vous pouvez rédiger des publications, commenter et réagir — un peu comme sur un réseau social, mais sans algorithme étranger.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_2', c."id", 'Où trouver les cours et les événements ?', 'Vous trouvez les cours débloqués dans l''espace « Cours » et les prochaines dates sous « Événements ». Ce que vous pouvez voir dépend de votre abonnement.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_3', c."id", 'Que sont les points, les niveaux et les badges ?', 'Grâce à votre activité, vous accumulez des points, montez de niveau et gagnez des badges. Un classement met en avant les membres les plus actifs — de quoi rendre la participation plus vivante.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_4', c."id", 'Puis-je écrire à d''autres membres ?', 'Oui, à condition que le créateur ait activé le chat et les messages privés, vous pouvez échanger avec d''autres membres.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_teilnehmen_5', c."id", 'Comment configurer mes notifications ?', 'Dans les paramètres de votre compte, vous définissez ce dont vous souhaitez être informé par e-mail et dans l''application.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_ki-funktionen_0', c."id", 'Que peut faire l''assistant IA ?', 'L''assistant IA vous aide à rédiger des publications, des newsletters et à rassembler des idées. Il fournit un point de départ que vous ajustez — vous gardez toujours le contrôle.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_ki-funktionen_1', c."id", 'Que sont les recommandations IA ?', 'Aera propose aux membres des contenus adaptés afin qu''ils trouvent plus vite ce qui les intéresse. Si aucune IA n''est active, cela fonctionne via une recherche par mots-clés simple et transparente.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_ki-funktionen_2', c."id", 'Qu''est-ce que le crédit IA ?', 'Les fonctions d''IA consomment du crédit. Chaque communauté dispose d''un crédit, et vous pouvez acheter des packs supplémentaires en cas de besoin.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_ki-funktionen_3', c."id", 'Que se passe-t-il lorsque le crédit IA est épuisé ?', 'Les fonctions d''IA se mettent alors en pause jusqu''à ce que vous rechargiez du crédit. Toutes les autres fonctions de votre communauté continuent de fonctionner tout à fait normalement.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_ki-funktionen_4', c."id", 'Mes contenus sont-ils utilisés pour entraîner l''IA ?', 'Non. Vos contenus vous appartiennent. Ils ne sont utilisés que pour vous fournir les fonctions que vous utilisez vous-même.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_0', c."id", 'Comment modifier mon profil ou mon mot de passe ?', 'Dans les paramètres de votre compte, vous pouvez modifier à tout moment votre nom, votre photo de profil, votre adresse e-mail et votre mot de passe.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_1', c."id", 'Comment gérer mes membres ?', 'Dans le tableau de bord, vous voyez tous les membres de votre communauté. Vous pouvez attribuer des rôles comme modérateur, inviter de nouveaux membres ou en retirer.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_2', c."id", 'Mes données m''appartiennent-elles ?', 'Oui. Votre communauté, votre liste de membres et vos contenus vous appartiennent. Vous pouvez télécharger vos données à tout moment — vous n''êtes lié à rien.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_3', c."id", 'Comment télécharger mes données ?', 'Dans les paramètres, vous trouvez l''export des données. Vous obtenez ainsi vos contenus à télécharger dans un format courant.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_4', c."id", 'Mes données sont-elles bien protégées ?', 'Chaque communauté est proprement séparée de toutes les autres et protégée, de sorte que personne d''autre n''y a accès. Vos données de paiement se trouvent exclusivement chez le prestataire de paiement, et non chez Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_5', c."id", 'Comment supprimer ma communauté ou mon compte ?', 'Cela se fait dans les paramètres. Lors de la suppression, les contenus associés sont supprimés — pensez à télécharger vos données au préalable si besoin.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_fr_konto-marke-daten_6', c."id", 'Comment contacter le support ?', 'Utilisez le bouton de contact au bas du centre d''aide. Décrivez votre demande le plus précisément possible, afin que nous puissions vous aider rapidement.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_fr_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_erste-schritte', 'it', 'Primi passi', 'erste-schritte', 'Scopri Aera, crea un account e trova una community.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_community-starten', 'it', 'Avvia la tua community', 'community-starten', 'Crea in pochi minuti la tua community con il tuo marchio.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_mitgliedschaften-preise', 'it', 'Iscrizioni e prezzi', 'mitgliedschaften-preise', 'Configura e comprendi le iscrizioni gratuite e a pagamento.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_bezahlen-auszahlungen', 'it', 'Pagamenti e pagamenti ai creator', 'bezahlen-auszahlungen', 'Pagamento sicuro, pagamenti ai creator, ricevute e rimborsi.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_inhalte-erstellen', 'it', 'Contenuti: post, corsi, eventi e newsletter', 'inhalte-erstellen', 'Pubblica, insegna, organizza eventi e raggiungi i membri direttamente.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_teilnehmen', 'it', 'Per i membri: partecipare', 'teilnehmen', 'Entra, partecipa, impara e resta in contatto.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_ki-funktionen', 'it', 'Funzioni di IA', 'ki-funktionen', 'L''assistente IA, i suggerimenti e il credito IA.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_it_konto-marke-daten', 'it', 'Account, marchio e dati', 'konto-marke-daten', 'Profilo e sicurezza, personalizza il marchio, gestisci i membri e scarica i dati.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_erste-schritte_0', c."id", 'Che cos''è Aera?', 'Aera è una piattaforma su cui i creator gestiscono la propria community con il proprio marchio: iscrizioni, corsi, eventi, newsletter e molto altro, tutto in un unico posto.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_erste-schritte_1', c."id", 'Come creo un account?', 'Clicca su „Registrati" e accedi con il tuo indirizzo e-mail e una password.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_erste-schritte_2', c."id", 'Mi serve un account per dare un''occhiata?', 'Molte pagine delle community puoi vederle anche senza account. Non appena vuoi entrare, scrivere qualcosa o fare un acquisto, ti serve un account gratuito.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_erste-schritte_3', c."id", 'Come trovo una community?', 'Tramite „Scopri" nella pagina iniziale trovi le community pubbliche. Oppure apri direttamente l''indirizzo o il link che ti ha dato un creator (per esempio name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_erste-schritte_4', c."id", 'Quanto costa Aera?', 'Creare un account ed entrare in una community è gratuito.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_0', c."id", 'Come avvio la mia community?', 'Scegli „Avvia una community". Imposti il nome e l''indirizzo e definisci alcune impostazioni di base. Poi arrivi direttamente nella tua dashboard e puoi cominciare.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_1', c."id", 'Che cos''è la dashboard?', 'La dashboard è la tua cabina di regia. Da qui configuri gli spazi, pubblichi contenuti, gestisci i membri, imposti iscrizioni e prezzi, invii newsletter e vedi i tuoi numeri più importanti.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_2', c."id", 'Che cosa sono gli spazi?', 'Gli spazi sono le stanze della tua community, per esempio un feed per i post, corsi, eventi, una chat o una libreria multimediale.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_3', c."id", 'Posso personalizzare l''aspetto con il mio marchio?', 'Sì. Puoi impostare logo, colori e layout in modo che la tua community sembri il tuo marchio. Aera resta volutamente in secondo piano: in primo piano ci sei tu.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_4', c."id", 'Ricevo un indirizzo mio?', 'Sì. La tua community ottiene un proprio indirizzo web (per esempio deinname.aera.so). Puoi anche collegare un dominio personalizzato tutto tuo.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_community-starten_5', c."id", 'Come invito i primi membri?', 'Basta condividere il link alla tua community, tramite social media, messaggistica o e-mail. In seguito raggiungi i tuoi membri in qualsiasi momento direttamente con la newsletter, senza nessun algoritmo di mezzo.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_mitgliedschaften-preise_0', c."id", 'Che cos''è un''iscrizione?', 'Un''iscrizione stabilisce cosa un membro può vedere e fare nella tua community. Ci possono essere livelli gratuiti e a pagamento, per esempio „Base", „Plus" e „Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_mitgliedschaften-preise_1', c."id", 'Come creo un''iscrizione a pagamento?', 'Nella dashboard, sotto Iscrizioni, crei un nuovo livello. Scegli il prezzo e la fatturazione (mensile o annuale) e stabilisci quali spazi e contenuti sblocca quel livello.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_mitgliedschaften-preise_2', c."id", 'Come divento un membro pagante?', 'Scegli nella community l''iscrizione che desideri e completa il pagamento tramite il checkout sicuro. Il tuo accesso si sblocca subito.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_mitgliedschaften-preise_3', c."id", 'Posso cambiare o annullare la mia iscrizione?', 'Sì. Nelle impostazioni della tua iscrizione puoi cambiare o annullare in qualsiasi momento.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_mitgliedschaften-preise_4', c."id", 'Cosa succede al mio accesso dopo l''acquisto?', 'Gli spazi e i contenuti a pagamento si sbloccano automaticamente. Quando un''iscrizione scade, vengono di nuovo bloccati, ma i tuoi post e i tuoi dati restano al loro posto.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_0', c."id", 'Come pago in modo sicuro?', 'I pagamenti passano attraverso il nostro fornitore di pagamenti Stripe. I tuoi dati di pagamento vengono elaborati lì in modo crittografato: Aera non conserva alcun dato della carta.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_1', c."id", 'Quali metodi di pagamento posso usare?', 'A seconda del paese e del dispositivo hai a disposizione, per esempio, carte di credito e di debito e i più comuni metodi di pagamento digitali. Quali opzioni sono disponibili lo vedi direttamente alla cassa.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_2', c."id", 'Ricevo una ricevuta o una fattura?', 'Sì. Dopo ogni acquisto ricevi una conferma via e-mail. Inoltre trovi i tuoi acquisti in qualsiasi momento nelle impostazioni del tuo account.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_3', c."id", 'Come ricevo i miei guadagni come creator?', 'I tuoi pagamenti passano in modo sicuro attraverso Stripe. Inserisci una sola volta i tuoi dati di pagamento e poi i tuoi guadagni ti vengono versati automaticamente.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_4', c."id", 'Quali commissioni ci sono per i creator?', 'Aera trattiene sulle vendite una piccola commissione di piattaforma. Inoltre, durante l''elaborazione del pagamento possono esserci commissioni del fornitore di pagamenti. Il resto dei tuoi guadagni è tuo.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_bezahlen-auszahlungen_5', c."id", 'Come funzionano i rimborsi?', 'Un rimborso viene avviato dal singolo creator. Per domande su un acquisto rivolgiti prima al creator della community, oppure al nostro supporto se non riesci a risolvere.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_0', c."id", 'Come pubblico un post?', 'Apri lo spazio giusto, scegli „Nuovo post", aggiungi testo e contenuti multimediali e pubblica. Nel farlo stabilisci quali membri possono vedere il post.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_1', c."id", 'Come creo un corso?', 'Crea uno spazio corso e aggiungi lezioni o moduli. Decidi tu se il corso è liberamente accessibile oppure fa parte di un''iscrizione a pagamento.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_2', c."id", 'Come organizzo un evento?', 'Nello spazio eventi imposti titolo, data e dettagli. I membri possono confermare la partecipazione. Gli eventi puoi offrirli gratuitamente o a pagamento.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_3', c."id", 'Come invio una newsletter?', 'Scrivi una newsletter nella dashboard e inviala a tutti o a membri selezionati. Così raggiungi la tua community direttamente nella loro casella di posta, senza nessun algoritmo esterno di mezzo.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_4', c."id", 'Che cos''è la libreria multimediale?', 'La libreria multimediale è il luogo centrale per i tuoi video, audio e file. Da lì li inserisci nei post, nei corsi o negli eventi.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_inhalte-erstellen_5', c."id", 'Posso programmare i post in anticipo?', 'Sì. Puoi programmare i contenuti per un momento successivo, così compaiono automaticamente: comodo per restare attivo con regolarità.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_0', c."id", 'Come entro in una community?', 'Apri la community e scegli „Entra". Nelle community gratuite sei subito dentro. In quelle a pagamento scegli prima un''iscrizione.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_1', c."id", 'Come scrivo post e commenti?', 'In tutti gli spazi a cui hai accesso puoi scrivere post, commentare e reagire, un po'' come in un social network, solo senza nessun algoritmo esterno.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_2', c."id", 'Dove trovo corsi ed eventi?', 'I corsi sbloccati li trovi nello spazio „Corsi", gli appuntamenti in arrivo sotto „Eventi". Ciò che puoi vedere dipende dalla tua iscrizione.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_3', c."id", 'Che cosa sono punti, livelli e badge?', 'Per la tua attività accumuli punti, sali di livello e guadagni badge. Una classifica mostra i membri più attivi: così partecipare diventa più vivace.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_4', c."id", 'Posso scrivere agli altri membri?', 'Sì, se il creator ha attivato la chat e i messaggi diretti, puoi scambiare messaggi con gli altri membri.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_teilnehmen_5', c."id", 'Come imposto le mie notifiche?', 'Nelle impostazioni del tuo account stabilisci di cosa vuoi essere informato via e-mail e nell''app.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_ki-funktionen_0', c."id", 'Cosa può fare l''assistente IA?', 'L''assistente IA ti aiuta a scrivere post e newsletter e a raccogliere idee. Ti offre un punto di partenza che poi adatti tu: il controllo resta sempre a te.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_ki-funktionen_1', c."id", 'Cosa sono i suggerimenti IA?', 'Aera propone ai membri contenuti adatti a loro, così trovano più in fretta ciò che li interessa. Se non è attiva nessuna IA, funziona tramite una ricerca semplice e trasparente per parole chiave.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_ki-funktionen_2', c."id", 'Che cos''è il credito IA?', 'Le funzioni di IA consumano credito. Ogni community ha un credito e, se serve, puoi acquistare pacchetti aggiuntivi.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_ki-funktionen_3', c."id", 'Cosa succede quando il credito IA è esaurito?', 'In quel caso le funzioni di IA si mettono in pausa finché non ricarichi nuovo credito. Tutte le altre funzioni della tua community continuano a funzionare normalmente.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_ki-funktionen_4', c."id", 'I miei contenuti vengono usati per addestrare l''IA?', 'No. I tuoi contenuti sono tuoi. Vengono usati solo per fornirti le funzioni che utilizzi tu stesso.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_0', c."id", 'Come cambio il mio profilo o la password?', 'Nelle impostazioni del tuo account puoi modificare in qualsiasi momento nome, immagine del profilo, indirizzo e-mail e password.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_1', c."id", 'Come gestisco i miei membri?', 'Nella dashboard vedi tutti i membri della tua community. Puoi assegnare ruoli come moderatore, invitare nuovi membri o rimuovere membri.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_2', c."id", 'I miei dati sono miei?', 'Sì. La tua community, la tua lista dei membri e i tuoi contenuti sono tuoi. Puoi scaricare i tuoi dati in qualsiasi momento: non sei vincolato a nulla.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_3', c."id", 'Come scarico i miei dati?', 'Nelle impostazioni trovi l''esportazione dei dati. Così ottieni i tuoi contenuti in un formato comune, pronti da scaricare.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_4', c."id", 'Quanto sono al sicuro i miei dati?', 'Ogni community è tenuta ben separata e protetta da tutte le altre, così nessun altro può accedervi. I tuoi dati di pagamento si trovano esclusivamente presso il fornitore di pagamenti, non presso Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_5', c."id", 'Come elimino la mia community o il mio account?', 'Puoi farlo nelle impostazioni. Con l''eliminazione i contenuti collegati vengono rimossi: se serve, scarica prima i tuoi dati.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_it_konto-marke-daten_6', c."id", 'Come contatto il supporto?', 'Usa il pulsante di contatto in fondo al centro assistenza. Descrivi la tua richiesta nel modo più preciso possibile, così possiamo aiutarti rapidamente.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_it_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_erste-schritte', 'nl', 'Aan de slag', 'erste-schritte', 'Aera leren kennen, een account aanmaken en een community vinden.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_community-starten', 'nl', 'Je community starten', 'community-starten', 'In een paar minuten je eigen community onder je eigen merk opbouwen.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_mitgliedschaften-preise', 'nl', 'Lidmaatschappen & prijzen', 'mitgliedschaften-preise', 'Gratis en betaalde lidmaatschappen instellen en begrijpen.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_bezahlen-auszahlungen', 'nl', 'Betalen & uitbetalingen', 'bezahlen-auszahlungen', 'Veilig betalen, uitbetalingen aan creators, bonnen en terugbetalingen.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_inhalte-erstellen', 'nl', 'Content: berichten, cursussen, events & nieuwsbrief', 'inhalte-erstellen', 'Publiceren, lesgeven, events houden en leden rechtstreeks bereiken.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_teilnehmen', 'nl', 'Voor leden: meedoen', 'teilnehmen', 'Joinen, meedoen, leren en in contact blijven.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_ki-funktionen', 'nl', 'AI-functies', 'ki-funktionen', 'De AI-assistent, aanbevelingen en het AI-tegoed.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nl_konto-marke-daten', 'nl', 'Account, merk & gegevens', 'konto-marke-daten', 'Profiel en beveiliging, merk aanpassen, leden beheren en gegevens downloaden.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_erste-schritte_0', c."id", 'Wat is Aera?', 'Aera is een platform waarop creators hun eigen community onder hun eigen merk runnen — met lidmaatschappen, cursussen, events, nieuwsbrief en meer op één plek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_erste-schritte_1', c."id", 'Hoe maak ik een account aan?', 'Klik op „Registreren" en meld je aan met je e-mailadres en een wachtwoord.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_erste-schritte_2', c."id", 'Heb ik een account nodig om rond te kijken?', 'Veel communitypagina''s kun je ook zonder account bekijken. Zodra je wilt joinen, wilt meepraten of iets wilt kopen, heb je een gratis account nodig.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_erste-schritte_3', c."id", 'Hoe vind ik een community?', 'Via „Ontdekken" op de startpagina vind je openbare communities. Of je opent direct het adres of de link die je van een creator hebt gekregen (bijvoorbeeld name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_erste-schritte_4', c."id", 'Wat kost Aera?', 'Een account aanmaken en lid worden van een community is gratis.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_0', c."id", 'Hoe start ik mijn eigen community?', 'Kies „Community starten". Je bepaalt de naam en het adres en maakt een paar basisinstellingen. Daarna kom je direct in je dashboard terecht en kun je aan de slag.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_1', c."id", 'Wat is het dashboard?', 'Het dashboard is je centrale plek om alles te regelen. Van hieruit richt je onderdelen in, publiceer je content, beheer je leden, stel je lidmaatschappen en prijzen in, verstuur je nieuwsbrieven en zie je je belangrijkste cijfers.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_2', c."id", 'Wat zijn onderdelen?', 'Onderdelen zijn de ruimtes van je community — bijvoorbeeld een feed voor berichten, cursussen, events, een chat of een mediatheek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_3', c."id", 'Kan ik de uitstraling aanpassen aan mijn merk?', 'Ja. Je kunt logo, kleuren en indeling zo instellen dat je community aanvoelt als je eigen merk. Aera treedt bewust op de achtergrond — jij staat op de voorgrond.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_4', c."id", 'Krijg ik een eigen adres?', 'Ja. Je community krijgt een eigen internetadres (bijvoorbeeld deinname.aera.so). Een eigen wensdomein kun je ook koppelen.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_community-starten_5', c."id", 'Hoe nodig ik de eerste leden uit?', 'Deel gewoon de link naar je community — via social media, messenger of e-mail. Later bereik je je leden altijd rechtstreeks via de nieuwsbrief, helemaal zonder algoritme ertussen.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_mitgliedschaften-preise_0', c."id", 'Wat is een lidmaatschap?', 'Een lidmaatschap bepaalt wat een lid in je community mag zien en doen. Er kunnen gratis en betaalde niveaus zijn — bijvoorbeeld „Gratis", „Plus" en „Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_mitgliedschaften-preise_1', c."id", 'Hoe maak ik een betaald lidmaatschap aan?', 'In het dashboard maak je onder Lidmaatschappen een nieuw niveau aan. Je kiest de prijs en de betaalperiode (maandelijks of jaarlijks) en bepaalt welke onderdelen en content het niveau ontgrendelt.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_mitgliedschaften-preise_2', c."id", 'Hoe word ik betalend lid?', 'Kies in de community het gewenste lidmaatschap en rond de betaling af via de veilige checkout. Je toegang wordt meteen vrijgeschakeld.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_mitgliedschaften-preise_3', c."id", 'Kan ik mijn lidmaatschap wijzigen of opzeggen?', 'Ja. In je lidmaatschapsinstellingen kun je altijd wisselen of opzeggen.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_mitgliedschaften-preise_4', c."id", 'Wat gebeurt er na de aankoop met mijn toegang?', 'Betaalde onderdelen en content worden automatisch vrijgeschakeld. Loopt een lidmaatschap af, dan worden ze weer vergrendeld — je eigen berichten en gegevens blijven daarbij bewaard.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_0', c."id", 'Hoe betaal ik veilig?', 'Betalingen lopen via onze betaaldienst Stripe. Je betaalgegevens worden daar versleuteld verwerkt — Aera bewaart zelf geen kaartgegevens.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_1', c."id", 'Welke betaalmethodes kan ik gebruiken?', 'Afhankelijk van je land en apparaat kun je bijvoorbeeld creditcards en betaalkaarten en gangbare digitale betaalmethodes gebruiken. Welke opties mogelijk zijn, zie je direct bij het afrekenen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_2', c."id", 'Krijg ik een bon of factuur?', 'Ja. Na elke aankoop krijg je een bevestiging per e-mail. Je aankopen vind je bovendien altijd terug in je accountinstellingen.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_3', c."id", 'Hoe krijg ik als creator mijn inkomsten?', 'Je uitbetalingen lopen veilig via Stripe. Je vult eenmalig je uitbetalingsgegevens in, daarna worden je inkomsten automatisch aan je overgemaakt.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_4', c."id", 'Welke kosten zijn er voor creators?', 'Aera houdt bij een verkoop een kleine platformbijdrage in. Daarnaast kunnen er bij het verwerken van de betaling kosten van de betaaldienst bij komen. De rest van je inkomsten is voor jou.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_bezahlen-auszahlungen_5', c."id", 'Hoe werken terugbetalingen?', 'Een terugbetaling zet de betreffende creator in gang. Heb je vragen over een aankoop, neem dan eerst contact op met de creator van de community — of met onze support als je er niet uitkomt.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_0', c."id", 'Hoe publiceer ik een bericht?', 'Open het juiste onderdeel, kies „Nieuw bericht", voeg tekst en media toe en publiceer. Je bepaalt daarbij welke leden het bericht mogen zien.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_1', c."id", 'Hoe maak ik een cursus?', 'Maak een cursusonderdeel aan en voeg lessen of modules toe. Jij bepaalt of de cursus vrij toegankelijk is of onderdeel van een betaald lidmaatschap.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_2', c."id", 'Hoe plan ik een event?', 'In het onderdeel Events bepaal je de titel, het tijdstip en de details. Leden kunnen zich aanmelden. Events kun je gratis of betaald aanbieden.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_3', c."id", 'Hoe verstuur ik een nieuwsbrief?', 'Schrijf in het dashboard een nieuwsbrief en stuur die naar alle of naar geselecteerde leden. Zo bereik je je community rechtstreeks in hun inbox — zonder algoritme van iemand anders ertussen.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_4', c."id", 'Wat is de mediatheek?', 'De mediatheek is de centrale plek voor je video''s, audio en bestanden. Van daaruit gebruik je ze in berichten, cursussen of events.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_inhalte-erstellen_5', c."id", 'Kan ik berichten vooraf inplannen?', 'Ja. Je kunt content voor een later moment inplannen, zodat die automatisch verschijnt — handig om regelmatig actief te blijven.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_0', c."id", 'Hoe word ik lid van een community?', 'Open de community en kies „Joinen". Bij gratis communities ben je meteen lid. Bij betaalde kies je eerst een lidmaatschap.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_1', c."id", 'Hoe schrijf ik berichten en reacties?', 'In alle onderdelen waartoe je toegang hebt, kun je berichten schrijven, reageren en reacties achterlaten — net als op een sociaal netwerk, alleen zonder algoritme van iemand anders.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_2', c."id", 'Waar vind ik cursussen en events?', 'Vrijgeschakelde cursussen vind je in het onderdeel „Cursussen", aankomende afspraken onder „Events". Wat je kunt zien, hangt af van je lidmaatschap.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_3', c."id", 'Wat zijn punten, levels en badges?', 'Voor je activiteit verzamel je punten, ga je een level omhoog en verdien je badges. Een ranglijst laat de meest actieve leden zien — dat maakt meedoen levendiger.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_4', c."id", 'Kan ik andere leden een bericht sturen?', 'Ja, als de creator de chat en directe berichten heeft ingeschakeld, kun je met andere leden in contact komen.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_teilnehmen_5', c."id", 'Hoe stel ik mijn meldingen in?', 'In je accountinstellingen bepaal je waarover je per e-mail en in de app op de hoogte wilt worden gehouden.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_ki-funktionen_0', c."id", 'Wat kan de AI-assistent?', 'De AI-assistent helpt je bij het schrijven van berichten en nieuwsbrieven en bij het verzamelen van ideeën. Hij geeft je een startpunt dat jij aanpast — jij houdt altijd de controle.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_ki-funktionen_1', c."id", 'Wat zijn AI-aanbevelingen?', 'Aera stelt leden passende content voor, zodat ze sneller vinden wat hen interesseert. Is er geen AI actief, dan werkt dat via een eenvoudige, transparante zoekfunctie op trefwoorden.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_ki-funktionen_2', c."id", 'Wat is het AI-tegoed?', 'AI-functies verbruiken tegoed. Elke community heeft een tegoed, en als je meer nodig hebt, kun je extra pakketten bijkopen.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_ki-funktionen_3', c."id", 'Wat gebeurt er als het AI-tegoed op is?', 'Dan pauzeren de AI-functies totdat je nieuw tegoed bijlaadt. Alle andere functies van je community lopen gewoon door.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_ki-funktionen_4', c."id", 'Worden mijn content gebruikt om AI te trainen?', 'Nee. Je content is van jou. Het wordt alleen gebruikt om je de functies te bieden die je zelf gebruikt.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_0', c."id", 'Hoe wijzig ik mijn profiel of wachtwoord?', 'In je accountinstellingen kun je je naam, profielfoto, e-mailadres en wachtwoord altijd aanpassen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_1', c."id", 'Hoe beheer ik mijn leden?', 'In het dashboard zie je alle leden van je community. Je kunt rollen zoals moderator toewijzen, nieuwe leden uitnodigen of leden verwijderen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_2', c."id", 'Zijn mijn gegevens van mij?', 'Ja. Je community, je ledenlijst en je content zijn van jou. Je kunt je gegevens altijd downloaden — je zit nergens aan vast.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_3', c."id", 'Hoe download ik mijn gegevens?', 'In de instellingen vind je de gegevensexport. Daarmee krijg je je content in een gangbaar formaat om te downloaden.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_4', c."id", 'Hoe veilig zijn mijn gegevens?', 'Elke community is netjes van alle andere gescheiden en beveiligd, zodat niemand anders er toegang toe heeft. Je betaalgegevens liggen uitsluitend bij de betaaldienst, niet bij Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_5', c."id", 'Hoe verwijder ik mijn community of mijn account?', 'Dat kan in de instellingen. Bij het verwijderen wordt de bijbehorende content weggehaald — download vooraf je gegevens als je die wilt bewaren.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nl_konto-marke-daten_6', c."id", 'Hoe bereik ik de support?', 'Gebruik de contactknop onderaan het helpcentrum. Beschrijf je vraag zo duidelijk mogelijk, dan kunnen we je snel verder helpen.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_erste-schritte', 'nb', 'Komme i gang', 'erste-schritte', 'Bli kjent med Aera, opprett en konto og finn et fellesskap.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_community-starten', 'nb', 'Start ditt eget fellesskap', 'community-starten', 'Bygg opp ditt eget fellesskap under din merkevare på noen få minutter.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_mitgliedschaften-preise', 'nb', 'Medlemskap og priser', 'mitgliedschaften-preise', 'Sett opp og forstå gratis og betalte medlemskap.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_bezahlen-auszahlungen', 'nb', 'Betaling og utbetalinger', 'bezahlen-auszahlungen', 'Trygg betaling, utbetalinger til skapere, kvitteringer og refusjoner.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_inhalte-erstellen', 'nb', 'Innhold: innlegg, kurs, arrangementer og nyhetsbrev', 'inhalte-erstellen', 'Publiser, undervis, hold arrangementer og nå medlemmene dine direkte.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_teilnehmen', 'nb', 'For medlemmer: delta', 'teilnehmen', 'Bli med, delta, lær og hold kontakten.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_ki-funktionen', 'nb', 'KI-funksjoner', 'ki-funktionen', 'KI-assistenten, anbefalinger og KI-saldoen.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_nb_konto-marke-daten', 'nb', 'Konto, merkevare og data', 'konto-marke-daten', 'Profil og sikkerhet, tilpasse merkevaren, administrere medlemmer og laste ned data.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_erste-schritte_0', c."id", 'Hva er Aera?', 'Aera er en plattform der skapere driver sitt eget fellesskap under sin egen merkevare — med medlemskap, kurs, arrangementer, nyhetsbrev og mye mer, samlet på ett sted.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_erste-schritte_1', c."id", 'Hvordan oppretter jeg en konto?', 'Klikk på «Registrer deg» og logg inn med e-postadressen din og et passord.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_erste-schritte_2', c."id", 'Trenger jeg en konto for å se meg om?', 'Mange fellesskapssider kan du se på også uten konto. Så snart du vil bli med, skrive innlegg eller kjøpe noe, trenger du en gratis konto.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_erste-schritte_3', c."id", 'Hvordan finner jeg et fellesskap?', 'Under «Oppdag» på forsiden finner du åpne fellesskap. Eller du åpner direkte adressen eller lenken en skaper har gitt deg (for eksempel name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_erste-schritte_4', c."id", 'Hva koster Aera?', 'Å opprette en konto og bli med i et fellesskap er gratis.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_0', c."id", 'Hvordan starter jeg mitt eget fellesskap?', 'Velg «Start et fellesskap». Du bestemmer navn og adresse og gjør noen få grunninnstillinger. Deretter havner du rett i oversikten din og kan sette i gang.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_1', c."id", 'Hva er oversikten?', 'Oversikten er ditt kontrollsenter. Herfra setter du opp rom, publiserer innhold, administrerer medlemmer, bestemmer medlemskap og priser, sender nyhetsbrev og ser de viktigste tallene dine.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_2', c."id", 'Hva er rom?', 'Rom er de ulike stedene i fellesskapet ditt — for eksempel en feed for innlegg, kurs, arrangementer, en chat eller et mediebibliotek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_3', c."id", 'Kan jeg tilpasse utseendet til min merkevare?', 'Ja. Du kan stille inn logo, farger og layout slik at fellesskapet ditt fremstår som din egen merkevare. Aera trer bevisst i bakgrunnen — det er du som står i sentrum.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_4', c."id", 'Får jeg en egen adresse?', 'Ja. Fellesskapet ditt får sin egen nettadresse (for eksempel dittnavn.aera.so). Du kan også koble til ditt eget ønskede domene.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_community-starten_5', c."id", 'Hvordan inviterer jeg de første medlemmene?', 'Del rett og slett lenken til fellesskapet ditt — via sosiale medier, meldinger eller e-post. Senere når du medlemmene dine når som helst direkte gjennom nyhetsbrevet, helt uten en algoritme imellom.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_mitgliedschaften-preise_0', c."id", 'Hva er et medlemskap?', 'Et medlemskap bestemmer hva et medlem får se og gjøre i fellesskapet ditt. Det kan finnes gratis og betalte nivåer — for eksempel «Gratis», «Pluss» og «Premium».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_mitgliedschaften-preise_1', c."id", 'Hvordan oppretter jeg et betalt medlemskap?', 'I oversikten oppretter du et nytt nivå under Medlemskap. Du velger prisen og betalingen (månedlig eller årlig) og bestemmer hvilke rom og hvilket innhold nivået låser opp.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_mitgliedschaften-preise_2', c."id", 'Hvordan blir jeg betalende medlem?', 'Velg det ønskede medlemskapet i fellesskapet og fullfør betalingen via den trygge kassen. Tilgangen din låses opp med det samme.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_mitgliedschaften-preise_3', c."id", 'Kan jeg endre eller si opp medlemskapet mitt?', 'Ja. I medlemskapsinnstillingene dine kan du bytte eller si opp når som helst.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_mitgliedschaften-preise_4', c."id", 'Hva skjer med tilgangen min etter kjøpet?', 'Betalte rom og betalt innhold låses opp automatisk. Når et medlemskap går ut, låses de igjen — men dine egne innlegg og data blir tatt vare på.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_0', c."id", 'Hvordan betaler jeg trygt?', 'Betalinger går gjennom betalingsleverandøren vår, Stripe. Betalingsopplysningene dine behandles kryptert der — Aera lagrer selv ingen kortopplysninger.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_1', c."id", 'Hvilke betalingsmåter kan jeg bruke?', 'Avhengig av land og enhet kan du for eksempel bruke kreditt- og debetkort samt vanlige digitale betalingsmåter. Hvilke muligheter som finnes, ser du rett i kassen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_2', c."id", 'Får jeg en kvittering eller en faktura?', 'Ja. Etter hvert kjøp får du en bekreftelse på e-post. Kjøpene dine finner du dessuten når som helst i kontoinnstillingene dine.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_3', c."id", 'Hvordan får jeg inntektene mine som skaper?', 'Utbetalingene dine går trygt gjennom Stripe. Du legger inn utbetalingsopplysningene dine én gang, deretter overføres inntektene dine automatisk til deg.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_4', c."id", 'Hvilke avgifter påløper for skapere?', 'Aera beholder en liten plattformavgift ved salg. I tillegg kan det påløpe avgifter fra betalingsleverandøren ved gjennomføring av betalingen. Resten av inntektene dine er dine.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_bezahlen-auszahlungen_5', c."id", 'Hvordan fungerer refusjoner?', 'En refusjon settes i gang av den aktuelle skaperen. Har du spørsmål om et kjøp, ta først kontakt med skaperen av fellesskapet — eller med kundestøtten vår hvis du ikke kommer videre.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_0', c."id", 'Hvordan publiserer jeg et innlegg?', 'Åpne det riktige rommet, velg «Nytt innlegg», legg til tekst og medier og publiser. Underveis bestemmer du hvilke medlemmer som får se innlegget.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_1', c."id", 'Hvordan lager jeg et kurs?', 'Opprett et kursrom og legg til leksjoner eller moduler. Du bestemmer om kurset er fritt tilgjengelig eller en del av et betalt medlemskap.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_2', c."id", 'Hvordan planlegger jeg et arrangement?', 'I arrangementsrommet bestemmer du tittel, tidspunkt og detaljer. Medlemmer kan melde seg på. Arrangementer kan du tilby gratis eller mot betaling.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_3', c."id", 'Hvordan sender jeg et nyhetsbrev?', 'Skriv et nyhetsbrev i oversikten og send det til alle eller til utvalgte medlemmer. Slik når du fellesskapet ditt direkte i innboksen deres — uten en fremmed algoritme imellom.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_4', c."id", 'Hva er mediebiblioteket?', 'Mediebiblioteket er det sentrale stedet for videoene, lydfilene og filene dine. Derfra legger du dem inn i innlegg, kurs eller arrangementer.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_inhalte-erstellen_5', c."id", 'Kan jeg planlegge innlegg på forhånd?', 'Ja. Du kan planlegge innhold til et senere tidspunkt, slik at det dukker opp automatisk — praktisk for å holde deg jevnlig aktiv.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_0', c."id", 'Hvordan blir jeg med i et fellesskap?', 'Åpne fellesskapet og velg «Bli med». I gratis fellesskap er du med med det samme. I betalte velger du først et medlemskap.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_1', c."id", 'Hvordan skriver jeg innlegg og kommentarer?', 'I alle rom du har tilgang til, kan du skrive innlegg, kommentere og reagere — omtrent som i et sosialt nettverk, bare uten en fremmed algoritme.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_2', c."id", 'Hvor finner jeg kurs og arrangementer?', 'Kurs du har fått tilgang til, finner du i rommet «Kurs», og kommende datoer under «Arrangementer». Hva du får se, avhenger av medlemskapet ditt.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_3', c."id", 'Hva er poeng, nivåer og merker?', 'For aktiviteten din samler du poeng, går opp i nivå og tjener merker. En resultatliste viser spesielt aktive medlemmer — det gjør det mer levende å delta.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_4', c."id", 'Kan jeg skrive til andre medlemmer?', 'Ja, så lenge skaperen har slått på chat og direktemeldinger, kan du utveksle meldinger med andre medlemmer.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_teilnehmen_5', c."id", 'Hvordan stiller jeg inn varslene mine?', 'I kontoinnstillingene dine bestemmer du hva du vil bli informert om på e-post og i appen.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_ki-funktionen_0', c."id", 'Hva kan KI-assistenten gjøre?', 'KI-assistenten hjelper deg med å skrive innlegg og nyhetsbrev og med å samle ideer. Den gir deg et utgangspunkt som du tilpasser — kontrollen har alltid du.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_ki-funktionen_1', c."id", 'Hva er KI-anbefalinger?', 'Aera foreslår passende innhold for medlemmene, slik at de raskere finner det de er interessert i. Er ingen KI aktiv, fungerer det via et enkelt og oversiktlig søk etter stikkord.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_ki-funktionen_2', c."id", 'Hva er KI-saldoen?', 'KI-funksjoner bruker av saldoen. Hvert fellesskap har en saldo, og ved behov kan du kjøpe flere pakker.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_ki-funktionen_3', c."id", 'Hva skjer når KI-saldoen er brukt opp?', 'Da settes KI-funksjonene på pause til du fyller på ny saldo. Alle de andre funksjonene i fellesskapet ditt fortsetter helt som normalt.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_ki-funktionen_4', c."id", 'Blir innholdet mitt brukt til KI-trening?', 'Nei. Innholdet ditt er ditt. Det brukes bare til å gi deg de funksjonene du selv bruker.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_0', c."id", 'Hvordan endrer jeg profilen eller passordet mitt?', 'I kontoinnstillingene dine kan du når som helst endre navn, profilbilde, e-postadresse og passord.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_1', c."id", 'Hvordan administrerer jeg medlemmene mine?', 'I oversikten ser du alle medlemmene i fellesskapet ditt. Du kan gi roller som moderator, invitere nye medlemmer eller fjerne medlemmer.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_2', c."id", 'Er dataene mine mine?', 'Ja. Fellesskapet ditt, medlemslisten din og innholdet ditt er ditt. Du kan laste ned dataene dine når som helst — du er ikke bundet til noe.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_3', c."id", 'Hvordan laster jeg ned dataene mine?', 'I innstillingene finner du dataeksporten. Med den får du innholdet ditt i et vanlig format klart til nedlasting.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_4', c."id", 'Hvor trygge er dataene mine?', 'Hvert fellesskap er ryddig atskilt fra alle andre og beskyttet, slik at ingen andre har tilgang. Betalingsopplysningene dine ligger kun hos betalingsleverandøren, ikke hos Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_5', c."id", 'Hvordan sletter jeg fellesskapet eller kontoen min?', 'Det gjør du i innstillingene. Ved sletting fjernes det tilhørende innholdet — last derfor ned dataene dine på forhånd om du trenger dem.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_nb_konto-marke-daten_6', c."id", 'Hvordan når jeg kundestøtten?', 'Bruk kontaktknappen nederst i hjelpesenteret. Beskriv saken din så nøyaktig som mulig, så kan vi hjelpe deg raskt.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_nb_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_erste-schritte', 'pl', 'Pierwsze kroki', 'erste-schritte', 'Poznaj Aera, załóż konto i znajdź społeczność.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_community-starten', 'pl', 'Załóż swoją społeczność', 'community-starten', 'Zbuduj własną społeczność pod swoją marką w kilka minut.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_mitgliedschaften-preise', 'pl', 'Członkostwa i ceny', 'mitgliedschaften-preise', 'Twórz i poznawaj bezpłatne oraz płatne członkostwa.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_bezahlen-auszahlungen', 'pl', 'Płatności i wypłaty', 'bezahlen-auszahlungen', 'Bezpieczne płatności, wypłaty dla twórców, potwierdzenia i zwroty.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_inhalte-erstellen', 'pl', 'Treści: wpisy, kursy, wydarzenia i newsletter', 'inhalte-erstellen', 'Publikuj, ucz, organizuj wydarzenia i docieraj bezpośrednio do członków.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_teilnehmen', 'pl', 'Dla członków: udział', 'teilnehmen', 'Dołączaj, bierz udział, ucz się i pozostawaj w kontakcie.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_ki-funktionen', 'pl', 'Funkcje AI', 'ki-funktionen', 'Asystent AI, rekomendacje i środki AI.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pl_konto-marke-daten', 'pl', 'Konto, marka i dane', 'konto-marke-daten', 'Profil i bezpieczeństwo, dopasowanie marki, zarządzanie członkami i pobieranie danych.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_erste-schritte_0', c."id", 'Czym jest Aera?', 'Aera to platforma, na której twórcy prowadzą własną społeczność pod własną marką — z członkostwami, kursami, wydarzeniami, newsletterem i wieloma innymi rzeczami w jednym miejscu.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_erste-schritte_1', c."id", 'Jak założyć konto?', 'Kliknij „Zarejestruj się" i utwórz konto, podając adres e-mail i hasło.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_erste-schritte_2', c."id", 'Czy potrzebuję konta, żeby się rozejrzeć?', 'Wiele stron społeczności możesz przeglądać także bez konta. Gdy tylko zechcesz dołączyć, coś napisać lub kupić, potrzebujesz bezpłatnego konta.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_erste-schritte_3', c."id", 'Jak znaleźć społeczność?', 'W sekcji „Odkrywaj" na stronie głównej znajdziesz publiczne społeczności. Możesz też otworzyć bezpośrednio adres lub link, który przekazał ci twórca (na przykład name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_erste-schritte_4', c."id", 'Ile kosztuje Aera?', 'Założenie konta i dołączenie do społeczności jest bezpłatne.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_0', c."id", 'Jak założyć własną społeczność?', 'Wybierz „Załóż społeczność". Ustalasz nazwę i adres oraz wybierasz kilka podstawowych ustawień. Potem od razu trafiasz do swojego panelu i możesz zaczynać.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_1', c."id", 'Czym jest panel?', 'Panel to twoje centrum sterowania. Stąd tworzysz przestrzenie, publikujesz treści, zarządzasz członkami, ustalasz członkostwa i ceny, wysyłasz newslettery oraz widzisz swoje najważniejsze dane.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_2', c."id", 'Czym są przestrzenie?', 'Przestrzenie to pomieszczenia twojej społeczności — na przykład tablica z wpisami, kursy, wydarzenia, czat czy biblioteka multimediów.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_3', c."id", 'Czy mogę dopasować wygląd do mojej marki?', 'Tak. Możesz tak ustawić logo, kolory i układ, aby twoja społeczność wyglądała jak twoja własna marka. Aera świadomie usuwa się w cień — na pierwszym planie jesteś ty.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_4', c."id", 'Czy dostanę własny adres?', 'Tak. Twoja społeczność otrzymuje własny adres internetowy (na przykład deinname.aera.so). Można też podłączyć własną, wybraną domenę.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_community-starten_5', c."id", 'Jak zaprosić pierwszych członków?', 'Po prostu udostępnij link do swojej społeczności — w mediach społecznościowych, komunikatorze lub e-mailu. Później w każdej chwili dotrzesz do swoich członków bezpośrednio przez newsletter, całkowicie bez żadnego algorytmu pośrodku.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_mitgliedschaften-preise_0', c."id", 'Czym jest członkostwo?', 'Członkostwo określa, co członek może widzieć i robić w twojej społeczności. Mogą istnieć poziomy bezpłatne i płatne — na przykład „Darmowy", „Plus" i „Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_mitgliedschaften-preise_1', c."id", 'Jak utworzyć płatne członkostwo?', 'W panelu, w sekcji Członkostwa, tworzysz nowy poziom. Wybierasz cenę i sposób rozliczania (miesięczny lub roczny) oraz określasz, które przestrzenie i treści odblokowuje dany poziom.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_mitgliedschaften-preise_2', c."id", 'Jak zostać płacącym członkiem?', 'Wybierz w społeczności odpowiednie członkostwo i sfinalizuj płatność w bezpiecznej kasie. Twój dostęp odblokowuje się od razu.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_mitgliedschaften-preise_3', c."id", 'Czy mogę zmienić lub anulować swoje członkostwo?', 'Tak. W ustawieniach członkostwa możesz je w każdej chwili zmienić lub anulować.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_mitgliedschaften-preise_4', c."id", 'Co dzieje się z moim dostępem po zakupie?', 'Płatne przestrzenie i treści odblokowują się automatycznie. Gdy członkostwo wygaśnie, zostają ponownie zablokowane — a twoje własne wpisy i dane pozostają zachowane.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_0', c."id", 'Jak bezpiecznie płacić?', 'Płatności obsługuje nasz dostawca płatności Stripe. Twoje dane płatnicze są tam przetwarzane w zaszyfrowanej formie — Aera samo nie przechowuje danych kart.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_1', c."id", 'Jakich metod płatności mogę używać?', 'W zależności od kraju i urządzenia dostępne są na przykład karty kredytowe i debetowe oraz popularne cyfrowe metody płatności. Które opcje są możliwe, zobaczysz bezpośrednio w kasie.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_2', c."id", 'Czy dostanę potwierdzenie lub fakturę?', 'Tak. Po każdym zakupie otrzymasz potwierdzenie e-mailem. Swoje zakupy znajdziesz też w każdej chwili w ustawieniach konta.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_3', c."id", 'Jak jako twórca otrzymuję swoje przychody?', 'Twoje wypłaty przebiegają bezpiecznie przez Stripe. Jednorazowo podajesz swoje dane do wypłat, a potem twoje przychody są automatycznie przelewane na twoje konto.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_4', c."id", 'Jakie opłaty ponoszą twórcy?', 'Przy sprzedaży Aera pobiera niewielką opłatę platformy. Dodatkowo przy obsłudze płatności mogą pojawić się opłaty dostawcy płatności. Reszta twoich przychodów należy do ciebie.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_bezahlen-auszahlungen_5', c."id", 'Jak działają zwroty?', 'Zwrot inicjuje dany twórca. W razie pytań dotyczących zakupu zwróć się najpierw do twórcy społeczności — albo do naszego wsparcia, jeśli nie możesz sobie poradzić.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_0', c."id", 'Jak opublikować wpis?', 'Otwórz odpowiednią przestrzeń, wybierz „Nowy wpis", dodaj tekst i multimedia, a następnie opublikuj. Przy tym ustalasz, którzy członkowie mogą zobaczyć wpis.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_1', c."id", 'Jak utworzyć kurs?', 'Utwórz przestrzeń kursu i dodaj lekcje lub moduły. Decydujesz, czy kurs jest dostępny bezpłatnie, czy stanowi część płatnego członkostwa.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_2', c."id", 'Jak zaplanować wydarzenie?', 'W przestrzeni wydarzeń ustalasz tytuł, termin i szczegóły. Członkowie mogą potwierdzić udział. Wydarzenia możesz oferować bezpłatnie lub odpłatnie.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_3', c."id", 'Jak wysłać newsletter?', 'Napisz newsletter w panelu i wyślij go do wszystkich lub do wybranych członków. W ten sposób docierasz do swojej społeczności bezpośrednio do jej skrzynki — bez obcego algorytmu pośrodku.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_4', c."id", 'Czym jest biblioteka multimediów?', 'Biblioteka multimediów to centralne miejsce na twoje filmy, nagrania audio i pliki. Stamtąd wstawiasz je do wpisów, kursów lub wydarzeń.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_inhalte-erstellen_5', c."id", 'Czy mogę planować wpisy z wyprzedzeniem?', 'Tak. Możesz zaplanować treści na późniejszy termin, tak aby pojawiły się automatycznie — to wygodny sposób, aby regularnie pozostawać aktywnym.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_0', c."id", 'Jak dołączyć do społeczności?', 'Otwórz społeczność i wybierz „Dołącz". W bezpłatnych społecznościach jesteś od razu w środku. W płatnych najpierw wybierasz członkostwo.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_1', c."id", 'Jak pisać wpisy i komentarze?', 'We wszystkich przestrzeniach, do których masz dostęp, możesz pisać wpisy, komentować i reagować — podobnie jak w sieci społecznościowej, tylko bez obcego algorytmu.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_2', c."id", 'Gdzie znajdę kursy i wydarzenia?', 'Odblokowane kursy znajdziesz w przestrzeni „Kursy", a nadchodzące terminy w „Wydarzenia". To, co możesz zobaczyć, zależy od twojego członkostwa.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_3', c."id", 'Czym są punkty, poziomy i odznaki?', 'Za swoją aktywność zbierasz punkty, awansujesz na kolejne poziomy i zdobywasz odznaki. Ranking pokazuje szczególnie aktywnych członków — dzięki temu udział staje się żywszy.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_4', c."id", 'Czy mogę pisać do innych członków?', 'Tak, o ile twórca włączył czat i wiadomości bezpośrednie, możesz kontaktować się z innymi członkami.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_teilnehmen_5', c."id", 'Jak ustawić swoje powiadomienia?', 'W ustawieniach konta określasz, o czym chcesz być informowany e-mailem i w aplikacji.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_ki-funktionen_0', c."id", 'Co potrafi asystent AI?', 'Asystent AI pomaga ci w pisaniu wpisów i newsletterów oraz w zbieraniu pomysłów. Daje punkt wyjścia, który dopasowujesz — kontrolę zawsze zachowujesz ty.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_ki-funktionen_1', c."id", 'Czym są rekomendacje AI?', 'Aera proponuje członkom pasujące treści, aby szybciej znajdowali to, co ich interesuje. Gdy AI nie jest aktywne, działa to poprzez proste, przejrzyste wyszukiwanie według słów kluczowych.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_ki-funktionen_2', c."id", 'Czym są środki AI?', 'Funkcje AI zużywają środki. Każda społeczność ma swoją pulę środków, a w razie potrzeby możesz dokupić dodatkowe pakiety.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_ki-funktionen_3', c."id", 'Co się dzieje, gdy środki AI się wyczerpią?', 'Wtedy funkcje AI zostają wstrzymane, dopóki nie doładujesz nowych środków. Wszystkie pozostałe funkcje twojej społeczności działają zupełnie normalnie.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_ki-funktionen_4', c."id", 'Czy moje treści są wykorzystywane do trenowania AI?', 'Nie. Twoje treści należą do ciebie. Są wykorzystywane wyłącznie po to, aby udostępniać ci funkcje, z których sam korzystasz.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_0', c."id", 'Jak zmienić swój profil lub hasło?', 'W ustawieniach konta możesz w każdej chwili zmienić imię, zdjęcie profilowe, adres e-mail i hasło.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_1', c."id", 'Jak zarządzać swoimi członkami?', 'W panelu widzisz wszystkich członków swojej społeczności. Możesz przydzielać role, takie jak moderator, zapraszać nowych członków lub usuwać członków.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_2', c."id", 'Czy moje dane należą do mnie?', 'Tak. Twoja społeczność, lista twoich członków i twoje treści należą do ciebie. Możesz w każdej chwili pobrać swoje dane — nic cię nie wiąże.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_3', c."id", 'Jak pobrać swoje dane?', 'W ustawieniach znajdziesz eksport danych. Dzięki niemu otrzymasz swoje treści do pobrania w popularnym formacie.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_4', c."id", 'Jak bezpieczne są moje dane?', 'Każda społeczność jest starannie oddzielona od wszystkich innych i chroniona, tak aby nikt inny nie miał do niej dostępu. Twoje dane płatnicze znajdują się wyłącznie u dostawcy płatności, a nie w Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_5', c."id", 'Jak usunąć swoją społeczność lub konto?', 'Zrobisz to w ustawieniach. Podczas usuwania powiązane treści zostają skasowane — w razie potrzeby wcześniej pobierz swoje dane.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pl_konto-marke-daten_6', c."id", 'Jak skontaktować się ze wsparciem?', 'Skorzystaj z przycisku kontaktu na dole centrum pomocy. Opisz swoją sprawę jak najdokładniej, wtedy szybko będziemy mogli ci pomóc.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pl_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_erste-schritte', 'pt-BR', 'Primeiros passos', 'erste-schritte', 'Conheça a Aera, crie uma conta e encontre uma comunidade.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_community-starten', 'pt-BR', 'Crie a sua comunidade', 'community-starten', 'Monte a sua própria comunidade com a sua marca em poucos minutos.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_mitgliedschaften-preise', 'pt-BR', 'Assinaturas e preços', 'mitgliedschaften-preise', 'Configure e entenda as assinaturas gratuitas e pagas.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_bezahlen-auszahlungen', 'pt-BR', 'Pagamentos e repasses', 'bezahlen-auszahlungen', 'Pagamento seguro, repasses para criadores, comprovantes e reembolsos.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_inhalte-erstellen', 'pt-BR', 'Conteúdos: publicações, cursos, eventos e newsletter', 'inhalte-erstellen', 'Publique, ensine, realize eventos e fale diretamente com os membros.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_teilnehmen', 'pt-BR', 'Para membros: participar', 'teilnehmen', 'Entre, participe, aprenda e mantenha o contato.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_ki-funktionen', 'pt-BR', 'Recursos de IA', 'ki-funktionen', 'O assistente de IA, as recomendações e os créditos de IA.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_pt-BR_konto-marke-daten', 'pt-BR', 'Conta, marca e dados', 'konto-marke-daten', 'Perfil e segurança, personalização da marca, gestão de membros e download dos dados.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_erste-schritte_0', c."id", 'O que é a Aera?', 'A Aera é uma plataforma onde criadores mantêm a própria comunidade com a sua própria marca — com assinaturas, cursos, eventos, newsletter e muito mais em um só lugar.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_erste-schritte_1', c."id", 'Como faço para criar uma conta?', 'Clique em "Cadastrar" e cadastre-se com o seu e-mail e uma senha.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_erste-schritte_2', c."id", 'Preciso de uma conta para dar uma olhada?', 'Você pode ver muitas páginas de comunidades mesmo sem ter uma conta. Assim que quiser entrar, participar ou comprar algo, você vai precisar de uma conta gratuita.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_erste-schritte_3', c."id", 'Como encontro uma comunidade?', 'Em "Descobrir", na página inicial, você encontra comunidades públicas. Ou pode abrir diretamente o endereço ou o link que um criador tenha te passado (por exemplo, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_erste-schritte_4', c."id", 'Quanto custa a Aera?', 'Criar uma conta e entrar em uma comunidade é gratuito.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_0', c."id", 'Como crio a minha própria comunidade?', 'Selecione "Criar comunidade". Você define o nome e o endereço e faz alguns ajustes básicos. Depois, você vai direto para o seu painel e já pode começar.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_1', c."id", 'O que é o painel?', 'O painel é a sua central de comando. É a partir dele que você cria espaços, publica conteúdos, gerencia os membros, define assinaturas e preços, envia newsletters e vê os seus números mais importantes.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_2', c."id", 'O que são os espaços?', 'Os espaços são os ambientes da sua comunidade — por exemplo, um feed para publicações, cursos, eventos, um chat ou uma midiateca.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_3', c."id", 'Posso ajustar a aparência à minha marca?', 'Sim. Você pode configurar o logo, as cores e o layout para que a sua comunidade tenha a cara da sua própria marca. A Aera fica de propósito em segundo plano — quem está em destaque é você.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_4', c."id", 'Ganho um endereço próprio?', 'Sim. A sua comunidade recebe um endereço próprio na internet (por exemplo, deinname.aera.so). Também é possível conectar um domínio próprio da sua escolha.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_community-starten_5', c."id", 'Como convido os primeiros membros?', 'É só compartilhar o link da sua comunidade — nas redes sociais, em apps de mensagem ou por e-mail. Depois, você fala com os seus membros a qualquer momento diretamente pela newsletter, sem nenhum algoritmo no meio do caminho.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_mitgliedschaften-preise_0', c."id", 'O que é uma assinatura?', 'Uma assinatura define o que um membro pode ver e fazer na sua comunidade. Pode haver níveis gratuitos e pagos — por exemplo, "Gratuito", "Plus" e "Premium".', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_mitgliedschaften-preise_1', c."id", 'Como crio uma assinatura paga?', 'No painel, você cria um novo nível em Assinaturas. Você escolhe o preço e a forma de cobrança (mensal ou anual) e define quais espaços e conteúdos aquele nível libera.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_mitgliedschaften-preise_2', c."id", 'Como me torno membro pagante?', 'Na comunidade, escolha a assinatura que quiser e conclua o pagamento pelo checkout seguro. O seu acesso é liberado na hora.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_mitgliedschaften-preise_3', c."id", 'Posso mudar ou cancelar a minha assinatura?', 'Sim. Nas configurações da sua assinatura, você pode trocar ou cancelar quando quiser.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_mitgliedschaften-preise_4', c."id", 'O que acontece com o meu acesso depois da compra?', 'Os espaços e conteúdos pagos são liberados automaticamente. Quando uma assinatura termina, eles voltam a ficar bloqueados — mas as suas próprias publicações e dados são mantidos.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_0', c."id", 'Como pago com segurança?', 'Os pagamentos são processados pela Stripe, o nosso provedor de pagamentos. Os seus dados de pagamento são tratados lá de forma criptografada — a própria Aera não guarda os dados do seu cartão.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_1', c."id", 'Quais formas de pagamento posso usar?', 'Dependendo do país e do dispositivo, você tem à disposição, por exemplo, cartões de crédito e débito, além das formas de pagamento digitais mais comuns. Você vê quais opções estão disponíveis na hora de finalizar a compra.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_2', c."id", 'Recebo um comprovante ou uma nota fiscal?', 'Sim. Depois de cada compra, você recebe uma confirmação por e-mail. Além disso, você encontra as suas compras a qualquer momento nas configurações da sua conta.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_3', c."id", 'Como recebo os meus ganhos como criador?', 'Os seus repasses são feitos com segurança pela Stripe. Você cadastra os seus dados de repasse uma única vez e, depois disso, os seus ganhos são transferidos automaticamente para você.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_4', c."id", 'Quais taxas os criadores pagam?', 'A Aera fica com uma pequena taxa da plataforma em cada venda. Além disso, podem incidir taxas do provedor de pagamentos no processamento. O restante dos seus ganhos é seu.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_bezahlen-auszahlungen_5', c."id", 'Como funcionam os reembolsos?', 'O reembolso é iniciado pelo próprio criador. Se tiver dúvidas sobre uma compra, fale primeiro com o criador da comunidade — ou com o nosso suporte, se você não conseguir resolver.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_0', c."id", 'Como faço uma publicação?', 'Abra o espaço certo, selecione "Nova publicação", adicione texto e mídia e publique. Nesse momento, você define quais membros podem ver a publicação.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_1', c."id", 'Como crio um curso?', 'Crie um espaço de curso e adicione aulas ou módulos. Você decide se o curso tem acesso livre ou se faz parte de uma assinatura paga.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_2', c."id", 'Como organizo um evento?', 'No espaço de eventos, você define o título, a data e o horário e os detalhes. Os membros podem confirmar presença. Você pode oferecer eventos de forma gratuita ou paga.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_3', c."id", 'Como envio uma newsletter?', 'Escreva uma newsletter no painel e envie para todos os membros ou apenas para alguns. Assim você fala com a sua comunidade diretamente na caixa de entrada — sem nenhum algoritmo de terceiros no meio do caminho.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_4', c."id", 'O que é a midiateca?', 'A midiateca é o lugar central para os seus vídeos, áudios e arquivos. A partir dela, você insere esses conteúdos em publicações, cursos ou eventos.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_inhalte-erstellen_5', c."id", 'Posso agendar publicações com antecedência?', 'Sim. Você pode agendar conteúdos para um momento posterior, de modo que apareçam automaticamente — prático para se manter ativo com regularidade.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_0', c."id", 'Como entro em uma comunidade?', 'Abra a comunidade e selecione "Entrar". Em comunidades gratuitas, você já entra na hora. Nas pagas, você escolhe primeiro uma assinatura.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_1', c."id", 'Como escrevo publicações e comentários?', 'Em todos os espaços a que você tem acesso, dá para escrever publicações, comentar e reagir — parecido com uma rede social, só que sem algoritmo de terceiros.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_2', c."id", 'Onde encontro cursos e eventos?', 'Os cursos liberados ficam no espaço "Cursos", e as próximas datas em "Eventos". O que você consegue ver depende da sua assinatura.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_3', c."id", 'O que são pontos, níveis e distintivos?', 'Pela sua atividade, você acumula pontos, sobe de nível e conquista distintivos. Um ranking mostra os membros mais ativos — o que deixa a participação mais animada.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_4', c."id", 'Posso enviar mensagem para outros membros?', 'Sim. Desde que o criador tenha ativado o chat e as mensagens diretas, você pode conversar com outros membros.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_teilnehmen_5', c."id", 'Como configuro as minhas notificações?', 'Nas configurações da sua conta, você define sobre o que quer ser avisado por e-mail e no aplicativo.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_ki-funktionen_0', c."id", 'O que o assistente de IA pode fazer?', 'O assistente de IA ajuda você a escrever publicações, newsletters e a reunir ideias. Ele oferece um ponto de partida que você ajusta — o controle é sempre seu.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_ki-funktionen_1', c."id", 'O que são as recomendações de IA?', 'A Aera sugere aos membros conteúdos que combinam com eles, para que encontrem mais rápido o que interessa. Quando não há IA ativa, isso funciona por meio de uma busca simples e transparente por palavras-chave.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_ki-funktionen_2', c."id", 'O que são os créditos de IA?', 'Os recursos de IA consomem créditos. Cada comunidade tem um saldo de créditos e, se precisar, você pode comprar pacotes adicionais.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_ki-funktionen_3', c."id", 'O que acontece quando os créditos de IA acabam?', 'Nesse caso, os recursos de IA ficam pausados até você recarregar os créditos. Todos os outros recursos da sua comunidade continuam funcionando normalmente.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_ki-funktionen_4', c."id", 'Os meus conteúdos são usados para treinar IA?', 'Não. Os seus conteúdos são seus. Eles são usados apenas para oferecer a você os recursos que você mesmo utiliza.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_0', c."id", 'Como altero o meu perfil ou a minha senha?', 'Nas configurações da sua conta, você pode alterar o nome, a foto de perfil, o e-mail e a senha quando quiser.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_1', c."id", 'Como gerencio os meus membros?', 'No painel, você vê todos os membros da sua comunidade. Você pode atribuir funções como moderador, convidar novos membros ou remover membros.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_2', c."id", 'Os meus dados são meus?', 'Sim. A sua comunidade, a sua lista de membros e os seus conteúdos são seus. Você pode baixar os seus dados quando quiser — você não fica preso a nada.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_3', c."id", 'Como baixo os meus dados?', 'Nas configurações, você encontra a exportação de dados. Com ela, você recebe os seus conteúdos em um formato comum para baixar.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_4', c."id", 'Quão seguros estão os meus dados?', 'Cada comunidade fica totalmente separada e protegida de todas as outras, para que mais ninguém tenha acesso. Os seus dados de pagamento ficam exclusivamente com o provedor de pagamentos, e não com a Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_5', c."id", 'Como excluo a minha comunidade ou a minha conta?', 'Isso é feito nas configurações. Ao excluir, os conteúdos relacionados são removidos — se precisar, baixe os seus dados antes.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_pt-BR_konto-marke-daten_6', c."id", 'Como falo com o suporte?', 'Use o botão de contato no final da Central de Ajuda. Descreva o seu caso com o máximo de detalhes possível, assim conseguimos te ajudar mais rápido.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_pt-BR_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_erste-schritte', 'sv', 'Kom igång', 'erste-schritte', 'Lär känna Aera, skapa ett konto och hitta en community.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_community-starten', 'sv', 'Starta din community', 'community-starten', 'Bygg upp din egen community under ditt varumärke på bara några minuter.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_mitgliedschaften-preise', 'sv', 'Medlemskap och priser', 'mitgliedschaften-preise', 'Skapa och förstå kostnadsfria och betalda medlemskap.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_bezahlen-auszahlungen', 'sv', 'Betalning och utbetalningar', 'bezahlen-auszahlungen', 'Säker betalning, utbetalningar till kreatörer, kvitton och återbetalningar.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_inhalte-erstellen', 'sv', 'Innehåll: inlägg, kurser, event och nyhetsbrev', 'inhalte-erstellen', 'Publicera, undervisa, hålla event och nå dina medlemmar direkt.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_teilnehmen', 'sv', 'För medlemmar: att delta', 'teilnehmen', 'Gå med, delta, lär dig och håll kontakten.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_ki-funktionen', 'sv', 'AI-funktioner', 'ki-funktionen', 'AI-assistenten, rekommendationer och AI-saldot.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_sv_konto-marke-daten', 'sv', 'Konto, varumärke och data', 'konto-marke-daten', 'Profil och säkerhet, anpassa varumärket, hantera medlemmar och ladda ner data.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_erste-schritte_0', c."id", 'Vad är Aera?', 'Aera är en plattform där kreatörer driver sin egen community under sitt eget varumärke – med medlemskap, kurser, event, nyhetsbrev och mycket mer på ett och samma ställe.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_erste-schritte_1', c."id", 'Hur skapar jag ett konto?', 'Klicka på ”Registrera dig” och logga in med din e-postadress och ett lösenord.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_erste-schritte_2', c."id", 'Behöver jag ett konto för att titta runt?', 'Många community-sidor kan du titta på även utan konto. Så snart du vill gå med, skriva inlägg eller köpa något behöver du ett kostnadsfritt konto.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_erste-schritte_3', c."id", 'Hur hittar jag en community?', 'Via ”Upptäck” på startsidan hittar du öppna communityn. Eller så öppnar du direkt adressen eller länken som en kreatör har gett dig (till exempel name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_erste-schritte_4', c."id", 'Vad kostar Aera?', 'Att skapa ett konto och gå med i en community är kostnadsfritt.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_0', c."id", 'Hur startar jag min egen community?', 'Välj ”Starta community”. Du bestämmer namn och adress och gör några grundläggande inställningar. Sedan hamnar du direkt i din instrumentpanel och kan sätta igång.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_1', c."id", 'Vad är instrumentpanelen?', 'Instrumentpanelen är ditt kommandocentrum. Härifrån skapar du olika utrymmen, publicerar innehåll, hanterar medlemmar, bestämmer medlemskap och priser, skickar nyhetsbrev och ser dina viktigaste siffror.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_2', c."id", 'Vad är utrymmen?', 'Utrymmen är rummen i din community – till exempel ett flöde för inlägg, kurser, event, en chatt eller ett mediebibliotek.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_3', c."id", 'Kan jag anpassa utseendet efter mitt varumärke?', 'Ja. Du kan ställa in logotyp, färger och layout så att din community känns som ditt eget varumärke. Aera håller sig medvetet i bakgrunden – det är du som står i förgrunden.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_4', c."id", 'Får jag en egen adress?', 'Ja. Din community får en egen webbadress (till exempel deinname.aera.so). Du kan också koppla på en egen önskad domän.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_community-starten_5', c."id", 'Hur bjuder jag in de första medlemmarna?', 'Dela bara länken till din community – via sociala medier, chattappar eller e-post. Senare når du dina medlemmar när som helst direkt via nyhetsbrevet, helt utan någon algoritm emellan.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_mitgliedschaften-preise_0', c."id", 'Vad är ett medlemskap?', 'Ett medlemskap bestämmer vad en medlem får se och göra i din community. Det kan finnas både kostnadsfria och betalda nivåer – till exempel ”Gratis”, ”Plus” och ”Premium”.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_mitgliedschaften-preise_1', c."id", 'Hur skapar jag ett betalt medlemskap?', 'I instrumentpanelen skapar du en ny nivå under Medlemskap. Du väljer pris och betalningssätt (månadsvis eller årsvis) och bestämmer vilka utrymmen och innehåll nivån låser upp.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_mitgliedschaften-preise_2', c."id", 'Hur blir jag betalande medlem?', 'Välj det medlemskap du vill ha i communityn och slutför betalningen via den säkra kassan. Din åtkomst låses upp direkt.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_mitgliedschaften-preise_3', c."id", 'Kan jag ändra eller säga upp mitt medlemskap?', 'Ja. I dina medlemskapsinställningar kan du när som helst byta eller säga upp.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_mitgliedschaften-preise_4', c."id", 'Vad händer med min åtkomst efter köpet?', 'Betalda utrymmen och innehåll låses upp automatiskt. När ett medlemskap löper ut låses de igen – men dina egna inlägg och uppgifter finns kvar.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_0', c."id", 'Hur betalar jag på ett säkert sätt?', 'Betalningar sköts av vår betalleverantör Stripe. Dina betaluppgifter behandlas krypterat där – Aera lagrar själv inga kortuppgifter.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_1', c."id", 'Vilka betalsätt kan jag använda?', 'Beroende på land och enhet kan du till exempel använda kredit- och betalkort samt vanliga digitala betalsätt. Vilka alternativ som är möjliga ser du direkt i kassan.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_2', c."id", 'Får jag ett kvitto eller en faktura?', 'Ja. Efter varje köp får du en bekräftelse via e-post. Dina köp hittar du dessutom när som helst i dina kontoinställningar.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_3', c."id", 'Hur får jag mina intäkter som kreatör?', 'Dina utbetalningar sköts säkert via Stripe. Du anger dina utbetalningsuppgifter en gång, sedan förs dina intäkter automatiskt över till dig.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_4', c."id", 'Vilka avgifter tillkommer för kreatörer?', 'Aera tar ut en liten plattformsavgift vid försäljning. Dessutom kan betalleverantörens avgifter tillkomma vid själva betalningen. Resten av dina intäkter är dina.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_bezahlen-auszahlungen_5', c."id", 'Hur fungerar återbetalningar?', 'En återbetalning startas av den aktuella kreatören. Om du har frågor om ett köp, vänd dig först till kreatören för communityn – eller till vår support om du inte kommer vidare.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_0', c."id", 'Hur publicerar jag ett inlägg?', 'Öppna rätt utrymme, välj ”Nytt inlägg”, lägg till text och media och publicera. Du bestämmer samtidigt vilka medlemmar som får se inlägget.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_1', c."id", 'Hur skapar jag en kurs?', 'Skapa ett kursutrymme och lägg till lektioner eller moduler. Du bestämmer om kursen ska vara fritt tillgänglig eller en del av ett betalt medlemskap.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_2', c."id", 'Hur planerar jag ett event?', 'I eventutrymmet anger du titel, tidpunkt och detaljer. Medlemmar kan tacka ja. Event kan du erbjuda kostnadsfritt eller mot betalning.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_3', c."id", 'Hur skickar jag ett nyhetsbrev?', 'Skriv ett nyhetsbrev i instrumentpanelen och skicka det till alla eller till utvalda medlemmar. Så når du din community direkt i deras inkorg – utan någon främmande algoritm emellan.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_4', c."id", 'Vad är mediebiblioteket?', 'Mediebiblioteket är den centrala platsen för dina videor, ljudfiler och dokument. Därifrån lägger du in dem i inlägg, kurser eller event.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_inhalte-erstellen_5', c."id", 'Kan jag planera inlägg i förväg?', 'Ja. Du kan schemalägga innehåll till en senare tidpunkt så att det publiceras automatiskt – smidigt för att hålla dig aktiv regelbundet.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_0', c."id", 'Hur går jag med i en community?', 'Öppna communityn och välj ”Gå med”. I kostnadsfria communityn är du med direkt. I betalda väljer du först ett medlemskap.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_1', c."id", 'Hur skriver jag inlägg och kommentarer?', 'I alla utrymmen du har åtkomst till kan du skriva inlägg, kommentera och reagera – ungefär som i ett socialt nätverk, fast utan någon främmande algoritm.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_2', c."id", 'Var hittar jag kurser och event?', 'Upplåsta kurser hittar du i utrymmet ”Kurser” och kommande tillfällen under ”Event”. Vad du kan se beror på ditt medlemskap.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_3', c."id", 'Vad är poäng, nivåer och märken?', 'För din aktivitet samlar du poäng, stiger i nivå och tjänar märken. En topplista visar särskilt aktiva medlemmar – det gör det roligare att vara med.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_4', c."id", 'Kan jag skriva till andra medlemmar?', 'Ja, så länge kreatören har aktiverat chatt och direktmeddelanden kan du utbyta tankar med andra medlemmar.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_teilnehmen_5', c."id", 'Hur ställer jag in mina aviseringar?', 'I dina kontoinställningar bestämmer du vad du vill bli informerad om via e-post och i appen.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_ki-funktionen_0', c."id", 'Vad kan AI-assistenten göra?', 'AI-assistenten hjälper dig att skriva inlägg och nyhetsbrev och att samla idéer. Den ger dig en startpunkt som du sedan anpassar – du behåller alltid kontrollen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_ki-funktionen_1', c."id", 'Vad är AI-rekommendationer?', 'Aera föreslår passande innehåll för medlemmar så att de snabbare hittar det som intresserar dem. Om ingen AI är aktiv sker det via en enkel och tydlig sökning på nyckelord.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_ki-funktionen_2', c."id", 'Vad är AI-saldot?', 'AI-funktioner förbrukar saldo. Varje community har ett saldo, och vid behov kan du köpa till fler paket.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_ki-funktionen_3', c."id", 'Vad händer när AI-saldot är slut?', 'Då pausas AI-funktionerna tills du fyller på nytt saldo. Alla övriga funktioner i din community fortsätter att fungera helt som vanligt.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_ki-funktionen_4', c."id", 'Används mitt innehåll för att träna AI?', 'Nej. Ditt innehåll tillhör dig. Det används bara för att ge dig de funktioner som du själv använder.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_0', c."id", 'Hur ändrar jag min profil eller mitt lösenord?', 'I dina kontoinställningar kan du när som helst ändra namn, profilbild, e-postadress och lösenord.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_1', c."id", 'Hur hanterar jag mina medlemmar?', 'I instrumentpanelen ser du alla medlemmar i din community. Du kan tilldela roller som moderator, bjuda in nya medlemmar eller ta bort medlemmar.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_2', c."id", 'Är mina data mina?', 'Ja. Din community, din medlemslista och ditt innehåll tillhör dig. Du kan ladda ner dina data när som helst – du är inte bunden till något.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_3', c."id", 'Hur laddar jag ner mina data?', 'I inställningarna hittar du dataexporten. Med den får du ditt innehåll i ett vanligt format som du kan ladda ner.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_4', c."id", 'Hur säkra är mina data?', 'Varje community är tydligt avskild från alla andra och skyddad, så att ingen annan har åtkomst. Dina betaluppgifter finns enbart hos betalleverantören, inte hos Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_5', c."id", 'Hur raderar jag min community eller mitt konto?', 'Det gör du i inställningarna. Vid radering tas det tillhörande innehållet bort – ladda vid behov ner dina data innan dess.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_sv_konto-marke-daten_6', c."id", 'Hur når jag supporten?', 'Använd kontaktknappen längst ner i hjälpcentret. Beskriv ditt ärende så noggrant som möjligt, så kan vi hjälpa dig snabbt.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_sv_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_erste-schritte', 'ru', 'Первые шаги', 'erste-schritte', 'Знакомство с Aera, создание аккаунта и поиск сообщества.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_community-starten', 'ru', 'Создание вашего сообщества', 'community-starten', 'Создайте собственное сообщество под своим брендом всего за несколько минут.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_mitgliedschaften-preise', 'ru', 'Подписки и цены', 'mitgliedschaften-preise', 'Как настроить и понять бесплатные и платные подписки.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_bezahlen-auszahlungen', 'ru', 'Оплата и выплаты', 'bezahlen-auszahlungen', 'Безопасная оплата, выплаты авторам, чеки и возвраты.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_inhalte-erstellen', 'ru', 'Материалы: публикации, курсы, мероприятия и рассылки', 'inhalte-erstellen', 'Публикуйте, обучайте, проводите мероприятия и общайтесь с участниками напрямую.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_teilnehmen', 'ru', 'Для участников: как участвовать', 'teilnehmen', 'Присоединяйтесь, участвуйте, учитесь и оставайтесь на связи.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_ki-funktionen', 'ru', 'Функции ИИ', 'ki-funktionen', 'ИИ-ассистент, рекомендации и баланс ИИ.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ru_konto-marke-daten', 'ru', 'Аккаунт, бренд и данные', 'konto-marke-daten', 'Профиль и безопасность, настройка бренда, управление участниками и скачивание данных.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_erste-schritte_0', c."id", 'Что такое Aera?', 'Aera — это платформа, на которой авторы создают собственное сообщество под своим брендом: подписки, курсы, мероприятия, рассылки и многое другое в одном месте.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_erste-schritte_1', c."id", 'Как создать аккаунт?', 'Нажмите «Регистрация» и войдите, указав адрес электронной почты и пароль.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_erste-schritte_2', c."id", 'Нужен ли аккаунт, чтобы просто осмотреться?', 'Многие страницы сообществ можно посмотреть и без аккаунта. Как только вы захотите присоединиться, написать сообщение или что-то приобрести, вам понадобится бесплатный аккаунт.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_erste-schritte_3', c."id", 'Как найти сообщество?', 'Публичные сообщества можно найти в разделе «Обзор» на главной странице. Либо просто откройте адрес или ссылку, которую вам дал автор (например, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_erste-schritte_4', c."id", 'Сколько стоит Aera?', 'Создать аккаунт и присоединиться к сообществу можно бесплатно.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_0', c."id", 'Как создать собственное сообщество?', 'Выберите «Создать сообщество». Вы задаёте название и адрес и делаете несколько основных настроек. После этого вы сразу попадаете в свою панель управления и можете приступать к работе.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_1', c."id", 'Что такое панель управления?', 'Панель управления — это ваш центр управления. Отсюда вы настраиваете разделы, публикуете материалы, управляете участниками, задаёте подписки и цены, отправляете рассылки и видите свои главные показатели.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_2', c."id", 'Что такое разделы?', 'Разделы — это пространства вашего сообщества: например, лента для публикаций, курсы, мероприятия, чат или медиатека.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_3', c."id", 'Могу ли я оформить всё под свой бренд?', 'Да. Вы можете настроить логотип, цвета и оформление так, чтобы ваше сообщество выглядело как ваш собственный бренд. Aera намеренно остаётся на втором плане — на первом плане именно вы.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_4', c."id", 'Получу ли я собственный адрес?', 'Да. Ваше сообщество получает собственный интернет-адрес (например, deinname.aera.so). Также можно подключить собственный домен на ваш выбор.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_community-starten_5', c."id", 'Как пригласить первых участников?', 'Просто поделитесь ссылкой на своё сообщество — в социальных сетях, мессенджерах или по электронной почте. А позже вы в любой момент сможете связаться с участниками напрямую через рассылку, без всяких алгоритмов между вами.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_mitgliedschaften-preise_0', c."id", 'Что такое подписка?', 'Подписка определяет, что участник может видеть и делать в вашем сообществе. Могут быть бесплатные и платные уровни — например, «Бесплатный», «Плюс» и «Премиум».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_mitgliedschaften-preise_1', c."id", 'Как создать платную подписку?', 'В панели управления в разделе «Подписки» вы создаёте новый уровень. Вы выбираете цену и способ оплаты (ежемесячно или ежегодно) и определяете, какие разделы и материалы открывает этот уровень.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_mitgliedschaften-preise_2', c."id", 'Как стать платным участником?', 'Выберите в сообществе нужную подписку и завершите оплату через безопасное оформление заказа. Ваш доступ откроется сразу же.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_mitgliedschaften-preise_3', c."id", 'Могу ли я изменить или отменить подписку?', 'Да. В настройках подписки вы можете в любой момент сменить уровень или отменить подписку.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_mitgliedschaften-preise_4', c."id", 'Что происходит с доступом после покупки?', 'Платные разделы и материалы открываются автоматически. Когда подписка заканчивается, они снова закрываются, но ваши собственные публикации и данные при этом сохраняются.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_0', c."id", 'Как оплатить безопасно?', 'Платежи проходят через нашего платёжного оператора Stripe. Ваши платёжные данные обрабатываются там в зашифрованном виде — сама Aera не хранит данные карт.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_1', c."id", 'Какими способами оплаты можно пользоваться?', 'В зависимости от страны и устройства вам доступны, например, кредитные и дебетовые карты, а также распространённые цифровые способы оплаты. Какие варианты возможны, вы увидите прямо при оформлении оплаты.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_2', c."id", 'Получу ли я чек или счёт?', 'Да. После каждой покупки вы получаете подтверждение по электронной почте. Кроме того, все ваши покупки в любой момент доступны в настройках аккаунта.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_3', c."id", 'Как я, как автор, получаю свой доход?', 'Ваши выплаты надёжно проходят через Stripe. Вы один раз указываете свои платёжные реквизиты, после чего доход автоматически перечисляется вам.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_4', c."id", 'Какие комиссии платят авторы?', 'При продаже Aera удерживает небольшую комиссию платформы. Дополнительно при обработке платежа может взиматься комиссия платёжного оператора. Остальная часть вашего дохода принадлежит вам.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_bezahlen-auszahlungen_5', c."id", 'Как работают возвраты?', 'Возврат оформляет соответствующий автор. Если у вас есть вопросы по покупке, обратитесь сначала к автору сообщества — или в нашу службу поддержки, если вопрос не удаётся решить.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_0', c."id", 'Как опубликовать запись?', 'Откройте нужный раздел, выберите «Новая запись», добавьте текст и медиа и опубликуйте. При этом вы указываете, какие участники смогут видеть эту запись.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_1', c."id", 'Как создать курс?', 'Создайте раздел с курсом и добавьте уроки или модули. Вы решаете, будет ли курс в свободном доступе или частью платной подписки.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_2', c."id", 'Как запланировать мероприятие?', 'В разделе мероприятий вы задаёте название, время и детали. Участники могут подтвердить участие. Мероприятия можно проводить бесплатно или за плату.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_3', c."id", 'Как отправить рассылку?', 'Составьте рассылку в панели управления и отправьте её всем или выбранным участникам. Так вы обращаетесь к своему сообществу напрямую в их почтовом ящике — без чужих алгоритмов между вами.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_4', c."id", 'Что такое медиатека?', 'Медиатека — это центральное место для ваших видео, аудио и файлов. Оттуда вы добавляете их в публикации, курсы или мероприятия.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_inhalte-erstellen_5', c."id", 'Могу ли я планировать публикации заранее?', 'Да. Вы можете запланировать материалы на более позднее время, чтобы они появлялись автоматически — удобно, чтобы регулярно оставаться активным.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_0', c."id", 'Как присоединиться к сообществу?', 'Откройте сообщество и выберите «Присоединиться». В бесплатных сообществах вы становитесь участником сразу. В платных вы сначала выбираете подписку.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_1', c."id", 'Как писать публикации и комментарии?', 'Во всех разделах, к которым у вас есть доступ, вы можете писать публикации, комментировать и реагировать — почти как в социальной сети, только без чужих алгоритмов.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_2', c."id", 'Где найти курсы и мероприятия?', 'Открытые вам курсы находятся в разделе «Курсы», а ближайшие даты — в разделе «Мероприятия». Что именно вы видите, зависит от вашей подписки.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_3', c."id", 'Что такое очки, уровни и значки?', 'За вашу активность вы набираете очки, повышаете уровень и зарабатываете значки. Таблица лидеров показывает самых активных участников — так участвовать становится живее и интереснее.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_4', c."id", 'Могу ли я писать другим участникам?', 'Да, если автор включил чат и личные сообщения, вы можете общаться с другими участниками.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_teilnehmen_5', c."id", 'Как настроить уведомления?', 'В настройках аккаунта вы указываете, о чём хотите получать уведомления по электронной почте и в приложении.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_ki-funktionen_0', c."id", 'Что умеет ИИ-ассистент?', 'ИИ-ассистент помогает вам писать публикации, рассылки и собирать идеи. Он даёт отправную точку, которую вы дорабатываете, — контроль всегда остаётся за вами.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_ki-funktionen_1', c."id", 'Что такое рекомендации ИИ?', 'Aera предлагает участникам подходящие материалы, чтобы они быстрее находили то, что им интересно. Если ИИ не включён, это работает через простой и прозрачный поиск по ключевым словам.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_ki-funktionen_2', c."id", 'Что такое баланс ИИ?', 'Функции ИИ расходуют баланс. У каждого сообщества есть свой баланс, и при необходимости вы можете докупить дополнительные пакеты.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_ki-funktionen_3', c."id", 'Что происходит, когда баланс ИИ заканчивается?', 'Тогда функции ИИ приостанавливаются, пока вы не пополните баланс. Все остальные функции вашего сообщества продолжают работать как обычно.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_ki-funktionen_4', c."id", 'Используются ли мои материалы для обучения ИИ?', 'Нет. Ваши материалы принадлежат вам. Они используются только для того, чтобы предоставлять вам те функции, которыми вы сами пользуетесь.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_0', c."id", 'Как изменить профиль или пароль?', 'В настройках аккаунта вы можете в любой момент изменить имя, фото профиля, адрес электронной почты и пароль.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_1', c."id", 'Как управлять участниками?', 'В панели управления вы видите всех участников своего сообщества. Вы можете назначать роли, например модератора, приглашать новых участников или удалять участников.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_2', c."id", 'Принадлежат ли мне мои данные?', 'Да. Ваше сообщество, ваш список участников и ваши материалы принадлежат вам. Вы можете в любой момент скачать свои данные — вы ничем не связаны.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_3', c."id", 'Как скачать свои данные?', 'В настройках вы найдёте экспорт данных. С его помощью вы получаете свои материалы для скачивания в распространённом формате.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_4', c."id", 'Насколько защищены мои данные?', 'Каждое сообщество надёжно отделено от всех остальных и защищено, так что ни у кого другого нет к нему доступа. Ваши платёжные данные хранятся исключительно у платёжного оператора, а не в Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_5', c."id", 'Как удалить сообщество или аккаунт?', 'Это можно сделать в настройках. При удалении соответствующие материалы удаляются — при необходимости заранее скачайте свои данные.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ru_konto-marke-daten_6', c."id", 'Как связаться со службой поддержки?', 'Воспользуйтесь кнопкой «Связаться» в конце центра помощи. Опишите свой вопрос как можно точнее, и тогда мы сможем быстро вам помочь.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ru_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_erste-schritte', 'uk', 'Перші кроки', 'erste-schritte', 'Знайомство з Aera, створення облікового запису та пошук спільноти.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_community-starten', 'uk', 'Створення вашої спільноти', 'community-starten', 'Створіть власну спільноту під своїм брендом за кілька хвилин.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_mitgliedschaften-preise', 'uk', 'Підписки та ціни', 'mitgliedschaften-preise', 'Як налаштувати безкоштовні та платні підписки й розібратися в них.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_bezahlen-auszahlungen', 'uk', 'Оплата та виплати', 'bezahlen-auszahlungen', 'Безпечна оплата, виплати авторам, чеки та повернення коштів.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_inhalte-erstellen', 'uk', 'Матеріали: дописи, курси, події та розсилки', 'inhalte-erstellen', 'Публікуйте, навчайте, проводьте події та звертайтеся до учасників безпосередньо.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_teilnehmen', 'uk', 'Для учасників: участь у спільноті', 'teilnehmen', 'Приєднуйтеся, беріть участь, навчайтеся та залишайтеся на зв''язку.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_ki-funktionen', 'uk', 'Функції ШІ', 'ki-funktionen', 'ШІ-помічник, рекомендації та баланс ШІ.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_uk_konto-marke-daten', 'uk', 'Обліковий запис, бренд і дані', 'konto-marke-daten', 'Профіль і безпека, налаштування бренду, керування учасниками та завантаження даних.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_erste-schritte_0', c."id", 'Що таке Aera?', 'Aera — це платформа, на якій автори ведуть власну спільноту під власним брендом: із підписками, курсами, подіями, розсилкою та багато чим іншим в одному місці.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_erste-schritte_1', c."id", 'Як створити обліковий запис?', 'Натисніть «Зареєструватися» й увійдіть за допомогою своєї електронної адреси та пароля.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_erste-schritte_2', c."id", 'Чи потрібен обліковий запис, щоб просто роздивитися?', 'Багато сторінок спільнот можна переглядати й без облікового запису. Щойно ви захочете приєднатися, щось написати чи придбати, вам знадобиться безкоштовний обліковий запис.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_erste-schritte_3', c."id", 'Як знайти спільноту?', 'Публічні спільноти можна знайти через «Огляд» на головній сторінці. Або ж відкрийте безпосередньо адресу чи посилання, які вам дав автор (наприклад, name.aera.so).', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_erste-schritte_4', c."id", 'Скільки коштує Aera?', 'Створити обліковий запис і приєднатися до спільноти можна безкоштовно.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_0', c."id", 'Як створити власну спільноту?', 'Оберіть «Створити спільноту». Ви задаєте назву й адресу та робите кілька базових налаштувань. Після цього ви одразу потрапляєте до своєї панелі керування й можете починати.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_1', c."id", 'Що таке панель керування?', 'Панель керування — це ваш центр управління. Звідси ви налаштовуєте розділи, публікуєте матеріали, керуєте учасниками, задаєте підписки та ціни, надсилаєте розсилки й бачите свої найважливіші показники.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_2', c."id", 'Що таке розділи?', 'Розділи — це простори вашої спільноти: наприклад, стрічка дописів, курси, події, чат або медіатека.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_3', c."id", 'Чи можна налаштувати вигляд під мій бренд?', 'Так. Ви можете налаштувати логотип, кольори та макет так, щоб ваша спільнота виглядала як ваш власний бренд. Aera свідомо залишається на другому плані — на першому плані саме ви.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_4', c."id", 'Чи отримаю я власну адресу?', 'Так. Ваша спільнота отримує власну інтернет-адресу (наприклад, deinname.aera.so). Також можна підключити власний бажаний домен.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_community-starten_5', c."id", 'Як запросити перших учасників?', 'Просто поділіться посиланням на свою спільноту — у соцмережах, месенджері чи електронною поштою. А згодом ви завжди зможете звертатися до своїх учасників безпосередньо через розсилку, без жодного алгоритму між вами.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_mitgliedschaften-preise_0', c."id", 'Що таке підписка?', 'Підписка визначає, що учасник може бачити й робити у вашій спільноті. Можуть бути безкоштовні та платні рівні — наприклад, «Безкоштовний», «Плюс» і «Преміум».', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_mitgliedschaften-preise_1', c."id", 'Як створити платну підписку?', 'На панелі керування у розділі підписок ви створюєте новий рівень. Ви обираєте ціну та спосіб оплати (щомісяця або щороку) і визначаєте, які розділи та матеріали відкриває цей рівень.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_mitgliedschaften-preise_2', c."id", 'Як стати платним учасником?', 'Оберіть у спільноті потрібну підписку та завершіть оплату через безпечну форму оплати. Ваш доступ відкриється одразу.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_mitgliedschaften-preise_3', c."id", 'Чи можна змінити або скасувати підписку?', 'Так. У налаштуваннях підписки ви можете будь-коли змінити рівень або скасувати підписку.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_mitgliedschaften-preise_4', c."id", 'Що відбувається з моїм доступом після покупки?', 'Платні розділи та матеріали відкриваються автоматично. Коли підписка завершується, вони знову закриваються — але ваші власні дописи й дані при цьому зберігаються.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_0', c."id", 'Як оплатити безпечно?', 'Платежі проходять через нашого платіжного партнера Stripe. Ваші платіжні дані обробляються там у зашифрованому вигляді — сама Aera не зберігає дані карток.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_1', c."id", 'Якими способами оплати я можу скористатися?', 'Залежно від країни та пристрою вам доступні, наприклад, кредитні й дебетові картки, а також поширені цифрові способи оплати. Які саме варіанти можливі, ви побачите безпосередньо під час оплати.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_2', c."id", 'Чи отримаю я чек або рахунок?', 'Так. Після кожної покупки ви отримуєте підтвердження електронною поштою. Крім того, свої покупки ви завжди можете переглянути в налаштуваннях облікового запису.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_3', c."id", 'Як я, як автор, отримую свій дохід?', 'Ваші виплати надійно проходять через Stripe. Ви один раз вказуєте свої реквізити для виплат, після чого ваш дохід автоматично перераховується вам.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_4', c."id", 'Які комісії передбачені для авторів?', 'Під час продажу Aera утримує невелику комісію платформи. Додатково під час обробки платежу можуть виникати комісії платіжного партнера. Решта вашого доходу належить вам.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_bezahlen-auszahlungen_5', c."id", 'Як працює повернення коштів?', 'Повернення коштів ініціює відповідний автор. Якщо у вас є питання щодо покупки, спершу зверніться до автора спільноти — або до нашої служби підтримки, якщо не вдається розв''язати питання.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_0', c."id", 'Як опублікувати допис?', 'Відкрийте потрібний розділ, оберіть «Новий допис», додайте текст і медіа та опублікуйте. При цьому ви визначаєте, які учасники зможуть бачити цей допис.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_1', c."id", 'Як створити курс?', 'Створіть розділ курсу та додайте уроки або модулі. Ви вирішуєте, чи буде курс у вільному доступі, чи стане частиною платної підписки.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_2', c."id", 'Як запланувати подію?', 'У розділі подій ви задаєте назву, час і деталі. Учасники можуть підтвердити участь. Події можна пропонувати безкоштовно або за плату.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_3', c."id", 'Як надіслати розсилку?', 'Складіть розсилку на панелі керування та надішліть її всім або обраним учасникам. Так ви звертаєтеся до своєї спільноти безпосередньо в їхній поштовій скриньці — без стороннього алгоритму між вами.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_4', c."id", 'Що таке медіатека?', 'Медіатека — це центральне місце для ваших відео, аудіо та файлів. Звідти ви додаєте їх до дописів, курсів або подій.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_inhalte-erstellen_5', c."id", 'Чи можна планувати дописи заздалегідь?', 'Так. Ви можете планувати матеріали на пізніший час, щоб вони з''являлися автоматично — це зручно, аби залишатися активними регулярно.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_0', c."id", 'Як приєднатися до спільноти?', 'Відкрийте спільноту та оберіть «Приєднатися». До безкоштовних спільнот ви долучаєтеся одразу. До платних — спершу оберіть підписку.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_1', c."id", 'Як писати дописи та коментарі?', 'У всіх розділах, до яких у вас є доступ, ви можете писати дописи, коментувати та реагувати — схоже на соціальну мережу, тільки без стороннього алгоритму.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_2', c."id", 'Де знайти курси та події?', 'Відкриті для вас курси ви знайдете в розділі «Курси», а найближчі заходи — у розділі «Події». Те, що ви можете бачити, залежить від вашої підписки.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_3', c."id", 'Що таке бали, рівні та значки?', 'За свою активність ви накопичуєте бали, підвищуєте рівень і отримуєте значки. Таблиця лідерів показує найактивніших учасників — так участь стає жвавішою.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_4', c."id", 'Чи можу я писати іншим учасникам?', 'Так, якщо автор увімкнув чат і особисті повідомлення, ви можете спілкуватися з іншими учасниками.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_teilnehmen_5', c."id", 'Як налаштувати сповіщення?', 'У налаштуваннях облікового запису ви визначаєте, про що хочете отримувати сповіщення електронною поштою та в застосунку.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_ki-funktionen_0', c."id", 'Що вміє ШІ-помічник?', 'ШІ-помічник допомагає вам писати дописи, розсилки та збирати ідеї. Він дає відправну точку, яку ви допрацьовуєте — контроль завжди залишається за вами.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_ki-funktionen_1', c."id", 'Що таке рекомендації ШІ?', 'Aera пропонує учасникам відповідні матеріали, щоб вони швидше знаходили те, що їх цікавить. Якщо ШІ не активний, це працює через простий і прозорий пошук за ключовими словами.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_ki-funktionen_2', c."id", 'Що таке баланс ШІ?', 'Функції ШІ витрачають баланс. Кожна спільнота має свій баланс, і за потреби ви можете докупити додаткові пакети.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_ki-funktionen_3', c."id", 'Що відбувається, коли баланс ШІ вичерпано?', 'Тоді функції ШІ призупиняються, доки ви не поповните баланс. Усі інші функції вашої спільноти працюють, як зазвичай.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_ki-funktionen_4', c."id", 'Чи використовуються мої матеріали для навчання ШІ?', 'Ні. Ваші матеріали належать вам. Вони використовуються лише для того, щоб надавати вам ті функції, якими ви користуєтеся.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_0', c."id", 'Як змінити профіль або пароль?', 'У налаштуваннях облікового запису ви можете будь-коли змінити ім''я, фото профілю, електронну адресу та пароль.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_1', c."id", 'Як керувати учасниками?', 'На панелі керування ви бачите всіх учасників своєї спільноти. Ви можете призначати ролі, як-от модератор, запрошувати нових учасників або видаляти їх.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_2', c."id", 'Чи належать мені мої дані?', 'Так. Ваша спільнота, ваш список учасників і ваші матеріали належать вам. Ви можете будь-коли завантажити свої дані — вас нічого не зобов''язує.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_3', c."id", 'Як завантажити свої дані?', 'У налаштуваннях ви знайдете експорт даних. Так ви отримаєте свої матеріали для завантаження у поширеному форматі.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_4', c."id", 'Наскільки захищені мої дані?', 'Кожна спільнота повністю відокремлена від інших і захищена, тож більше ніхто не має до неї доступу. Ваші платіжні дані зберігаються виключно у платіжного партнера, а не в Aera.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_5', c."id", 'Як видалити свою спільноту або обліковий запис?', 'Це можна зробити в налаштуваннях. Під час видалення пов''язані матеріали буде вилучено — за потреби спершу завантажте свої дані.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_uk_konto-marke-daten_6', c."id", 'Як звернутися до служби підтримки?', 'Скористайтеся кнопкою зв''язку в кінці довідкового центру. Опишіть своє питання якомога точніше, і ми зможемо швидко вам допомогти.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_uk_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_erste-schritte', 'ja', 'はじめに', 'erste-schritte', 'Aeraについて知り、アカウントを作成し、コミュニティを見つけましょう。', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_community-starten', 'ja', 'コミュニティを始める', 'community-starten', '自分のブランドのもとで、数分で自分だけのコミュニティを立ち上げましょう。', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_mitgliedschaften-preise', 'ja', 'メンバーシップと料金', 'mitgliedschaften-preise', '無料と有料のメンバーシップを設定し、その仕組みを理解しましょう。', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_bezahlen-auszahlungen', 'ja', 'お支払いとお受け取り', 'bezahlen-auszahlungen', '安全なお支払い、クリエイターへの入金、領収書、返金について。', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_inhalte-erstellen', 'ja', 'コンテンツ：投稿、コース、イベント、ニュースレター', 'inhalte-erstellen', 'コンテンツを公開し、教え、イベントを開き、メンバーに直接届けましょう。', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_teilnehmen', 'ja', 'メンバーの方へ：参加する', 'teilnehmen', '参加して、活動して、学んで、つながりを保ちましょう。', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_ki-funktionen', 'ja', 'AI機能', 'ki-funktionen', 'AIアシスタント、おすすめ機能、AIクレジットについて。', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ja_konto-marke-daten', 'ja', 'アカウント、ブランド、データ', 'konto-marke-daten', 'プロフィールとセキュリティ、ブランドの調整、メンバーの管理、データのダウンロードについて。', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_erste-schritte_0', c."id", 'Aeraとは何ですか？', 'Aeraは、クリエイターが自分自身のブランドのもとで独自のコミュニティを運営できるプラットフォームです。メンバーシップ、コース、イベント、ニュースレターなどを一つの場所にまとめられます。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_erste-schritte_1', c."id", 'アカウントはどのように作成しますか？', '「登録」をクリックし、メールアドレスとパスワードでサインインしてください。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_erste-schritte_2', c."id", '見て回るだけでもアカウントは必要ですか？', '多くのコミュニティページは、アカウントがなくてもご覧いただけます。参加したり、投稿したり、何かを購入したりしたくなったときには、無料のアカウントが必要になります。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_erste-schritte_3', c."id", 'コミュニティはどうやって見つけますか？', 'トップページの「見つける」から、公開されているコミュニティを探せます。または、クリエイターから教えてもらったアドレスやリンク（例：name.aera.so）を直接開くこともできます。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_erste-schritte_4', c."id", 'Aeraの利用にはいくらかかりますか？', 'アカウントの作成とコミュニティへの参加は無料です。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_0', c."id", '自分のコミュニティはどうやって始めますか？', '「コミュニティを始める」を選びます。名前とアドレスを決め、いくつかの基本設定を行います。その後はそのままダッシュボードに移動し、すぐに始められます。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_1', c."id", 'ダッシュボードとは何ですか？', 'ダッシュボードは、あなたの操作の中心となる場所です。ここからスペースを設定したり、コンテンツを公開したり、メンバーを管理したり、メンバーシップや料金を決めたり、ニュースレターを送ったり、大切な数値を確認したりできます。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_2', c."id", 'スペースとは何ですか？', 'スペースは、コミュニティの中のさまざまな部屋のようなものです。たとえば、投稿用のフィードやコース、イベント、チャット、メディアライブラリなどがあります。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_3', c."id", '見た目を自分のブランドに合わせられますか？', 'はい。ロゴや色、レイアウトを調整して、コミュニティをあなた自身のブランドらしく見せられます。Aeraはあえて後ろに控え、主役はいつもあなたです。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_4', c."id", '自分専用のアドレスはもらえますか？', 'はい。あなたのコミュニティには専用のインターネットアドレス（例：deinname.aera.so）が付きます。ご希望の独自ドメインを接続することもできます。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_community-starten_5', c."id", '最初のメンバーはどうやって招待しますか？', 'コミュニティへのリンクを、SNSやメッセンジャー、メールなどでシェアするだけです。その後は、ニュースレターを通じていつでもメンバーに直接届けられます。間にアルゴリズムが入ることもありません。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_mitgliedschaften-preise_0', c."id", 'メンバーシップとは何ですか？', 'メンバーシップは、メンバーがコミュニティ内で何を見られ、何ができるかを決めるものです。無料と有料のプランを用意できます。たとえば「フリー」「プラス」「プレミアム」などです。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_mitgliedschaften-preise_1', c."id", '有料メンバーシップはどうやって作成しますか？', 'ダッシュボードのメンバーシップから、新しいプランを作成します。料金と請求の周期（月額または年額）を選び、そのプランでどのスペースやコンテンツを利用できるようにするかを決めます。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_mitgliedschaften-preise_2', c."id", '有料メンバーになるにはどうすればよいですか？', 'コミュニティで希望のメンバーシップを選び、安全なお支払い画面で決済を完了してください。アクセス権はすぐに有効になります。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_mitgliedschaften-preise_3', c."id", 'メンバーシップの変更や解約はできますか？', 'はい。メンバーシップの設定から、いつでも変更や解約ができます。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_mitgliedschaften-preise_4', c."id", '購入後、私のアクセス権はどうなりますか？', '有料のスペースやコンテンツは自動的に利用できるようになります。メンバーシップが終了すると再び利用できなくなりますが、あなた自身の投稿やデータはそのまま残ります。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_0', c."id", '安全に支払うにはどうすればよいですか？', 'お支払いは、決済サービスのStripeを通じて処理されます。お支払い情報はそこで暗号化して扱われ、Aera自体がカード情報を保存することはありません。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_1', c."id", 'どんな支払い方法が使えますか？', 'お住まいの国やお使いの端末によって、たとえばクレジットカードやデビットカード、一般的なデジタル決済などがご利用いただけます。どの方法が使えるかは、お支払い画面で直接ご確認いただけます。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_2', c."id", '領収書や請求書はもらえますか？', 'はい。ご購入のたびに、確認のメールが届きます。また、購入履歴はいつでもアカウント設定からご確認いただけます。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_3', c."id", 'クリエイターとして、売上はどのように受け取れますか？', '入金は、Stripeを通じて安全に行われます。最初に一度だけ受け取り用の情報を登録すれば、その後は売上が自動的にあなたへ振り込まれます。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_4', c."id", 'クリエイターにはどんな手数料がかかりますか？', 'Aeraは、販売時にわずかなプラットフォーム手数料をいただきます。さらに、決済の処理にあたって決済サービスの手数料がかかる場合があります。残りの売上はすべてあなたのものです。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_bezahlen-auszahlungen_5', c."id", '返金はどのように行われますか？', '返金は、それぞれのクリエイターが手続きを行います。ご購入について疑問がある場合は、まずそのコミュニティのクリエイターにお問い合わせください。解決しない場合は、私たちのサポートまでご連絡ください。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_0', c."id", '投稿はどうやって公開しますか？', '目的のスペースを開いて「新しい投稿」を選び、テキストやメディアを追加して公開します。その際、どのメンバーが投稿を見られるかを決められます。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_1', c."id", 'コースはどうやって作成しますか？', 'コース用のスペースを作り、レッスンやモジュールを追加します。そのコースを誰でも自由に利用できるようにするか、有料メンバーシップの一部にするかは、あなたが決められます。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_2', c."id", 'イベントはどうやって計画しますか？', 'イベント用のスペースで、タイトルや日時、詳細を設定します。メンバーは参加の返事をすることができます。イベントは無料でも有料でも提供できます。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_3', c."id", 'ニュースレターはどうやって送りますか？', 'ダッシュボードでニュースレターを作成し、すべてのメンバー、または選んだメンバーに送ります。こうして、間に外部のアルゴリズムを介さず、コミュニティのメンバーの受信トレイに直接届けられます。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_4', c."id", 'メディアライブラリとは何ですか？', 'メディアライブラリは、動画や音声、ファイルをまとめて置いておける中心的な場所です。そこから、投稿やコース、イベントにそれらを組み込めます。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_inhalte-erstellen_5', c."id", '投稿を前もって予約できますか？', 'はい。コンテンツを後の日時に予約しておけば、自動的に公開されます。定期的に活動を続けたいときに便利です。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_0', c."id", 'コミュニティにはどうやって参加しますか？', 'コミュニティを開いて「参加する」を選びます。無料のコミュニティなら、すぐに参加できます。有料の場合は、まずメンバーシップを選びます。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_1', c."id", '投稿やコメントはどうやって書きますか？', 'アクセスできるすべてのスペースで、投稿したり、コメントしたり、リアクションしたりできます。SNSに似ていますが、外部のアルゴリズムが入ることはありません。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_2', c."id", 'コースやイベントはどこで見つけられますか？', '利用できるコースは「コース」のスペースに、これからの予定は「イベント」にあります。何を見られるかは、あなたのメンバーシップによって変わります。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_3', c."id", 'ポイント、レベル、バッジとは何ですか？', '活動するとポイントがたまり、レベルが上がり、バッジを獲得できます。ランキングでは特に活発なメンバーが表示され、参加がより楽しくなります。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_4', c."id", '他のメンバーにメッセージを送れますか？', 'はい。クリエイターがチャットやダイレクトメッセージを有効にしている場合は、他のメンバーと交流できます。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_teilnehmen_5', c."id", '通知はどうやって設定しますか？', 'アカウント設定で、どんなことをメールやアプリで知らせてほしいかを決められます。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_ki-funktionen_0', c."id", 'AIアシスタントには何ができますか？', 'AIアシスタントは、投稿やニュースレターを書いたり、アイデアを集めたりするお手伝いをします。出発点を用意してくれるので、あとはあなたが仕上げます。主導権はいつもあなたにあります。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_ki-funktionen_1', c."id", 'AIのおすすめとは何ですか？', 'Aeraは、メンバーが興味のあるものをより早く見つけられるよう、ぴったりのコンテンツを提案します。AIが有効になっていない場合は、キーワードによるシンプルで分かりやすい検索で対応します。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_ki-funktionen_2', c."id", 'AIクレジットとは何ですか？', 'AI機能を使うと、クレジットを消費します。各コミュニティにはクレジットが用意されており、必要に応じて追加のパックを購入できます。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_ki-funktionen_3', c."id", 'AIクレジットを使い切るとどうなりますか？', 'その場合、新しいクレジットを補充するまでAI機能は一時停止します。コミュニティのそのほかの機能は、これまで通り通常どおりご利用いただけます。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_ki-funktionen_4', c."id", '私のコンテンツはAIの学習に使われますか？', 'いいえ。あなたのコンテンツはあなたのものです。あなた自身が使う機能を提供するためだけに利用されます。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_0', c."id", 'プロフィールやパスワードはどうやって変更しますか？', 'アカウント設定から、名前やプロフィール写真、メールアドレス、パスワードをいつでも変更できます。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_1', c."id", 'メンバーはどうやって管理しますか？', 'ダッシュボードでは、コミュニティのすべてのメンバーを確認できます。モデレーターなどの役割を付与したり、新しいメンバーを招待したり、メンバーを削除したりできます。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_2', c."id", 'データは私のものになりますか？', 'はい。あなたのコミュニティ、メンバーのリスト、コンテンツは、すべてあなたのものです。データはいつでもダウンロードでき、何かに縛られることはありません。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_3', c."id", 'データはどうやってダウンロードしますか？', '設定の中に、データのエクスポート機能があります。これを使うと、コンテンツを一般的な形式でダウンロードできます。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_4', c."id", 'データはどのくらい安全ですか？', '各コミュニティは、ほかのすべてのコミュニティときちんと分けられ、保護されているため、ほかの人がアクセスすることはありません。お支払い情報は決済サービスにのみ保管され、Aeraには保管されません。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_5', c."id", 'コミュニティやアカウントはどうやって削除しますか？', '設定から削除できます。削除すると、関連するコンテンツも消えますので、必要に応じて事前にデータをダウンロードしておいてください。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ja_konto-marke-daten_6', c."id", 'サポートにはどうやって連絡できますか？', 'ヘルプセンターの一番下にあるお問い合わせボタンをご利用ください。お困りの内容をできるだけ詳しくお書きいただくと、私たちも早くお手伝いできます。', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ja_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_erste-schritte', 'zh-Hans', '新手上路', 'erste-schritte', '了解 Aera，创建账户，并找到心仪的社区。', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_community-starten', 'zh-Hans', '创建你的社区', 'community-starten', '几分钟内，用你自己的品牌打造专属社区。', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_mitgliedschaften-preise', 'zh-Hans', '会员方案与价格', 'mitgliedschaften-preise', '设置并了解免费和付费的会员方案。', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_bezahlen-auszahlungen', 'zh-Hans', '付款与结算', 'bezahlen-auszahlungen', '安全付款、向创作者结算、单据以及退款。', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_inhalte-erstellen', 'zh-Hans', '内容：帖子、课程、活动与邮件通讯', 'inhalte-erstellen', '发布内容、开课授课、举办活动，并直接触达成员。', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_teilnehmen', 'zh-Hans', '面向成员：参与其中', 'teilnehmen', '加入、互动、学习并保持联系。', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_ki-funktionen', 'zh-Hans', 'AI 功能', 'ki-funktionen', 'AI 助手、推荐功能以及 AI 额度。', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hans_konto-marke-daten', 'zh-Hans', '账户、品牌与数据', 'konto-marke-daten', '管理资料与安全、调整品牌、管理成员以及下载数据。', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_erste-schritte_0', c."id", '什么是 Aera？', 'Aera 是一个平台，创作者可以在这里用自己的品牌运营专属社区——把会员、课程、活动、邮件通讯等功能都汇聚在一个地方。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_erste-schritte_1', c."id", '如何创建账户？', '点击“注册”，用你的电子邮箱和密码登录即可。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_erste-schritte_2', c."id", '只是随便看看也需要账户吗？', '许多社区页面无需账户也可以浏览。只有当你想加入、发言或购买时，才需要一个免费账户。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_erste-schritte_3', c."id", '如何找到一个社区？', '在首页的“发现”里，你可以找到公开的社区。或者你也可以直接打开创作者给你的网址或链接（例如 name.aera.so）。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_erste-schritte_4', c."id", '使用 Aera 需要多少费用？', '创建账户和加入社区都是免费的。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_0', c."id", '如何创建属于自己的社区？', '选择“创建社区”。你先设置好名称和网址，再完成几项基本设置。之后你会直接进入自己的后台，就可以开始了。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_1', c."id", '后台是什么？', '后台是你的中控台。在这里，你可以设置各个板块、发布内容、管理成员、设定会员方案和价格、发送邮件通讯，还能查看最重要的数据。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_2', c."id", '板块是什么？', '板块就是你社区里的各个空间——例如发帖动态、课程、活动、聊天，或者媒体库。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_3', c."id", '我可以把外观调整成自己的品牌风格吗？', '可以。你可以设置徽标、颜色和布局，让你的社区看起来就像你自己的品牌。Aera 会有意退居幕后——站在台前的是你。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_4', c."id", '我会有专属网址吗？', '会的。你的社区会拥有一个专属的网址（例如 deinname.aera.so）。你也可以绑定自己心仪的独立域名。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_community-starten_5', c."id", '如何邀请最早的一批成员？', '只需分享你社区的链接即可——通过社交媒体、即时通讯或电子邮件都行。之后你随时都能通过邮件通讯直接联系到成员，中间没有任何算法阻隔。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_mitgliedschaften-preise_0', c."id", '会员方案是什么？', '会员方案决定了一位成员在你社区里可以看到什么、做什么。你可以设置免费和付费的不同等级——例如“免费版”“进阶版”和“高级版”。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_mitgliedschaften-preise_1', c."id", '如何设置付费会员方案？', '在后台的“会员方案”里，你可以新建一个等级。你可以设定价格和计费方式（按月或按年），并决定该等级会解锁哪些板块和内容。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_mitgliedschaften-preise_2', c."id", '如何成为付费会员？', '在社区里选择你想要的会员方案，通过安全的结账流程完成付款即可。你的权限会立即解锁。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_mitgliedschaften-preise_3', c."id", '我可以更改或取消我的会员方案吗？', '可以。在你的会员方案设置里，你随时都能更换或取消。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_mitgliedschaften-preise_4', c."id", '购买后我的权限会怎样？', '付费的板块和内容会自动解锁。如果会员方案到期，它们会重新被锁定——而你自己发布的内容和数据依然会保留。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_0', c."id", '如何安全付款？', '付款通过我们的支付服务商 Stripe 进行。你的支付信息会在那里以加密方式处理——Aera 本身不会保存任何银行卡信息。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_1', c."id", '我可以使用哪些付款方式？', '根据你所在的国家和设备，你可以使用例如信用卡、借记卡以及常见的电子支付方式。具体有哪些选项，你在结账页面就能直接看到。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_2', c."id", '我会收到单据或发票吗？', '会的。每次购买后，你都会收到一封确认邮件。此外，你随时可以在账户设置里查看自己的购买记录。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_3', c."id", '作为创作者，我如何拿到收入？', '你的结算会通过 Stripe 安全进行。你只需一次性填写好收款信息，之后你的收入就会自动转给你。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_4', c."id", '创作者需要承担哪些费用？', '成交时，Aera 会收取一小笔平台费用。此外，在处理付款时可能还会产生支付服务商的手续费。剩下的收入都归你所有。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_bezahlen-auszahlungen_5', c."id", '退款是怎么处理的？', '退款由相应的创作者发起。如果你对某笔购买有疑问，请先联系该社区的创作者——如果仍无法解决，再联系我们的客服。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_0', c."id", '如何发布一篇帖子？', '打开相应的板块，选择“新建帖子”，添加文字和媒体后发布即可。发布时，你可以决定哪些成员能看到这篇帖子。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_1', c."id", '如何创建一门课程？', '新建一个课程板块，再添加课时或章节。你可以决定这门课是免费开放，还是作为付费会员方案的一部分。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_2', c."id", '如何策划一场活动？', '在活动板块里，你可以设定标题、时间和详情。成员可以报名参加。活动既可以免费提供，也可以收费。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_3', c."id", '如何发送邮件通讯？', '在后台撰写一封邮件通讯，然后发送给所有成员或选定的成员。这样你就能直接把内容送到社区成员的收件箱里——中间没有任何外部算法阻隔。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_4', c."id", '媒体库是什么？', '媒体库是集中存放你的视频、音频和文件的地方。你可以从这里把它们插入到帖子、课程或活动中。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_inhalte-erstellen_5', c."id", '我可以提前安排帖子发布吗？', '可以。你可以把内容安排在稍后的某个时间自动发布——这对于保持稳定更新非常方便。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_0', c."id", '如何加入一个社区？', '打开社区，选择“加入”。免费社区你会立即加入。付费社区则需要你先选择一个会员方案。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_1', c."id", '如何发帖和评论？', '在你有权限的所有板块里，你都可以发帖、评论和点赞互动——就像在社交网络里一样，只是没有外部算法阻隔。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_2', c."id", '在哪里可以找到课程和活动？', '已解锁的课程可以在“课程”板块里找到，即将开始的活动在“活动”里。你能看到哪些内容，取决于你的会员方案。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_3', c."id", '积分、等级和徽章是什么？', '你的每一次参与都能积累积分、提升等级并赢得徽章。排行榜会展示特别活跃的成员——这让参与变得更有乐趣。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_4', c."id", '我可以给其他成员发消息吗？', '可以，只要创作者开启了聊天和私信功能，你就能和其他成员互相交流。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_teilnehmen_5', c."id", '如何设置我的通知？', '在你的账户设置里，你可以决定哪些内容通过电子邮件和应用内通知来提醒你。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_ki-funktionen_0', c."id", 'AI 助手能做什么？', 'AI 助手可以帮你撰写帖子、邮件通讯，以及收集灵感。它会给你一个起点，你再进行调整——主动权始终在你手中。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_ki-funktionen_1', c."id", '什么是 AI 推荐？', 'Aera 会向成员推荐合适的内容，帮他们更快找到感兴趣的东西。如果没有启用 AI，这项功能会通过一种简单、透明的关键词搜索来实现。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_ki-funktionen_2', c."id", '什么是 AI 额度？', 'AI 功能会消耗额度。每个社区都有一份额度，需要时你也可以额外加购套餐。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_ki-funktionen_3', c."id", 'AI 额度用完了会怎样？', '那么 AI 功能会暂停，直到你充值新的额度。你社区里的其他所有功能都会照常运行。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_ki-funktionen_4', c."id", '我的内容会被用于 AI 训练吗？', '不会。你的内容属于你自己。它们只会被用来为你提供你自己正在使用的功能。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_0', c."id", '如何更改我的资料或密码？', '在你的账户设置里，你随时可以修改姓名、头像、电子邮箱和密码。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_1', c."id", '如何管理我的成员？', '在后台你可以看到社区里的所有成员。你可以分配像版主这样的角色，邀请新成员，或移除成员。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_2', c."id", '我的数据属于我自己吗？', '是的。你的社区、你的成员名单和你的内容都属于你。你随时可以下载自己的数据——不受任何约束。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_3', c."id", '如何下载我的数据？', '在设置里你可以找到数据导出功能。通过它，你会得到一份常见格式的内容文件，可供下载。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_4', c."id", '我的数据有多安全？', '每个社区都与其他所有社区彻底隔离并受到保护，别人无法访问。你的支付信息只保存在支付服务商那里，而不是 Aera。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_5', c."id", '如何删除我的社区或账户？', '这可以在设置里完成。删除时，相关内容会被移除——如有需要，请先下载好你的数据。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hans_konto-marke-daten_6', c."id", '如何联系客服？', '使用帮助中心底部的联系按钮。请尽量详细地描述你的问题，这样我们就能更快地帮到你。', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hans_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_erste-schritte', 'zh-Hant', '開始使用', 'erste-schritte', '認識 Aera、建立帳號並找到適合你的社群。', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_community-starten', 'zh-Hant', '開始經營你的社群', 'community-starten', '在短短幾分鐘內，用你的品牌打造出屬於自己的社群。', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_mitgliedschaften-preise', 'zh-Hant', '會員方案與價格', 'mitgliedschaften-preise', '設定並了解免費與付費的會員方案。', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_bezahlen-auszahlungen', 'zh-Hant', '付款與撥款', 'bezahlen-auszahlungen', '安全的付款方式、撥款給創作者、收據與退款。', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_inhalte-erstellen', 'zh-Hant', '內容：貼文、課程、活動與電子報', 'inhalte-erstellen', '發布內容、開課教學、舉辦活動，並直接聯繫你的會員。', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_teilnehmen', 'zh-Hant', '給會員：參與其中', 'teilnehmen', '加入社群、參與互動、學習，並保持聯繫。', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_ki-funktionen', 'zh-Hant', 'AI 功能', 'ki-funktionen', 'AI 小幫手、推薦內容，以及 AI 額度。', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_zh-Hant_konto-marke-daten', 'zh-Hant', '帳號、品牌與資料', 'konto-marke-daten', '個人資料與安全性、調整品牌、管理會員，以及下載資料。', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_erste-schritte_0', c."id", 'Aera 是什麼？', 'Aera 是一個讓創作者用自己的品牌經營專屬社群的平台——會員方案、課程、活動、電子報等功能，全都集中在同一個地方。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_erste-schritte_1', c."id", '我要怎麼建立帳號？', '點選「註冊」，並用你的電子郵件地址和密碼登入。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_erste-schritte_2', c."id", '我需要帳號才能到處看看嗎？', '許多社群頁面即使沒有帳號也能瀏覽。不過只要你想加入、發言互動或購買東西，就需要一個免費帳號。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_erste-schritte_3', c."id", '我要怎麼找到社群？', '在首頁的「探索」中，你可以找到公開的社群。或者你也可以直接開啟創作者給你的網址或連結（例如 name.aera.so）。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_erste-schritte_4', c."id", 'Aera 要多少錢？', '建立帳號和加入社群都是免費的。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_0', c."id", '我要怎麼開始經營自己的社群？', '選擇「開始經營社群」。你可以設定名稱和網址，並完成幾項基本設定。接著你就會直接進入你的管理後台，可以馬上開始。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_1', c."id", '管理後台是什麼？', '管理後台是你的控制中心。你可以在這裡設定各個專區、發布內容、管理會員、設定會員方案與價格、寄送電子報，並查看最重要的各項數據。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_2', c."id", '專區是什麼？', '專區就是你社群裡的各個空間——例如發布貼文的動態、課程、活動、聊天室或媒體庫。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_3', c."id", '我可以把外觀調整成我的品牌風格嗎？', '可以。你可以設定標誌、色彩和版面配置，讓你的社群看起來就像你自己的品牌。Aera 會刻意退居幕後——站在檯面上的是你。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_4', c."id", '我會有專屬的網址嗎？', '會的。你的社群會有一個專屬的網址（例如 deinname.aera.so）。你也可以綁定自己想要的網域。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_community-starten_5', c."id", '我要怎麼邀請第一批會員？', '只要分享你社群的連結就好——透過社群媒體、通訊軟體或電子郵件都行。之後你隨時都能透過電子報直接聯繫到你的會員，中間完全不會有演算法擋在其中。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_mitgliedschaften-preise_0', c."id", '會員方案是什麼？', '會員方案決定了一位會員在你的社群裡可以看到什麼、做什麼。你可以設定免費和付費的不同等級——例如「免費」、「Plus」和「Premium」。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_mitgliedschaften-preise_1', c."id", '我要怎麼建立付費的會員方案？', '在管理後台的「會員方案」中，你可以新增一個等級。你可以選擇價格和收費方式（每月或每年），並決定這個等級可以解鎖哪些專區和內容。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_mitgliedschaften-preise_2', c."id", '我要怎麼成為付費會員？', '在社群中選擇你想要的會員方案，並透過安全的結帳流程完成付款。你的使用權限會立即開通。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_mitgliedschaften-preise_3', c."id", '我可以更改或取消我的會員方案嗎？', '可以。在你的會員方案設定中，你隨時都能更換或取消。
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_mitgliedschaften-preise_4', c."id", '購買之後，我的使用權限會怎麼樣？', '付費的專區和內容會自動開通。當會員方案到期後，這些內容會再次被鎖起來——不過你自己的貼文和資料都會保留下來。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_0', c."id", '我要怎麼安全付款？', '所有付款都透過我們的金流服務商 Stripe 處理。你的付款資料會在 Stripe 那裡經過加密處理——Aera 本身不會儲存任何卡片資料。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_1', c."id", '我可以使用哪些付款方式？', '依照你所在的國家和使用的裝置，你可以使用信用卡、簽帳金融卡，以及常見的數位付款方式等。實際有哪些選項，你在結帳頁面就能直接看到。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_2', c."id", '我會拿到收據或發票嗎？', '會的。每次購買後，你都會收到一封電子郵件確認信。此外，你也隨時可以在你的帳號設定中查看你的購買紀錄。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_3', c."id", '身為創作者，我要怎麼拿到我的收入？', '你的款項會透過 Stripe 安全撥付。你只需要設定一次收款資料，之後你的收入就會自動匯給你。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_4', c."id", '創作者需要負擔哪些費用？', '在銷售時，Aera 會收取一小筆平台費用。此外，金流服務商在處理付款時也可能會收取手續費。除此之外的收入全都歸你所有。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_bezahlen-auszahlungen_5', c."id", '退款是怎麼運作的？', '退款是由該創作者發起的。如果你對某筆購買有疑問，請先聯繫該社群的創作者——如果還是無法解決，再聯繫我們的客服。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_0', c."id", '我要怎麼發布一則貼文？', '開啟合適的專區，選擇「新增貼文」，加入文字和媒體檔案，然後發布。你可以在過程中設定哪些會員可以看到這則貼文。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_1', c."id", '我要怎麼建立一門課程？', '建立一個課程專區，並加入單元或章節。你可以決定這門課程是免費開放，還是屬於某個付費會員方案的一部分。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_2', c."id", '我要怎麼安排一場活動？', '在活動專區中，你可以設定標題、時間和詳細內容。會員可以報名參加。活動可以免費，也可以收費提供。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_3', c."id", '我要怎麼寄送電子報？', '在管理後台撰寫一份電子報，然後寄給所有會員或特定的會員。這樣你就能直接把訊息送進你社群成員的信箱——中間不會有其他演算法擋著。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_4', c."id", '媒體庫是什麼？', '媒體庫是集中存放你影片、音訊和檔案的地方。你可以從那裡把它們放進貼文、課程或活動中。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_inhalte-erstellen_5', c."id", '我可以預先排定貼文嗎？', '可以。你可以把內容排定在之後的某個時間發布，讓它們自動出現——這對於維持規律更新非常方便。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_0', c."id", '我要怎麼加入一個社群？', '開啟該社群，然後選擇「加入」。如果是免費社群，你會立刻成為成員。如果是付費社群，你需要先選擇一個會員方案。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_1', c."id", '我要怎麼發表貼文和留言？', '在所有你有權限進入的專區裡，你都可以發表貼文、留言和按讚回應——就像在社群網站上一樣，只是沒有其他演算法介入。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_2', c."id", '我要在哪裡找到課程和活動？', '已開通的課程可以在「課程」專區找到，即將舉行的活動則在「活動」中。你能看到哪些內容，取決於你的會員方案。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_3', c."id", '點數、等級和徽章是什麼？', '你在社群中的活躍表現可以累積點數、提升等級並贏得徽章。排行榜會顯示特別活躍的會員——讓參與變得更有樂趣。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_4', c."id", '我可以傳訊息給其他會員嗎？', '可以，只要創作者有開啟聊天室和私訊功能，你就能和其他會員互相交流。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_teilnehmen_5', c."id", '我要怎麼設定我的通知？', '在你的帳號設定中，你可以決定想透過電子郵件和 App 收到哪些通知。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_ki-funktionen_0', c."id", 'AI 小幫手能做什麼？', 'AI 小幫手可以協助你撰寫貼文、電子報，並幫你發想點子。它會提供一個起點讓你再加以調整——主導權永遠在你手上。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_ki-funktionen_1', c."id", 'AI 推薦是什麼？', 'Aera 會向會員推薦適合的內容，讓他們更快找到自己感興趣的東西。如果沒有啟用 AI，這項功能會透過簡單、透明的關鍵字搜尋來運作。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_ki-funktionen_2', c."id", 'AI 額度是什麼？', 'AI 功能會消耗額度。每個社群都有一定的額度，需要時你也可以另外加購額外的方案。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_ki-funktionen_3', c."id", '如果 AI 額度用完了會怎麼樣？', '這時 AI 功能會暫停，直到你儲值新的額度為止。你社群的其他所有功能都會照常運作。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_ki-funktionen_4', c."id", '我的內容會被拿去訓練 AI 嗎？', '不會。你的內容屬於你自己。它們只會被用來提供你自己使用的那些功能。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_0', c."id", '我要怎麼變更我的個人資料或密碼？', '在你的帳號設定中，你隨時都能修改姓名、大頭貼、電子郵件地址和密碼。', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_1', c."id", '我要怎麼管理我的會員？', '在管理後台，你可以看到你社群裡的所有會員。你可以指派像是「版主」這樣的角色、邀請新會員，或是移除會員。', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_2', c."id", '我的資料是屬於我的嗎？', '是的。你的社群、你的會員名單和你的內容都屬於你。你隨時都可以下載你的資料——你不會被任何東西綁住。', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_3', c."id", '我要怎麼下載我的資料？', '在設定中你可以找到資料匯出功能。透過它，你就能以常見的格式下載你的內容。', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_4', c."id", '我的資料有多安全？', '每個社群都與其他社群徹底分隔並受到保護，因此沒有其他人可以存取。你的付款資料只會存放在金流服務商那裡，不會保存在 Aera。', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_5', c."id", '我要怎麼刪除我的社群或帳號？', '你可以在設定中進行。刪除時，相關的內容都會被移除——如果需要，請先把你的資料下載下來。', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_zh-Hant_konto-marke-daten_6', c."id", '我要怎麼聯繫客服？', '請使用說明中心底部的「聯絡我們」按鈕。請盡量詳細描述你的問題，這樣我們就能更快地協助你。', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_zh-Hant_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_erste-schritte', 'ko', '시작하기', 'erste-schritte', 'Aera를 알아보고, 계정을 만들고, 커뮤니티를 찾아보세요.', 10, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_community-starten', 'ko', '커뮤니티 시작하기', 'community-starten', '몇 분 만에 나만의 브랜드로 나만의 커뮤니티를 만들어 보세요.', 11, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_mitgliedschaften-preise', 'ko', '멤버십 및 가격', 'mitgliedschaften-preise', '무료 및 유료 멤버십을 설정하고 이해해 보세요.', 12, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_bezahlen-auszahlungen', 'ko', '결제 및 정산', 'bezahlen-auszahlungen', '안전한 결제, 크리에이터 정산, 영수증과 환불에 대해 알아보세요.', 13, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_inhalte-erstellen', 'ko', '콘텐츠: 게시글, 강좌, 이벤트 및 뉴스레터', 'inhalte-erstellen', '게시하고, 가르치고, 이벤트를 열고, 회원에게 직접 소식을 전해 보세요.', 14, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_teilnehmen', 'ko', '회원을 위한 안내: 함께 참여하기', 'teilnehmen', '가입하고, 함께하고, 배우고, 계속 소통해 보세요.', 15, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_ki-funktionen', 'ko', 'AI 기능', 'ki-funktionen', 'AI 어시스턴트, 추천 기능, 그리고 AI 크레딧에 대해 알아보세요.', 16, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpCategory" ("id","locale","title","slug","description","sortOrder","createdAt") VALUES ('hc_ko_konto-marke-daten', 'ko', '계정, 브랜드 및 데이터', 'konto-marke-daten', '프로필과 보안, 브랜드 설정, 회원 관리, 데이터 다운로드에 대해 알아보세요.', 17, now()) ON CONFLICT ("locale","slug") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_erste-schritte_0', c."id", 'Aera는 무엇인가요?', 'Aera는 크리에이터가 자신만의 브랜드로 직접 커뮤니티를 운영할 수 있는 플랫폼입니다. 멤버십, 강좌, 이벤트, 뉴스레터 등 다양한 기능을 한곳에서 이용할 수 있어요.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_erste-schritte_1', c."id", '계정은 어떻게 만드나요?', '''회원가입''을 누르고 이메일 주소와 비밀번호로 가입하세요.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_erste-schritte_2', c."id", '둘러보려면 계정이 꼭 필요한가요?', '많은 커뮤니티 페이지는 계정 없이도 둘러볼 수 있어요. 커뮤니티에 가입하거나 글을 쓰거나 무언가를 구매하려면 무료 계정이 필요합니다.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_erste-schritte_3', c."id", '커뮤니티는 어떻게 찾나요?', '홈 화면의 ''둘러보기''에서 공개된 커뮤니티를 찾아볼 수 있어요. 또는 크리에이터가 알려준 주소나 링크(예: name.aera.so)를 직접 열어서 접속할 수도 있습니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_erste-schritte' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_erste-schritte_4', c."id", 'Aera 이용 요금은 얼마인가요?', '계정을 만들고 커뮤니티에 가입하는 것은 무료입니다.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_0', c."id", '나만의 커뮤니티는 어떻게 시작하나요?', '''커뮤니티 시작하기''를 선택하세요. 이름과 주소를 정하고 몇 가지 기본 설정을 마치면 됩니다. 그러면 곧바로 내 대시보드로 이동해 바로 시작할 수 있어요.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_1', c."id", '대시보드는 무엇인가요?', '대시보드는 여러분의 관리 중심지입니다. 이곳에서 공간을 만들고, 콘텐츠를 게시하고, 회원을 관리하고, 멤버십과 가격을 정하고, 뉴스레터를 보내고, 주요 지표를 한눈에 확인할 수 있어요.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_2', c."id", '공간이란 무엇인가요?', '공간은 커뮤니티를 이루는 방과 같은 곳이에요. 예를 들어 게시글을 위한 피드, 강좌, 이벤트, 채팅, 미디어 보관함 등이 있습니다.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_3', c."id", '디자인을 제 브랜드에 맞게 바꿀 수 있나요?', '네. 로고와 색상, 레이아웃을 설정해 커뮤니티를 나만의 브랜드처럼 꾸밀 수 있어요. Aera는 일부러 뒤로 물러나 있으며, 주인공은 바로 여러분입니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_4', c."id", '저만의 주소도 받을 수 있나요?', '네. 여러분의 커뮤니티는 고유한 인터넷 주소(예: deinname.aera.so)를 갖게 됩니다. 원하는 나만의 도메인을 연결하는 것도 가능합니다.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_community-starten_5', c."id", '첫 회원들은 어떻게 초대하나요?', '소셜 미디어, 메신저, 이메일 등을 통해 커뮤니티 링크를 공유하기만 하면 됩니다. 이후에는 뉴스레터로 언제든 회원들에게 직접 소식을 전할 수 있어요. 그 사이를 가로막는 알고리즘도 없습니다.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_community-starten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_mitgliedschaften-preise_0', c."id", '멤버십이란 무엇인가요?', '멤버십은 회원이 커뮤니티에서 무엇을 보고 무엇을 할 수 있는지를 정하는 것입니다. 무료 등급과 유료 등급을 둘 수 있어요. 예를 들어 ''무료'', ''플러스'', ''프리미엄''처럼요.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_mitgliedschaften-preise_1', c."id", '유료 멤버십은 어떻게 만드나요?', '대시보드의 멤버십에서 새 등급을 만들 수 있어요. 가격과 결제 주기(월간 또는 연간)를 정하고, 이 등급으로 어떤 공간과 콘텐츠를 이용할 수 있는지 설정하면 됩니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_mitgliedschaften-preise_2', c."id", '유료 회원이 되려면 어떻게 하나요?', '커뮤니티에서 원하는 멤버십을 고르고 안전한 결제 화면에서 결제를 마치세요. 그러면 이용 권한이 바로 열립니다.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_mitgliedschaften-preise_3', c."id", '멤버십을 변경하거나 해지할 수 있나요?', '네. 멤버십 설정에서 언제든 변경하거나 해지할 수 있어요.
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_mitgliedschaften-preise_4', c."id", '구매 후 제 이용 권한은 어떻게 되나요?', '유료 공간과 콘텐츠가 자동으로 열립니다. 멤버십이 만료되면 다시 잠기지만, 여러분이 직접 작성한 게시글과 데이터는 그대로 남아 있어요.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_0', c."id", '안전하게 결제하려면 어떻게 하나요?', '결제는 결제 서비스 제공업체인 Stripe를 통해 이루어집니다. 결제 정보는 그곳에서 암호화되어 처리되며, Aera는 카드 정보를 직접 저장하지 않아요.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_1', c."id", '어떤 결제 수단을 이용할 수 있나요?', '국가와 기기에 따라 신용카드와 체크카드, 그리고 널리 쓰이는 디지털 결제 수단 등을 이용할 수 있어요. 어떤 결제 방법이 가능한지는 결제 화면에서 바로 확인할 수 있습니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_2', c."id", '영수증이나 청구서를 받을 수 있나요?', '네. 구매할 때마다 이메일로 확인 안내를 받게 됩니다. 또한 구매 내역은 계정 설정에서 언제든 확인할 수 있어요.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_3', c."id", '크리에이터로서 수익은 어떻게 받나요?', '정산은 Stripe를 통해 안전하게 이루어집니다. 정산 정보를 한 번만 등록해 두면, 이후 수익이 자동으로 여러분에게 지급됩니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_4', c."id", '크리에이터에게는 어떤 수수료가 부과되나요?', 'Aera는 판매가 이루어질 때 소액의 플랫폼 수수료를 받습니다. 이와 별도로 결제 처리 과정에서 결제 서비스 제공업체의 수수료가 발생할 수 있어요. 나머지 수익은 모두 여러분의 것입니다.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_bezahlen-auszahlungen_5', c."id", '환불은 어떻게 진행되나요?', '환불은 해당 크리에이터가 처리합니다. 구매와 관련해 궁금한 점이 있으면 먼저 해당 커뮤니티의 크리에이터에게 문의해 주세요. 해결이 어렵다면 저희 고객지원팀에 연락하시면 됩니다.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_bezahlen-auszahlungen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_0', c."id", '게시글은 어떻게 올리나요?', '원하는 공간을 열고 ''새 게시글''을 선택한 뒤 글과 미디어를 추가하고 게시하세요. 이때 어떤 회원이 게시글을 볼 수 있는지도 함께 정할 수 있습니다.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_1', c."id", '강좌는 어떻게 만드나요?', '강좌 공간을 만들고 수업이나 모듈을 추가하세요. 강좌를 무료로 공개할지, 아니면 유료 멤버십의 일부로 제공할지는 여러분이 정합니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_2', c."id", '이벤트는 어떻게 계획하나요?', '이벤트 공간에서 제목과 일시, 세부 내용을 정하면 됩니다. 회원들은 참석 의사를 밝힐 수 있어요. 이벤트는 무료로도, 유료로도 제공할 수 있습니다.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_3', c."id", '뉴스레터는 어떻게 보내나요?', '대시보드에서 뉴스레터를 작성해 전체 회원 또는 선택한 회원에게 보낼 수 있어요. 이렇게 하면 낯선 알고리즘의 방해 없이 회원들의 받은편지함으로 직접 소식을 전할 수 있습니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_4', c."id", '미디어 보관함은 무엇인가요?', '미디어 보관함은 여러분의 동영상, 오디오, 파일을 한곳에 모아 두는 공간입니다. 여기에서 이 자료들을 게시글, 강좌, 이벤트에 넣어 활용할 수 있어요.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_inhalte-erstellen_5', c."id", '게시글을 미리 예약할 수 있나요?', '네. 콘텐츠를 원하는 시점으로 예약해 두면 그때 자동으로 게시됩니다. 꾸준히 활동을 이어 가는 데 아주 유용해요.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_inhalte-erstellen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_0', c."id", '커뮤니티에는 어떻게 가입하나요?', '커뮤니티를 열고 ''가입하기''를 선택하세요. 무료 커뮤니티라면 곧바로 함께하게 됩니다. 유료 커뮤니티라면 먼저 멤버십을 선택하면 돼요.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_1', c."id", '게시글과 댓글은 어떻게 작성하나요?', '이용 권한이 있는 모든 공간에서 게시글을 쓰고 댓글을 달고 반응을 남길 수 있어요. 소셜 네트워크와 비슷하지만, 낯선 알고리즘은 끼어들지 않습니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_2', c."id", '강좌와 이벤트는 어디에서 찾나요?', '이용 가능한 강좌는 ''강좌'' 공간에서, 다가오는 일정은 ''이벤트''에서 확인할 수 있어요. 무엇을 볼 수 있는지는 여러분의 멤버십에 따라 달라집니다.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_3', c."id", '포인트, 레벨, 배지는 무엇인가요?', '활동을 하면 포인트를 모으고, 레벨이 올라가며, 배지를 얻게 됩니다. 순위표에서는 특히 활발한 회원을 보여 주는데, 이런 요소들이 참여를 더 즐겁게 만들어 줍니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_4', c."id", '다른 회원에게 메시지를 보낼 수 있나요?', '네. 크리에이터가 채팅과 다이렉트 메시지를 켜 두었다면, 다른 회원들과 자유롭게 소통할 수 있어요.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_teilnehmen_5', c."id", '알림은 어떻게 설정하나요?', '계정 설정에서 이메일과 앱을 통해 어떤 소식을 받을지 직접 정할 수 있습니다.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_teilnehmen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_ki-funktionen_0', c."id", 'AI 어시스턴트로 무엇을 할 수 있나요?', 'AI 어시스턴트는 게시글과 뉴스레터를 쓰거나 아이디어를 모을 때 도움을 줍니다. 시작점이 될 초안을 제공하면 여러분이 다듬으면 되고, 최종 결정권은 언제나 여러분에게 있어요.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_ki-funktionen_1', c."id", 'AI 추천이란 무엇인가요?', 'Aera는 회원에게 어울리는 콘텐츠를 추천해 관심 있는 내용을 더 빠르게 찾을 수 있도록 도와줍니다. AI가 켜져 있지 않을 때는 간단하고 투명한 키워드 검색을 통해 이 기능이 동작합니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_ki-funktionen_2', c."id", 'AI 크레딧은 무엇인가요?', 'AI 기능을 사용하면 크레딧이 소모됩니다. 커뮤니티마다 크레딧이 주어지며, 필요할 때 추가 패키지를 더 구매할 수 있어요.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_ki-funktionen_3', c."id", 'AI 크레딧을 모두 사용하면 어떻게 되나요?', '그러면 크레딧을 다시 충전할 때까지 AI 기능이 잠시 멈춥니다. 커뮤니티의 나머지 기능은 모두 평소와 똑같이 이용할 수 있어요.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_ki-funktionen_4', c."id", '제 콘텐츠가 AI 학습에 사용되나요?', '아니요. 여러분의 콘텐츠는 여러분의 것입니다. 콘텐츠는 오직 여러분이 직접 사용하는 기능을 제공하기 위해서만 이용됩니다.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_ki-funktionen' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_0', c."id", '프로필이나 비밀번호는 어떻게 바꾸나요?', '계정 설정에서 이름, 프로필 사진, 이메일 주소, 비밀번호를 언제든 변경할 수 있습니다.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_1', c."id", '회원은 어떻게 관리하나요?', '대시보드에서 커뮤니티의 모든 회원을 볼 수 있어요. 모더레이터 같은 역할을 부여하거나, 새 회원을 초대하거나, 회원을 내보낼 수 있습니다.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_2', c."id", '제 데이터는 제 것인가요?', '네. 여러분의 커뮤니티, 회원 목록, 콘텐츠는 모두 여러분의 것입니다. 데이터는 언제든 내려받을 수 있으며, 어디에도 얽매이지 않습니다.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_3', c."id", '제 데이터는 어떻게 내려받나요?', '설정에서 데이터 내보내기를 찾을 수 있어요. 이를 통해 여러분의 콘텐츠를 널리 쓰이는 형식으로 내려받을 수 있습니다.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_4', c."id", '제 데이터는 얼마나 안전한가요?', '모든 커뮤니티는 다른 커뮤니티와 깔끔하게 분리되고 보호되어, 다른 누구도 접근할 수 없습니다. 결제 정보는 오직 결제 서비스 제공업체에만 보관되며, Aera에는 저장되지 않아요.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_5', c."id", '제 커뮤니티나 계정은 어떻게 삭제하나요?', '설정에서 할 수 있습니다. 삭제하면 관련 콘텐츠도 함께 지워지므로, 필요하다면 미리 데이터를 내려받아 두세요.', 5, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
INSERT INTO "HelpArticle" ("id","categoryId","question","answer","sortOrder","isPublished","updatedAt") SELECT 'ha_ko_konto-marke-daten_6', c."id", '고객지원팀에는 어떻게 연락하나요?', '도움말 센터 하단의 문의하기 버튼을 이용하세요. 궁금한 점을 최대한 자세히 적어 주시면 더 빠르게 도와드릴 수 있습니다.', 6, true, now() FROM "HelpCategory" c WHERE c."id"='hc_ko_konto-marke-daten' ON CONFLICT ("id") DO NOTHING;
