-- Aera Hilfe-Center: Sprach-Feld + Inhalte in 19 Sprachen. Idempotent & duplikatsicher.
-- Teil 1: Schema (idempotent).
ALTER TABLE "HelpCategory" ADD COLUMN IF NOT EXISTS "locale" TEXT NOT NULL DEFAULT 'de';
DROP INDEX IF EXISTS "HelpCategory_slug_key";
CREATE UNIQUE INDEX IF NOT EXISTS "HelpCategory_locale_slug_key" ON "HelpCategory"("locale","slug");
CREATE INDEX IF NOT EXISTS "HelpCategory_locale_sortOrder_idx" ON "HelpCategory"("locale","sortOrder");

-- Teil 2: Inhalte je Sprache. Artikel binden an die vom Skript erzeugte Kategorie-ID,
-- damit bereits vorhandene Inhalte (z. B. deutsche) niemals dupliziert werden.
-- de

Als Mitglied trittst du der Community eines Creators bei und nimmst teil. Als Creator baust du deine eigene Community auf und entscheidest selbst über Inhalte, Preise und Aussehen.', 0, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_erste-schritte' ON CONFLICT ("id") DO NOTHING;

Danach kannst du Communities beitreten — oder unter „Community starten" in wenigen Minuten deine eigene aufbauen.', 1, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_erste-schritte' ON CONFLICT ("id") DO NOTHING;

Kosten entstehen nur, wenn du eine bezahlte Mitgliedschaft, einen Kurs, ein Produkt oder ein kostenpflichtiges Event eines Creators kaufst.

Für Creator ist das Starten einer Community kostenlos — beim Verkaufen behält Aera lediglich eine kleine Plattformgebühr.', 4, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_erste-schritte' ON CONFLICT ("id") DO NOTHING;

Du entscheidest, welche Bereiche es gibt, wie sie heißen und wer sie sehen darf.', 2, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_community-starten' ON CONFLICT ("id") DO NOTHING;

Nach einer Kündigung bleibt dein Zugang bis zum Ende des bereits bezahlten Zeitraums bestehen.', 3, true, now() FROM "HelpCategory" c WHERE c."id"='hc_de_mitgliedschaften-preise' ON CONFLICT ("id") DO NOTHING;

